-- Poems batch 395
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-372','感皇恩','辛弃疾','宋','宋词','song-ci','感皇恩','[]','案上数编书，非庄即老。',81,'宋词/ci.song.11000.json','["案上数编书，非庄即老。", "会说忘言始知道。", "万言千句，自不能忘堪笑。", "朝来梅雨霁，青青好。", "一壑一丘，轻衫短帽。", "白发多时故人少。", "子云何在，应有玄经□草。", "江河流日夜，何时了。"]'),
('song-ci-373','感皇恩','辛弃疾','宋','宋词','song-ci','感皇恩','[]','七十古来稀，未为稀有。',81,'宋词/ci.song.11000.json','["七十古来稀，未为稀有。", "须是荣华更长久。", "满床靴笏，罗列儿孙新妇。", "精神浑是个，西王母。", "遥想画堂，两行红袖。", "妙舞清歌拥前后。", "大男小女，逐个出来为寿。", "一个一百岁，一杯酒。"]'),
('song-ci-374','南乡子','辛弃疾','宋','宋词','song-ci','南乡子','[]','无处著春光。',66,'宋词/ci.song.11000.json','["无处著春光。", "天上飞来诏十行。", "父老欢呼童稚舞，前江。", "千载周家孝义乡。", "草木尽芬芳。", "更觉溪头水也香。", "我道乌头门侧畔，诸郎。", "准备他年昼锦堂。"]'),
('song-ci-375','小重山','辛弃疾','宋','宋词','song-ci','小重山','[]','绿涨连云翠拂空。',70,'宋词/ci.song.11000.json','["绿涨连云翠拂空。", "十分风月处，著衰翁。", "垂杨影断岸西东。", "君恩重，教且种芙蓉。", "十里水晶宫。", "有时骑马去，笑儿童。", "殷勤却谢打头风。", "船儿住，且醉浪花中。"]'),
('song-ci-376','婆罗门引','辛弃疾','宋','宋词','song-ci','婆罗门引','[]','落花时节，杜鹃声里送君归。',93,'宋词/ci.song.11000.json','["落花时节，杜鹃声里送君归。", "未消文字湘累。", "只怕蛟龙云雨，后会渺难期。", "更何人念我，老大伤悲。", "已而已而。", "算此意、只君知。", "记取岐亭买酒，云洞题诗。", "争如不见，才相见、便有别离时。", "千里月、两地相思。"]'),
('song-ci-377','婆罗门引','辛弃疾','宋','宋词','song-ci','婆罗门引','[]','绿阴啼鸟，阳关未彻早催归。',93,'宋词/ci.song.11000.json','["绿阴啼鸟，阳关未彻早催归。", "歌珠凄断累累。", "回首海山何处，千里共襟期。", "叹高山流水，弦断堪悲。", "中心怅而。", "似风雨、落花知。", "更拟停云君去，细□陶诗。", "见君何日，待琼林、宴罢醉归时。", "人争看、宝马来思。"]'),
('song-ci-378','婆罗门引','辛弃疾','宋','宋词','song-ci','婆罗门引','[]','落星万点，一天宝焰下层霄。',93,'宋词/ci.song.11000.json','["落星万点，一天宝焰下层霄。", "人间叠作仙鳌。", "最爱金连侧畔，红粉袅花梢。", "更鸣鼍击鼓，喷玉吹箫。", "曲江画桥。", "记花月、可怜宵。", "想见闲愁未了，宿酒才消。", "东风摇荡，似杨柳、十五女儿腰。", "人共柳、那个无聊。"]'),
('song-ci-379','行香子','辛弃疾','宋','宋词','song-ci','行香子','[]','好雨当春。',84,'宋词/ci.song.11000.json','["好雨当春。", "要趁归耕。", "况而今、已是清明。", "小窗坐地，侧听檐声。", "恨夜来风，夜来月，夜来云。", "花絮飘零。", "莺燕丁宁。", "怕妨侬、湖上闲行。", "天心肯后，费甚心情。", "放霎时阴，霎时雨，霎时晴。"]'),
('song-ci-380','行香子','辛弃疾','宋','宋词','song-ci','行香子','[]','白露园蔬。',84,'宋词/ci.song.11000.json','["白露园蔬。", "碧水溪鱼。", "笑先生、网钓还锄。", "小窗高卧，风展残书。", "看北移山，盘谷序，辋川图。", "白饭青刍。", "赤脚长须。", "客来时、酒尽重沽。", "听风听雨，吾爱吾庐。", "笑本无心，刚自瘦，此君疏。"]'),
('song-ci-381','行香子','辛弃疾','宋','宋词','song-ci','行香子','[]','云岫如簪。',84,'宋词/ci.song.11000.json','["云岫如簪。", "野涨挼蓝。", "向春阑、绿醒红酣。", "青裙缟袂，两两三三。", "把曲生禅，玉版句，一时参。", "拄杖弯环。", "过眼嵌岩。", "岸轻乌、白发鬖鬖。", "他年来种，万桂千杉。", "听小绵蛮，新格磔，旧呢喃。"]'),
('song-ci-382','粉蝶儿','辛弃疾','宋','宋词','song-ci','粉蝶儿','[]','昨日春如，十三女儿学绣。',90,'宋词/ci.song.11000.json','["昨日春如，十三女儿学绣。", "一枝枝、不教花瘦。", "甚无情，便下得，雨僝风僽。", "向园林、铺作地衣红绉。", "而今春似，轻薄荡子难久。", "记前时、送春归后。", "把春波，都酿作，一江春酎。", "约清愁、杨柳岸边相候。"]'),
('song-ci-383','锦帐春','辛弃疾','宋','宋词','song-ci','锦帐春','[]','春色难留，酒杯常浅。',76,'宋词/ci.song.11000.json','["春色难留，酒杯常浅。", "把旧恨、新愁相间。", "五更风，千里梦，看飞红几片。", "这般庭院。", "几许风流，几般娇懒。", "问相见、何如不见。", "燕飞忙，莺语乱。", "恨重帘不卷。", "翠屏平远。"]'),
('song-ci-384','夜游宫','辛弃疾','宋','宋词','song-ci','夜游宫','[]','几个相知可喜。',71,'宋词/ci.song.11000.json','["几个相知可喜。", "才厮见、说山说水。", "颠倒烂熟只这是。", "怎奈向，一回说，一回美。", "有个尖新底。", "说底话、非名即利。", "说得口乾罪过你。", "且不罪，俺略起，去洗耳。"]'),
('song-ci-385','浪淘沙','辛弃疾','宋','宋词','song-ci','浪淘沙','[]','身世酒杯中。',64,'宋词/ci.song.11000.json','["身世酒杯中。", "万事皆空。", "古来三五个英雄。", "雨打风吹何处是，汉殿秦宫。", "梦入少年丛。", "歌舞匆匆。", "老僧夜半误鸣钟。", "惊起西窗眠不得，卷地西风。"]'),
('song-ci-386','河传','辛弃疾','宋','宋词','song-ci','河传','[]','春水。',68,'宋词/ci.song.11000.json','["春水。", "千里。", "孤舟浪起。", "梦携西子。", "觉来村巷夕阳斜。", "几家。", "短墙红杏花。", "晚云做造些儿雨。", "折花去。", "岸上谁家女。", "太狂颠。", "那岸边。", "柳绵。", "被风吹上天。"]'),
('song-ci-387','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','人道偏宜歌舞，天教只入丹青。',58,'宋词/ci.song.11000.json','["人道偏宜歌舞，天教只入丹青。", "喧天画鼓要他听。", "把著花枝不应。", "何处娇魂瘦影，向来软语柔情。", "有时醉里唤卿卿。", "却被傍人笑问。"]'),
('song-ci-388','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','万事云烟忽过，一身蒲柳先衰。',58,'宋词/ci.song.11000.json','["万事云烟忽过，一身蒲柳先衰。", "而今何事最相宜。", "宜醉宜游宜睡。", "早趁催科了纳，更量出入收支。", "乃翁依旧管些儿。", "管竹管山管水。"]'),
('song-ci-389','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','少年不识愁滋味，爱上层楼。',52,'宋词/ci.song.11000.json','["少年不识愁滋味，爱上层楼。", "爱上层楼。", "为赋新词强说愁。", "而今识尽愁滋味，欲说还休。", "欲说还休。", "却道天凉好个秋。"]'),
('song-ci-390','破阵子','辛弃疾','宋','宋词','song-ci','破阵子','[]','少日春风满眼，而今秋叶辞柯。',72,'宋词/ci.song.11000.json','["少日春风满眼，而今秋叶辞柯。", "便好消磨心下事，莫忆寻常醉后歌。", "可怜白发多。", "明日扶头颠倒，倩谁伴舞婆娑。", "我定思君拼瘦损，君不思兮可奈何。", "天寒将息呵。"]'),
('song-ci-391','破阵子','辛弃疾','宋','宋词','song-ci','破阵子','[]','宿麦畦中雉鷕，柔桑陌上蚕生。',72,'宋词/ci.song.11000.json','["宿麦畦中雉鷕，柔桑陌上蚕生。", "骑火须防花月暗，玉唾长携彩笔行。", "隔墙人笑声。", "莫说弓刀事业，依然诗酒功名。", "千载图中今古事，万石溪头长短亭。", "小塘风浪平。"]'),
('song-ci-392','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','少日犹堪话别离。',73,'宋词/ci.song.11000.json','["少日犹堪话别离。", "老来怕作送行诗。", "极目南云无过雁。", "君看。", "梅花也解寄相思。", "无限江山行未了。", "父老。", "不须和泪看旌旗。", "后会丁宁何日□。", "须记。", "春风十日放灯时。"]'),
('song-ci-393','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','莫望中州叹黍离。',73,'宋词/ci.song.11000.json','["莫望中州叹黍离。", "元和圣德要君诗。", "老去不堪谁似我。", "归卧。", "青山活计费寻思。", "谁筑诗墙高十丈。", "直上。", "看君斩将更搴旗。", "歌舞正浓还有语。", "记取。", "须髯不似少年时。"]'),
('song-ci-394','踏莎行','辛弃疾','宋','宋词','song-ci','踏莎行','[]','进退存亡，行藏用舍。',68,'宋词/ci.song.11000.json','["进退存亡，行藏用舍。", "小人请学樊须稼。", "衡门之下可栖迟，日之夕矣□□下。", "去卫灵公，遭桓司马。", "东西南北之人也。", "长沮粲溺耦而耕，丘何为是栖栖者。"]'),
('song-ci-395','汉宫春','辛弃疾','宋','宋词','song-ci','汉宫春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','春已归来，看美人头上，袅袅春幡。',118,'宋词/ci.song.11000.json','["春已归来，看美人头上，袅袅春幡。", "无端风雨，未肯收尽馀寒。", "年时燕子，料今宵、梦到西园。", "浑未办、黄柑荐酒，更传青韭堆盘。", "却笑东风从此，便薰梅染柳，更没些闲。", "闲时又来镜里，转变朱颜。", "清愁不断，问何人、会解连环。", "生怕见、花开花落，朝来塞雁先还。"]'),
('song-ci-396','归朝欢','辛弃疾','宋','宋词','song-ci','归朝欢','[]','山下千林花太俗。',122,'宋词/ci.song.11000.json','["山下千林花太俗。", "山上一枝看不足。", "春风正在此花边，菖蒲自蘸清溪绿。", "与花同草木。", "问谁风雨飘零速。", "莫怨歌，夜深岩下，惊动白云宿。", "病怯残年频自卜。", "老爱遗编难细读。", "苦无妙手画於菟，人间雕刻真成鹄。", "梦中人似玉。", "觉来更忆腰如束。", "许多愁，问君有酒，何不日丝竹。"]'),
('song-ci-397','玉蝴蝶','辛弃疾','宋','宋词','song-ci','玉蝴蝶','[]','古道行人来去，香红满树，风雨残花。',124,'宋词/ci.song.11000.json','["古道行人来去，香红满树，风雨残花。", "望断青山，高处都被云遮。", "客重来、风流觞咏，春已去、光景桑麻。", "苦无多。", "一条垂柳，两个啼鸦。", "人家。", "疏疏翠竹，阴阴绿树，浅浅寒沙。", "醉兀篮舆，夜来豪饮太狂些。", "到如今、都齐醒却，只依旧、无奈愁何。", "试听呵。", "寒食近也，且住为佳。"]'),
('song-ci-398','雨中花慢','辛弃疾','宋','宋词','song-ci','雨中花慢','[]','旧雨常来，今□不来，佳人偃蹇谁留。',118,'宋词/ci.song.11000.json','["旧雨常来，今□不来，佳人偃蹇谁留。", "幸山中芋栗，今岁全收。", "贫贱交情落落，古今吾道悠悠。", "怪新来却见，文反离骚，诗□秦州。", "功名只道，无之不乐，那知有更堪忧。", "怎奈向、儿曹抵死，唤不回头。", "石卧山前认虎，蚁喧床下闻牛。", "为谁西望，凭栏一饷，却下层楼。"]'),
('song-ci-399','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','一自酒情诗兴懒，舞裙歌扇阑珊。',70,'宋词/ci.song.11000.json','["一自酒情诗兴懒，舞裙歌扇阑珊。", "好天良夜月团团。", "杜陵真好事，留得一钱看。", "岁晚人欺程不识，怎教阿堵留连。", "杨花榆荚雪漫天。", "从今花影下，只看绿苔圆。"]'),
('song-ci-400','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','鼓子花开春烂漫，荒园无限思量。',70,'宋词/ci.song.11000.json','["鼓子花开春烂漫，荒园无限思量。", "今朝拄杖过西乡。", "急呼桃叶渡，为看牡丹忙。", "不管昨宵风雨横，依然红紫成行。", "白头陪奉少年场。", "一枝簪不住，推道帽檐长。"]'),
('song-ci-401','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','三三两两谁家女。',64,'宋词/ci.song.11000.json','["三三两两谁家女。", "听取鸣禽枝上语。", "提壶沽酒已多时，婆饼焦时须早去。", "醉中忘却来时路。", "借问行人家住处。", "只寻古庙那边行，更过溪南乌桕树。"]'),
('song-ci-402','南歌子','辛弃疾','宋','宋词','song-ci','南歌子','[]','散发披襟处，浮瓜沈李杯。',62,'宋词/ci.song.11000.json','["散发披襟处，浮瓜沈李杯。", "涓涓流水细侵阶。", "凿个池儿，唤个月儿来。", "画栋频摇动，红葵尽倒开。", "斗匀红粉照香腮。", "有个人人，把做镜儿猜。"]'),
('song-ci-403','品令','辛弃疾','宋','宋词','song-ci','品令','[]','更休说。',65,'宋词/ci.song.11000.json','["更休说。", "便是个、住世观音菩萨。", "甚今年、容貌八十岁，见底道、才十八。", "莫献寿星香烛。", "莫祝灵龟椿鹤。", "只消得、把笔轻轻去，十字上、添一撇。"]'),
('song-ci-404','武陵春','辛弃疾','宋','宋词','song-ci','武陵春','[]','桃李风前多妩媚，杨柳更温柔。',56,'宋词/ci.song.11000.json','["桃李风前多妩媚，杨柳更温柔。", "唤取笙歌烂熳游。", "且莫管闲愁。", "好趁春晴连夜赏，雨便一春休。", "草草杯盘不要收。", "才晓更扶头。"]'),
('song-ci-405','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','聚散匆匆不偶然。',64,'宋词/ci.song.11000.json','["聚散匆匆不偶然。", "二年遍历楚山川。", "但将痛饮酬风月，莫放离歌入管弦。", "萦绿带，点青钱。", "东湖春水碧连天。", "明朝放我东归去，后夜相思月满船。"]'),
('song-ci-406','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','翰墨诸君久擅场。',64,'宋词/ci.song.11000.json','["翰墨诸君久擅场。", "胸中书传许多香。", "苦无丝竹衔杯乐，却看龙蛇落笔忙。", "闲意思，老风光。", "酒徒今有几高阳。", "黄花不怯秋风冷，只怕诗人两鬓霜。"]'),
('song-ci-407','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','万事纷纷一笑中。',64,'宋词/ci.song.11000.json','["万事纷纷一笑中。", "渊明把菊对秋风。", "细看爽气今犹在，惟有南山一似翁。", "情味好，语言工。", "三贤高会古来同。", "谁知止酒停云老，独立斜阳数过鸿。"]'),
('song-ci-408','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','点尽苍苔色欲空。',64,'宋词/ci.song.11000.json','["点尽苍苔色欲空。", "竹篱茅舍要诗翁。", "花馀歌舞欢娱外，诗在经营惨澹中。", "听软语，笑衰容。", "一枝斜坠翠鬟松。", "浅颦轻笑谁堪醉，看取萧然林下风。"]'),
('song-ci-409','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','病绕梅花酒不空。',64,'宋词/ci.song.11000.json','["病绕梅花酒不空。", "齿牙牢在莫欺翁。", "恨无飞雪青松畔，却放疏花翠叶中。", "冰作骨，玉为容。", "当年宫额鬓云松。", "直须烂醉烧银烛，横笛难堪一再风。"]'),
('song-ci-410','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','句里春风正剪裁。',64,'宋词/ci.song.11000.json','["句里春风正剪裁。", "溪山一片画图开。", "轻鸥自趁虚船去，荒犬还迎野妇回。", "松菊竹，翠成堆。", "要擎残雪斗疏梅。", "乱鸦毕竟无才思，时把琼瑶蹴下来。"]'),
('song-ci-411','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','石壁虚云积渐高。',64,'宋词/ci.song.11000.json','["石壁虚云积渐高。", "溪声绕屋几周遭。", "自从一雨花零乱，却爱微风草动摇。", "呼玉友，荐溪毛。", "殷勤野老苦相邀。", "杖藜忽避行人去，认是翁来却过桥。"]'),
('song-ci-412','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','自古高人最可嗟。',64,'宋词/ci.song.11000.json','["自古高人最可嗟。", "只因疏懒取名多。", "居山一似庚桑楚，种树真成郭橐驼。", "云子饭，水晶瓜。", "林间携客更烹茶。", "君归休矣吾忙甚，要看蜂儿趁晚衙。"]'),
('song-ci-413','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','掩鼻人间臭腐场。',64,'宋词/ci.song.11000.json','["掩鼻人间臭腐场。", "古来惟有酒偏香。", "自从归住云烟畔，直到而今歌舞忙。", "呼老伴，共秋光。", "黄花何事避重阳。", "要知烂熳开时节，直待西风一夜霜。"]'),
('song-ci-414','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','谁共春光管日华。',64,'宋词/ci.song.11000.json','["谁共春光管日华。", "朱朱纷纷野蒿花。", "闲愁投老无多子，酒病而今较减些。", "山远近，路横斜。", "正无聊处管弦哗。", "去年醉处犹能记，细数溪边第几家。"]'),
('song-ci-415','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','占断雕栏只一株。',66,'宋词/ci.song.11000.json','["占断雕栏只一株。", "春风费尽几工夫。", "天香夜染衣犹湿，国色朝酣酒未苏。", "娇欲语，巧相扶。", "不妨老干自扶疏。", "恰如翠幕高堂上，来看红衫《百子图》。"]'),
('song-ci-416','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','翠盖牙签几百株。',64,'宋词/ci.song.11000.json','["翠盖牙签几百株。", "杨家姊妹夜游初。", "五花结队香如雾，一朵倾城醉未苏。", "闲小立，困相扶。", "夜来风雨有情无。", "愁红惨绿今宵看，却似吴宫教阵图。"]'),
('song-ci-417','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','浓紫深红一画图。',64,'宋词/ci.song.11000.json','["浓紫深红一画图。", "中间更著玉盘盂。", "先裁翡翠装成盖，更点胭脂染透酥。", "香潋滟，锦模糊。", "主人长得醉功夫。", "莫携弄玉栏边去，羞得花枝一朵无。"]'),
('song-ci-418','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','老病那堪岁月侵。',66,'宋词/ci.song.11000.json','["老病那堪岁月侵。", "霎时光景值千金。", "一生不负溪山债，百药难治书史淫。", "随巧拙，任浮沈。", "人无同处面如心。", "不妨旧事从头记，要写行藏入《笑林》。"]'),
('song-ci-419','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','鸡鸭成群晚不收。',64,'宋词/ci.song.11000.json','["鸡鸭成群晚不收。", "桑麻长过屋山头。", "有何不可吾方羡，要底都无饱便休。", "新柳树，旧沙洲。", "去年溪打那边流。", "自言此地生儿女，不嫁金家即聘周。"]'),
('song-ci-420','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','不向长安路上行。',64,'宋词/ci.song.11000.json','["不向长安路上行。", "却教山寺厌逢迎。", "味无味处求吾乐，材不材间过此生。", "宁作我，岂其卿。", "人间走遍却归耕。", "一松一竹真朋友，山鸟山花好弟兄。"]'),
('song-ci-421','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','是处移花是处开。',64,'宋词/ci.song.11000.json','["是处移花是处开。", "古今兴废几池台。", "背人翠羽偷鱼去，抱蕊黄须趁蝶来。", "掀老瓮，拨新醅。", "客来且尽两三杯。", "日高盘馔供何晚，市远鱼鲑买未回。"]'),
('song-ci-422','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','寸步人间百尺楼。',48,'宋词/ci.song.11000.json','["寸步人间百尺楼。", "孤城春水一沙鸥。", "天风吹树几时休。", "突兀趁人山石狠，朦胧避路野花羞。", "人家平水庙东头。"]'),
('song-ci-423','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','细听春山杜宇啼。',48,'宋词/ci.song.11000.json','["细听春山杜宇啼。", "一声声是送行诗。", "朝来白鸟背人飞。", "对郑子真岩石卧，趁陶元亮菊花期。", "而今堪诵北山移。"]'),
('song-ci-424','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','草木於人也作疏。',48,'宋词/ci.song.11000.json','["草木於人也作疏。", "秋来咫尺共荣枯。", "空山晚翠孰华余。", "孤竹君穷犹抱节，赤松子嫩已生须。", "主人相爱肯留无。"]'),
('song-ci-425','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','艳杏夭桃两行排。',56,'宋词/ci.song.11000.json','["艳杏夭桃两行排。", "莫携歌舞去相催。", "次第未堪供醉眼，去年栽。", "春意才从梅里过，人情都向柳边来。", "咫尺东家还又有，海棠开。"]'),
('song-ci-426','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','酒面低迷翠被重。',56,'宋词/ci.song.11000.json','["酒面低迷翠被重。", "黄昏院落月朦胧。", "堕髻啼妆孙寿醉，泥秦宫。", "试问花留春几日，略无人管雨和风。", "瞥向绿珠楼下见，坠残红。"]'),
('song-ci-427','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','强欲加餐竟未佳。',56,'宋词/ci.song.11000.json','["强欲加餐竟未佳。", "只宜长伴病僧斋。", "心似风吹香篆过，也无灰。", "山上朝来云出岫，随风一去未曾回。", "次第前村行雨了，合归来。"]'),
('song-ci-428','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','新葺茅檐次第成。',48,'宋词/ci.song.11000.json','["新葺茅檐次第成。", "青山恰对小窗横。", "去年曾共燕经营。", "病怯杯盘甘止酒，老依香火苦翻经。", "夜来依旧管弦声。"]'),
('song-ci-429','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','花向今朝粉面匀。',48,'宋词/ci.song.11000.json','["花向今朝粉面匀。", "柳因何事翠眉颦。", "东风吹雨细於尘。", "自笑好山如好色，只今怀树更怀人。", "闲愁闲恨一番新。"]'),
('song-ci-430','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','台倚崩崖玉灭瘢。',48,'宋词/ci.song.11000.json','["台倚崩崖玉灭瘢。", "青山却作捧心颦。", "远林烟火几家村。", "引入沧浪鱼得计，展成寥阔鹤能言。", "几时高处见层轩。"]'),
('song-ci-431','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','总把平生入醉乡。',56,'宋词/ci.song.11000.json','["总把平生入醉乡。", "大都三万六千场。", "今古悠悠多少事，莫思量。", "微有寒些春雨好，更无寻处野花香。", "年去年来还又笑，燕飞忙。"]'),
('song-ci-432','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','北陇田高踏水频。',48,'宋词/ci.song.11000.json','["北陇田高踏水频。", "西溪禾早已尝新。", "隔墙沽酒□纤鳞。", "忽有微凉何处雨，更无留影霎时云。", "卖瓜声过竹边村。"]'),
('song-ci-433','新荷叶','辛弃疾','宋','宋词','song-ci','新荷叶','[]','曲水流觞，赏心乐事良辰。',100,'宋词/ci.song.11000.json','["曲水流觞，赏心乐事良辰。", "兰蕙光风，转头天气还新。", "明眸皓齿，看江头、有女如云。", "折花归去，绮罗陌上芳尘。", "能几多春。", "试听啼鸟殷勤。", "览物兴怀，向来哀乐纷纷。", "且题醉墨，似兰亭、列序时人。", "后之览者，又将有感斯文。"]'),
('song-ci-434','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','漫天春雪来，才抵梅花半。',48,'宋词/ci.song.11000.json','["漫天春雪来，才抵梅花半。", "最爱雪边人，楚些裁成乱。", "雪儿偏解歌，只要金杯满。", "谁道雪天寒，翠袖阑干暖。"]'),
('song-ci-435','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','去年燕子来，帘幕深深处。',48,'宋词/ci.song.11000.json','["去年燕子来，帘幕深深处。", "香径得泥归，都把琴书污。", "今年燕子来，谁听呢喃语。", "不见卷帘人，一阵黄昏雨。"]'),
('song-ci-436','昭君怨','辛弃疾','宋','宋词','song-ci','昭君怨','[]','人面不如花面。',48,'宋词/ci.song.11000.json','["人面不如花面。", "花到开时重见。", "独倚小阑干。", "许多山。", "落叶西风时候。", "人共青山都瘦。", "说道梦阳台。", "几曾来。"]'),
('song-ci-437','乌夜啼','辛弃疾','宋','宋词','song-ci','乌夜啼','[]','晚花露叶风条。',45,'宋词/ci.song.11000.json','["晚花露叶风条。", "燕飞高。", "行过长廊西畔、小红桥。", "歌再起，人再舞，酒才消。", "更把一杯重劝、摘樱桃。"]'),
('song-ci-438','朝中措','辛弃疾','宋','宋词','song-ci','朝中措','[]','年年团扇怨秋风。',57,'宋词/ci.song.11000.json','["年年团扇怨秋风。", "愁绝宝杯空。", "山下卧龙丰度，台前戏马英雄。", "而今休矣，花残人似，人老花同。", "莫怪东篱韵减，只今丹桂香浓。"]'),
('song-ci-439','朝中措','辛弃疾','宋','宋词','song-ci','朝中措','[]','夜深残月过山房。',57,'宋词/ci.song.11000.json','["夜深残月过山房。", "睡觉北窗凉。", "起绕中庭独步，一天星斗文章。", "朝来客话，山林锺鼎，那处难忘。", "君向沙头细问，白鸥知我行藏。"]'),
('song-ci-440','河渎神','辛弃疾','宋','宋词','song-ci','河渎神','[]','芳草绿萋萋。',57,'宋词/ci.song.11000.json','["芳草绿萋萋。", "断肠绝浦相思。", "山头人望翠云旗。", "蕙香佳酒君归。", "惆怅画檐双燕舞。", "东风吹散灵雨。", "香火冷残箫鼓。", "斜阳门外今古。"]'),
('song-ci-441','太常引','辛弃疾','宋','宋词','song-ci','太常引','[]','一轮秋影转金波。',60,'宋词/ci.song.11000.json','["一轮秋影转金波。", "飞镜又重磨。", "把酒问姮娥。", "被白发、欺人奈何。", "乘风好去，长空万里，直下看山河。", "斫去桂婆娑。", "人道是、清光更多。"]'),
('song-ci-442','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','少年痛饮。',54,'宋词/ci.song.11000.json','["少年痛饮。", "忆向吴江醒。", "明月团圆高树影。", "十里蔷薇水冷。", "大都一点宫黄。", "人间直恁芳芬。", "怕是九天风露，染教世界都香。"]'),
('song-ci-443','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','东园向晓。',54,'宋词/ci.song.11000.json','["东园向晓。", "阵阵西风好。", "唤起仙人金小小。", "翠羽玲珑装了。", "一枝沈畔开时。", "罗帏翠幕低垂。", "恁地十分遮护，打窗早有蜂儿。"]'),
('song-ci-444','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','春宵睡重。',54,'宋词/ci.song.11000.json','["春宵睡重。", "梦里还相送。", "枕畔起寻双玉凤。", "半日才知是梦。", "一从卖翠人还。", "又无音信经年。", "却把泪来做水，流也流到伊边。"]'),
('song-ci-445','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','旌旗依旧长亭路。',52,'宋词/ci.song.11000.json','["旌旗依旧长亭路。", "尊前试点莺花数。", "何处捧心颦。", "人间别样春。", "功名君自许。", "少日闻鸡舞。", "诗句到梅花。", "春风十万家。"]'),
('song-ci-446','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','画楼影蘸清溪水。',52,'宋词/ci.song.11000.json','["画楼影蘸清溪水。", "歌声响彻行云里。", "帘幕燕双双。", "绿杨低映窗。", "曲中特地误。", "要试周郎顾。", "醉里客魂消。", "春风大小乔。"]'),
('song-ci-447','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','万金不换囊中术。',52,'宋词/ci.song.11000.json','["万金不换囊中术。", "上医元自能医国。", "软语到更阑。", "绨袍范叔寒。", "江头杨柳路。", "马踏春风去。", "快趁两三杯。", "河豚欲上来。"]'),
('song-ci-448','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','看灯元是菩提叶。',52,'宋词/ci.song.11000.json','["看灯元是菩提叶。", "依然会说菩提法。", "法似一灯明。", "须叟千万灯。", "灯边花更满。", "谁把空花散。", "说与病维摩。", "而今天女歌。"]'),
('song-ci-449','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','游人占却岩中屋。',52,'宋词/ci.song.11000.json','["游人占却岩中屋。", "白云只向檐头宿。", "谁解探玲珑。", "青山十里空。", "松篁通一径。", "噤嘇山花冷。", "今古几千年。", "西乡小有天。"]'),
('song-ci-450','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','葛巾自向沧浪濯。',52,'宋词/ci.song.11000.json','["葛巾自向沧浪濯。", "朝来漉酒那堪著。", "高树莫鸣蝉。", "晚凉秋水眠。", "竹床能几尺。", "上有华胥国。", "山上咽飞泉。", "梦中琴断弦。"]'),
('song-ci-451','柳梢青','辛弃疾','宋','宋词','song-ci','柳梢青','["\u9ec4\u6cb3"]','莫炼丹难。',61,'宋词/ci.song.11000.json','["莫炼丹难。", "黄河可塞，金可成难。", "休辟谷难。", "吸风饮露，长忍饥难。", "劝君莫远游难。", "何处有、西王母难。", "休采药难。", "人沈下土，我上天难。"]'),
('song-ci-452','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','濮上看垂钓。',142,'宋词/ci.song.11000.json','["濮上看垂钓。", "更风流、羊裘泽畔，精神孤矫。", "楚汉黄金公卿印，比著渔竿谁小。", "但过眼、才堪一笑。", "惠子焉知濠梁乐，望桐江、千丈高台好。", "烟雨外，几鱼鸟。", "古来如许高人少。", "细平章、两翁似与，巢由同调。", "已被尧知方洗耳，毕竟尘污人了。", "要名字、人间如扫。", "我爱蜀庄沈冥者，解门前、不使徵书到。", "君为我，画三老。"]'),
('song-ci-453','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','下马东山路。',142,'宋词/ci.song.11000.json','["下马东山路。", "恍临风、周情孔思，悠然千古。", "寂寞东家丘何在，缥缈危亭小鲁。", "试重上、岩岩高处。", "更忆公归西悲日，正濛濛、陌上多零雨。", "嗟费却，几章句。", "谢安雅志还成趣。", "记风流、中年怀抱，长携歌舞。", "政尔良难君臣事，晚听秦筝声苦。", "快满眼、松篁千亩。", "把似渠垂功名泪，算何如、且作溪山主。", "双白鸟，又飞去。"]'),
('song-ci-454','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','逸气轩眉宇。',142,'宋词/ci.song.11000.json','["逸气轩眉宇。", "似王良、轻车熟路，骅骝欲舞。", "我觉君非池中物，咫尺蛟龙云雨。", "时与命、犹须天付。", "兰佩芳菲无人问，叹灵均、欲向重华诉。", "空壹郁，共谁语。", "儿曹不料扬雄赋。", "怪当年、甘泉误说，青葱玉树。", "风引船回沧溟阔，目断三山伊阻。", "但笑指、吾庐何许。", "门外苍官千百辈，尽堂堂、八尺须髯古。", "谁载酒，带湖去。"]'),
('song-ci-455','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','路入门前柳。',142,'宋词/ci.song.11000.json','["路入门前柳。", "到君家、悠然细说，渊明重九。", "岁晚凄其无诸葛，惟有黄花入手。", "更西风、东篱依旧。", "斗顿南山高如许，是先生、拄杖归来后。", "山不记，何年有。", "是中不减康庐秀。", "倩西风、为君唤起，翁能来否。", "鸟倦飞还平林去，云肯无心出岫。", "剩准备、新诗几首。", "欲辨忘言当年意，慨遥遥、我去羲农久。", "天下事，可无酒。"]'),
('song-ci-456','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','曾与东山约。',142,'宋词/ci.song.11000.json','["曾与东山约。", "为鯈鱼、从容分得，清泉一勺。", "堪笑高人读书处，多少松窗竹阁。", "甚长被、游人占却。", "万卷何言达时用，士方穷、早与人同乐。", "新种得，几花药。", "山头怪石蹲秋鹗。", "俯人间、尘埃野马，孤撑高攫。", "拄杖危亭扶未到，已觉云生两脚。", "更换却、朝来毛发。", "此地千年曾物化，莫呼猿、且自多招鹤。", "吾亦有，一丘壑。"]'),
('song-ci-457','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','["\u6d1e\u5ead\u6e56"]','拄杖重来约。',142,'宋词/ci.song.11000.json','["拄杖重来约。", "对东风、洞庭张乐，满空箫勺。", "巨海拔犀头角出，来向此山高阁。", "尚两两、三三前却。", "老我伤怀登临际，问何方、可以平哀乐。", "唯酒是，万金药。", "劝君且作横空鹗。", "便休论、人间腥腐，纷纷乌攫。", "九万里风斯在下，翻覆云头雨脚。", "更直上、昆仑濯发。", "好卧长虹陂十里，是谁言、听取双黄鹤。", "推翠影，浸云壑。"]'),
('song-ci-458','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','听我三章约。',142,'宋词/ci.song.11000.json','["听我三章约。", "有谈功、谈名者舞，谈经深酌。", "作赋相如亲涤器，识字子云投阁。", "算枉把、精神费却。", "此会不如公荣者，莫呼来、政尔妨人乐。", "医俗士，苦无药。", "当年众鸟看孤鹗。", "意飘然、横空直把，曹吞刘攫。", "老我山中谁来伴，须信穷愁有脚。", "似剪尽、还生僧发。", "自断此生天休问，倩何人、说与乘轩鹤。", "吾有志，在沟壑。"]'),
('song-ci-459','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','高阁临江渚。',142,'宋词/ci.song.11000.json','["高阁临江渚。", "访层城、空馀旧迹，黯然怀古。", "画栋珠帘当日事，不见朝云暮雨。", "但遗意、西山南浦。", "天宇修眉浮新绿，映悠悠、潭影长如故。", "空有恨，奈何许。", "王郎健笔夸翘楚。", "到如今、落霞孤鹜，竞传佳句。", "物换星移知几度，梦想珠歌翠舞。", "为徙倚、阑干凝伫。", "目断平芜苍波晚，快江风、一瞬澄襟暑。", "谁共饮，有诗侣。"]'),
('song-ci-460','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','老来曾识渊明，梦中一见参差是。',126,'宋词/ci.song.11000.json','["老来曾识渊明，梦中一见参差是。", "觉来幽恨，停觞不御，欲歌还止。", "白发西风，折腰五斗，不应堪此。", "问北窗高卧，东篱自醉，应别有、归来意。", "须信此翁未死。", "到如今、凛然生气。", "吾侪心事，古今长在，高山流水。", "富贵他年，直饶未免，也应无味。", "甚东山何事，当时也道，为苍生起。"]'),
('song-ci-461','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','被公惊倒瓢泉，倒流三峡词源泻。',126,'宋词/ci.song.11000.json','["被公惊倒瓢泉，倒流三峡词源泻。", "长安纸贵，流传一字，千金争舍。", "割肉怀归，先生自笑，又何廉也。", "但衔杯莫问，人间岂有，如孺子、长贫者。", "谁识稼轩心事，似风乎、舞雩之下。", "回头落日，苍茫万里，尘埃野马。", "更想隆中，卧龙千尺，高吟才罢。", "倩何人与问，雷鸣瓦釜，甚黄锺哑。"]'),
('song-ci-462','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','木末翠楼出，诗眼巧安排。',114,'宋词/ci.song.11000.json','["木末翠楼出，诗眼巧安排。", "天公一夜，削出四面玉崔嵬。", "畴昔此山安在，应为先生见挽，万马一时来。", "白鸟飞不尽，却带夕阳回。", "劝公饮，左手蟹，右手杯。", "人间万事变灭，今古几池台。", "君看庄生达者，犹对山林皋壤，哀乐未忘怀。", "我老尚能赋，风月试追陪。"]'),
('song-ci-463','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','万事几时足，日月自西东。',114,'宋词/ci.song.11000.json','["万事几时足，日月自西东。", "无穷宇宙，人是一粟太仓中。", "一葛一裘经岁，一钵一瓶终日，老子旧家风。", "更著一杯酒，梦觉大槐宫。", "记当年，吓腐鼠，叹冥鸿。", "衣冠神武门外，惊倒几儿童。", "休说须弥芥子，看取鵾鹏斥鷃，小大若为同。", "君欲论齐物，须访一枝翁。"]'),
('song-ci-464','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','唤起子陆子，经德问何如。',114,'宋词/ci.song.11000.json','["唤起子陆子，经德问何如。", "万锺於我何有，不负古人书。", "闻道千章松桂，剩有四时柯叶，霜雪岁寒馀。", "此是瑱山境，还似象山无。", "耕也馁，学也禄，孔子徒。", "青衫毕竟升斗，此意正关渠。", "天地清宁高下，日月东西寒暑，何用著工夫。", "两字君勿惜，借我榜吾庐。"]'),
('song-ci-465','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','十里深窈窕，万瓦碧参差。',116,'宋词/ci.song.11000.json','["十里深窈窕，万瓦碧参差。", "青山屋上，流水屋下绿横溪。", "真得归来笑语，方是闲中风月，剩费酒边诗。", "点检歌舞了，琴罢更围棋。", "王家竹，陶家柳，谢家池。", "知君勋业未了，不是枕流时。", "莫向痴儿说梦，且作山人索价，颇怪鹤书迟。", "一事定嗔我，已办《北山移》。"]'),
('song-ci-466','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','高马勿捶面，千里事难量。',114,'宋词/ci.song.11000.json','["高马勿捶面，千里事难量。", "长鱼变化云雨，无使寸鳞伤。", "一壑一丘吾事，一斗一石皆醉，风月几千场。", "须作猬毛磔，笔作剑锋长。", "我怜君，痴绝似，顾长康。", "纶巾羽扇颠倒，又似竹林狂。", "解道澄江如练，准备停云堂上，千首买秋光。", "怨调为谁赋，一斛贮槟榔。"]'),
('song-ci-467','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','我志在寥阔，畴昔梦登天。',114,'宋词/ci.song.11000.json','["我志在寥阔，畴昔梦登天。", "摩挲素月，人世俯仰已千年。", "有客骖麟并凤，云遇青山赤壁，相约上高寒。", "酌酒援北斗，我亦虱其间。", "少歌曰，神甚放，形则眠。", "鸿鹄一再高举，天地睹方圆。", "欲重歌兮梦觉，推枕惘然独念，人事底亏全。", "有美人可语，秋水隔娟娟。"]'),
('song-ci-468','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','看公风骨，似长松磊落，多生奇节。',120,'宋词/ci.song.11000.json','["看公风骨，似长松磊落，多生奇节。", "世上儿曹都蓄缩，冻芋旁堆秋瓞。", "结屋溪头，境随人胜，不是江山别。", "紫云如阵，妙歌争唱新阕。", "尊酒一笑相逢，与公臭味，菊茂兰须悦。", "天上四时调玉烛，万事宜询黄发。", "看取东归，周家叔父，手把元龟说。", "祝公长似，十分今夜明月。"]'),
('song-ci-469','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','龙山何处，记当年高会，重阳佳节。',120,'宋词/ci.song.11000.json','["龙山何处，记当年高会，重阳佳节。", "谁与老兵供一笑，落帽参军华发。", "莫倚忘怀，西风也会，点检尊前客。", "凄凉今古，眼中三两飞蝶。", "须信采菊东篱，高情千载，只有陶彭泽。", "爱说琴中如得趣，弦上何劳声切。", "试把空杯，翁还肯道，何必杯中物。", "临风一笑，请翁同醉今夕。"]'),
('song-ci-470','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','君诗好处，似邹鲁儒家，还有奇节。',120,'宋词/ci.song.11000.json','["君诗好处，似邹鲁儒家，还有奇节。", "下笔如神强压韵，遗恨都无毫发。", "灸手炎来，掉头冷去，无限长安客。", "丁宁黄菊，未消勾引蜂蝶。", "天上绛阙清都，听君归去，我自癯山泽。", "人道君才刚百炼，美玉都成泥切。", "我爱风流，醉中颠倒，丘壑胸中物。", "一杯相属，莫孤风月今夕。"]'),
('song-ci-471','新荷叶','辛弃疾','宋','宋词','song-ci','新荷叶','[]','曲水流觞，赏心乐事良辰。',99,'宋词/ci.song.11000.json','["曲水流觞，赏心乐事良辰。", "今几千年，风流禊事如新。", "明眸皓齿，看江头、有女如云。", "折花归去，绮罗陌上芳尘。", "丝竹纷纷。", "杨花飞鸟衔巾。", "争似群贤，茂林修竹兰亭。", "一觞一咏，亦足以畅叙幽情。", "清欢未了，不如留住青春。"]'),
('song-ci-472','新荷叶','辛弃疾','宋','宋词','song-ci','新荷叶','[]','种豆南山，零落一顷为萁。',100,'宋词/ci.song.11000.json','["种豆南山，零落一顷为萁。", "岁晚渊明，也吟草盛苗稀。", "风流剗地，向尊前、采菊题诗。", "悠然忽见，此山正绕东篱。", "千载襟期。", "高情想像当时。", "小阁横空，朝来翠扑人衣。", "是中真趣，问骋怀、游目谁知。", "无心出岫，白云一片孤飞。"]'),
('song-ci-473','婆罗门引','辛弃疾','宋','宋词','song-ci','婆罗门引','[]','龙泉佳处，种花满县却东归。',93,'宋词/ci.song.11000.json','["龙泉佳处，种花满县却东归。", "腰间玉若金累。", "须信功名富贵，长与少年期。", "怅高山流水，古调今悲。", "卧龙暂而。", "算天上、有人知。", "最好五十学易，三百篇诗。", "男儿事业，看一日、须有致君时。", "端的了、休更寻思。"]'),
('song-ci-474','行香子','辛弃疾','宋','宋词','song-ci','行香子','[]','少日尝闻。',84,'宋词/ci.song.11000.json','["少日尝闻。", "富不如贫。", "贵不如、贱者长存。", "由来至乐，总属闲人。", "且饮瓢泉，弄秋水，看停云。", "岁晚情亲。", "老语弥真。", "记前时、劝我殷勤。", "都休殢酒，也莫论文。", "把相牛经，种鱼法，教儿孙。"]'),
('song-ci-475','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','簟铺湘竹帐垂纱。',86,'宋词/ci.song.11000.json','["簟铺湘竹帐垂纱。", "醉眠些。", "梦天涯。", "一枕惊回，水底沸鸣蛙。", "借问喧天成鼓吹，良自苦，为官哪。", "心空喧静不争多。", "病维摩。", "意云何。", "扫地烧香，且看散天花。", "斜日绿阴枝上噪，还又问，是蝉麽。"]'),
('song-ci-476','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','两轮屋角走如梭。',86,'宋词/ci.song.11000.json','["两轮屋角走如梭。", "太忙些。", "怎禁他。", "拟倩何人，天上劝羲娥。", "何似从容来小住，倾美酒，听高歌。", "人生今古不须磨。", "积教多。", "似尘沙。", "未必坚牢，划地事堪嗟。", "漫道长生学不得，学得后，待如何。"]'),
('song-ci-477','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','叠嶂西驰，万马回旋，众山欲东。',139,'宋词/ci.song.11000.json','["叠嶂西驰，万马回旋，众山欲东。", "正惊湍直下，跳珠倒溅，小桥横截，缺月初弓。", "老合投闲，天教多事，检校长身十万松。", "吾庐小，在龙蛇影外，风雨声中。", "争先见面重重。", "看爽气朝来三数峰。", "似谢家子弟，衣冠磊落，相如庭户，车骑雍容。", "我觉其间，雄深雅健，如对文章太史公。", "新堤路，问偃湖何日，烟水濛濛。"]'),
('song-ci-478','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','甲子相高，亥首曾疑，绛县老人。',139,'宋词/ci.song.11000.json','["甲子相高，亥首曾疑，绛县老人。", "看长身玉立，鹤般风度，方颐须磔，虎样精神。", "文烂卿云，诗凌鲍谢，笔势骎骎更右军。", "浑馀事，羡仙都梦觉，金阙名存。", "门前父老忻忻。", "焕奎阁新褒沼语温。", "记他年帷幄，须依日月，只今剑履，快上星辰。", "人道阴功，天教多寿，看到貂蝉七叶孙。", "君家里，是几枝丹桂，几树灵椿。"]'),
('song-ci-479','喜迁莺','辛弃疾','宋','宋词','song-ci','喜迁莺','[]','暑风凉月。',126,'宋词/ci.song.11000.json','["暑风凉月。", "爱亭亭无数，绿衣持节。", "掩冉如羞，参差似妒，拥出芙渠花发。", "步衬潘娘堪恨，貌比六郎谁洁。", "添白鹭，晚晴时，公子佳人并列。", "休说。", "搴木末。", "当日灵均，恨与君王别。", "心阻媒劳，交疏怨极，恩不甚兮轻绝。", "千古离骚文字，芳至今犹未歇。", "都休问，但千杯快饮，露荷翻叶。"]'),
('song-ci-480','永遇乐','辛弃疾','宋','宋词','song-ci','永遇乐','[]','怪底寒梅，一枝雪里，直恁愁绝。',127,'宋词/ci.song.11000.json','["怪底寒梅，一枝雪里，直恁愁绝。", "问讯无言，依稀似妒，天上飞英白。", "江山一夜，琼瑶万顷，此段如何妒得。", "细看来，风流添得，自家越样标格。", "晓来楼上，对花临镜，学作半妆宫额。", "著意争妍，那知却有，人妒花颜色。", "无情休问，许多般事，且自访梅踏雪。", "待行过溪桥，夜半更邀素月。"]'),
('song-ci-481','永遇乐','辛弃疾','宋','宋词','song-ci','永遇乐','[]','烈日秋霜，忠肝义胆，千载家谱。',128,'宋词/ci.song.11000.json','["烈日秋霜，忠肝义胆，千载家谱。", "得姓何年，细参辛字，一笑君听取。", "艰辛做就，悲辛滋味，总是辛酸辛苦。", "更十分，向人辛辣，椒桂捣残堪吐。", "世间应有，芳甘浓美，不到吾家门户。", "比著儿曹，累累却有，金印光垂组。", "付君此事，从今直上，休忆对床风雨。", "但赢得，靴纹绉面，记余戏语。"]'),
('song-ci-482','归朝欢','辛弃疾','宋','宋词','song-ci','归朝欢','[]','万里康成西走蜀。',124,'宋词/ci.song.11000.json','["万里康成西走蜀。", "药市船归书满屋。", "有时光彩射星躔，何人汉简雠天禄。", "好之宁有足。", "请看良贾藏金玉。", "记斯文，千年未丧，四壁闻丝竹。", "试问辛勤携一束。", "何似牙签三万轴。", "古来不作借人痴，有朋只就云窗读。", "忆君清梦熟。", "觉来笑我便便腹。", "倚危楼，人间何处，扫地《八风曲》。"]'),
('song-ci-483','瑞鹤仙','辛弃疾','宋','宋词','song-ci','瑞鹤仙','[]','片帆何太急。',127,'宋词/ci.song.11000.json','["片帆何太急。", "望一点须臾，去天咫尺。", "舟人好看客。", "似三峡风涛，嵯峨剑戟。", "溪南溪北。", "正遐想、幽人泉石。", "看渔憔、指点危楼，却羡舞筵歌席。", "叹息。", "山林锺鼎，意倦情迁，本无欣戚。", "转头陈迹。", "飞鸟外，晚烟碧。", "问谁怜旧日，南楼老子，最爱月明吹笛。", "到而今、扑面黄尘，欲归未得。"]'),
('song-ci-484','玉蝴蝶','辛弃疾','宋','宋词','song-ci','玉蝴蝶','[]','贵贱偶然，浑似随风帘幌，篱落飞花。',124,'宋词/ci.song.11000.json','["贵贱偶然，浑似随风帘幌，篱落飞花。", "空使儿曹，马上羞面频遮。", "向空江、谁捐玉珮，寄离恨、应折疏麻。", "暮云多。", "佳人何处，数尽归鸦。", "侬家。", "生涯蜡屐，功名破甑，交友抟沙。", "往日曾论，渊明似胜卧龙些。", "记从来、人生行乐，休更问、日饮亡何。", "快堪呵。", "裁诗未稳，得酒良佳。"]'),
('song-ci-485','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','我对君侯，长怪见、两眉阴德。',115,'宋词/ci.song.11000.json','["我对君侯，长怪见、两眉阴德。", "更长梦、玉皇金阙，姓名仙籍。", "旧岁炊烟浑欲断，被公扶起千人活。", "算胸中、除却五车书，都无物。", "溪左右，山南北。", "花远近，云朝夕。", "看风流杖屦，苍髯如戟。", "种柳已成陶令宅，散花更满维摩室。", "劝人间、且住五千年，如金石。"]'),
('song-ci-486','雨中花慢','辛弃疾','宋','宋词','song-ci','雨中花慢','[]','马上三年，醉帽吟鞭，锦囊诗卷长留。',118,'宋词/ci.song.11000.json','["马上三年，醉帽吟鞭，锦囊诗卷长留。", "怅溪山旧管，风月新收。", "明便关河杳杳，去应日月悠悠。", "笑千篇索价，未抵蒲萄，五斗凉州。", "停云老子，有酒盈尊，琴书端可消忧。", "浑未办、倾身一饱，淅米矛头。", "心似伤弓塞雁，身如喘月吴牛。", "晚天凉也，月明谁伴，吹笛南楼。"]'),
('song-ci-487','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','婆娑欲舞，怪青山欢喜。',101,'宋词/ci.song.11000.json','["婆娑欲舞，怪青山欢喜。", "分得清溪半篙水。", "记平沙鸥鹭，落日渔樵，湘江上，风景依然如此。", "东篱多种菊，待学渊明，酒兴诗情不相似。", "十里涨春波，一棹归来，只做个、五湖范蠡。", "是则是、一般弄扁舟，争知道，他家有个西子。"]'),
('song-ci-488','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','旧交贫贱，太半成新贵。',100,'宋词/ci.song.11000.json','["旧交贫贱，太半成新贵。", "冠盖门前几行李。", "看匆匆西笑，争出山来，凭谁问，小草何如远志。", "悠悠今古事。", "得丧乘除，暮四朝三又何异。", "任掀天勋业，冠古文章，有几个、笙歌晚岁。", "况满屋貂蝉未为荣，记裂土分茅，是公家世。"]'),
('song-ci-489','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','松关桂岭，望青葱无路。',103,'宋词/ci.song.11000.json','["松关桂岭，望青葱无路。", "费尽银钩榜佳处。", "怅空山岁晚，窈窕谁来，须著我，醉卧石楼风雨。", "仙人琼海上，握手当年，笑许君携半山去。", "劖叠嶂，卷飞泉，洞府凄凉，又却怪、先生多取。", "怕夜半、罗浮有时还，好长把云烟，再三遮住。"]'),
('song-ci-490','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','欲上高楼去避愁。',64,'宋词/ci.song.11000.json','["欲上高楼去避愁。", "愁还随我上高楼。", "经行几处江山改，多少亲朋尽白头。", "归休去，去归休。", "不成人总要封侯。", "浮云出处元无定，得似浮云也自由。"]'),
('song-ci-491','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','一片归心拟乱云。',64,'宋词/ci.song.11000.json','["一片归心拟乱云。", "春来谙尽恶黄昏。", "不堪向晚檐前雨，又待今宵滴梦魂。", "炉烬冷，鼎香氛。", "酒寒谁遣为重温。", "何人柳外横双笛，客耳那堪不忍闻。"]'),
('song-ci-492','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','修竹翠罗寒，迟日江山暮。',52,'宋词/ci.song.11000.json','["修竹翠罗寒，迟日江山暮。", "幽迳无人独自芳，此恨知无数。", "只共梅花语。", "懒逐游丝去。", "著意寻春不肯香，香在无寻处。"]'),
('song-ci-493','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','欲行且起行，欲坐重来坐。',52,'宋词/ci.song.11000.json','["欲行且起行，欲坐重来坐。", "坐坐行行有倦时，更枕闲书卧。", "病是近来身，懒是从前我。", "静扫瓢泉竹树阴，且凭随缘过。"]'),
('song-ci-494','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','红粉靓梳妆，翠盖低风雨。',52,'宋词/ci.song.11000.json','["红粉靓梳妆，翠盖低风雨。", "占断人间六月凉，期月鸳鸯浦。", "根底藕丝长，花里莲心苦。", "只为风流有许愁，更衬佳人步。"]'),
('song-ci-495','点绛唇','辛弃疾','宋','宋词','song-ci','点绛唇','[]','身后功名，古来不换生前醉。',50,'宋词/ci.song.11000.json','["身后功名，古来不换生前醉。", "青鞋自喜。", "不踏长安市。", "竹外僧归，路指霜锺寺。", "孤鸿起。", "丹青手里。", "剪破松江水。"]'),
('song-ci-496','谒金门','辛弃疾','宋','宋词','song-ci','谒金门','[]','遮素月。',53,'宋词/ci.song.11000.json','["遮素月。", "云外金蛇明灭。", "翻树啼鸦声未彻。", "雨声惊落叶。", "宝蜡成行嫌热。", "玉腕藕花谁雪。", "流水高山弦断绝。", "怒蛙声自咽。"]'),
('song-ci-497','谒金门','辛弃疾','宋','宋词','song-ci','谒金门','[]','山吐月。',53,'宋词/ci.song.11000.json','["山吐月。", "画烛从教风灭。", "一曲瑶琴才听彻。", "金蕉三两叶。", "骤雨微凉还热。", "似欠舞琼歌雪。", "近日醉乡音问绝。", "有时清泪咽。"]'),
('song-ci-498','东坡引','辛弃疾','宋','宋词','song-ci','东坡引','[]','玉纤弹旧怨。',70,'宋词/ci.song.11000.json','["玉纤弹旧怨。", "还敲绣屏面。", "清歌目送西风雁。", "雁行吹字断。", "雁行吹字断。", "夜深拜月，琐窗西畔。", "但桂影、空阶满。", "翠帏自掩无人见。", "罗衣宽一半。", "罗衣宽一半。"]'),
('song-ci-499','醉花阴','辛弃疾','宋','宋词','song-ci','醉花阴','[]','黄花谩说年年好。',62,'宋词/ci.song.11000.json','["黄花谩说年年好。", "也趁秋光老。", "绿鬓不惊秋，若斗尊前，人好花堪笑。", "蟠桃结子知多少。", "家住三山岛。", "何日跨归鸾，沧海飞尘，人世因缘了。"]'),
('song-ci-500','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','清词索笑。',54,'宋词/ci.song.11000.json','["清词索笑。", "莫厌银杯小。", "应是天孙新与巧。", "剪恨裁愁句好。", "有人梦断关河。", "小窗日饮亡何。", "想见重帘不卷，泪痕滴尽湘娥。"]'),
('song-ci-501','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','灵皇醮罢。',54,'宋词/ci.song.11000.json','["灵皇醮罢。", "福禄都来也。", "试引鹓雏花树下。", "断了惊惊怕怕。", "从今日日聪明。", "更宜潭妹嵩兄。", "看取辛家铁柱，无灾无难公卿。"]'),
('song-ci-502','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','月明秋晓。',54,'宋词/ci.song.11000.json','["月明秋晓。", "翠盖团团好。", "碎剪黄金教恁小。", "都著叶儿遮了。", "折来休似年时。", "小窗能有高低。", "无顿许多香处，只消三两枝儿。"]'),
('song-ci-503','醉翁操','辛弃疾','宋','宋词','song-ci','醉翁操','[]','长松。',112,'宋词/ci.song.11000.json','["长松。", "之风。", "如公。", "肯余从。", "山中。", "人心与吾兮谁问。", "湛湛千里之江。", "上有枫。", "噫，送子东。", "望君之门兮九重。", "女无悦己，谁适为容。", "不龟手药，或一朝兮取封。", "昔与游兮皆童。", "我独穷兮今翁。", "一鱼兮一龙。", "劳心兮忡忡。", "噫，命与时逢。", "子取之食兮万锺。"]'),
('song-ci-504','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','秀骨青松不老，新词玉佩相磨。',58,'宋词/ci.song.11000.json','["秀骨青松不老，新词玉佩相磨。", "灵槎准拟泛银河。", "剩摘天星几个。", "奠枕楼东风月，驻春亭上笙歌。", "留君一醉意如何。", "金印明年斗大。"]'),
('song-ci-505','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','鹅湖山下长亭路，明月临关。',52,'宋词/ci.song.11000.json','["鹅湖山下长亭路，明月临关。", "明月临关。", "几阵西风落叶乾。", "新词谁解裁冰雪，笔墨生寒。", "笔墨生寒。", "会说离愁千万般。"]'),
('song-ci-506','破阵子','辛弃疾','宋','宋词','song-ci','破阵子','[]','掷地刘郎玉斗，挂帆西子扁舟。',72,'宋词/ci.song.11000.json','["掷地刘郎玉斗，挂帆西子扁舟。", "千古风流今在此，万里功名莫放休。", "君王三百州。", "燕雀岂知鸿鹄，貂蝉元出兜鍪。", "却笑泸溪如斗大，肯把牛刀试手不。", "寿君双玉瓯。"]'),
('song-ci-507','破阵子','辛弃疾','宋','宋词','song-ci','破阵子','[]','醉里挑灯看剑，梦回吹角连营。',72,'宋词/ci.song.11000.json','["醉里挑灯看剑，梦回吹角连营。", "八百里分麾下炙，五十弦翻塞外声。", "沙场秋点兵。", "马作的卢飞快，弓如霹雳弦惊。", "了却君王天下事，赢得生前身后名。", "可怜白发生。"]'),
('song-ci-508','千年调','辛弃疾','宋','宋词','song-ci','千年调','[]','左手把青霓，右手挟明月。',93,'宋词/ci.song.11000.json','["左手把青霓，右手挟明月。", "吾使丰隆前导，叫开阊阖。", "周游上下，径入寥天一。", "览县圃，万斛泉，千丈石。", "钧天广乐，燕我瑶之席。", "帝饮予觞甚乐，赐汝苍璧。", "嶙峋突兀，正在一丘壑。", "余马怀，仆夫悲，下恍惚。"]'),
('song-ci-509','祝英台近','辛弃疾','宋','宋词','song-ci','祝英台近','[]','水纵横，山远近。',95,'宋词/ci.song.11000.json','["水纵横，山远近。", "拄杖占千顷。", "老眼羞将，水底看山影。", "试教水动山摇，吾生堪笑，似此个、青山无定。", "一瓢饮。", "人问翁爱飞泉，来寻个中静。", "绕屋生喧，怎做静中境。", "我眠君且归休，维摩方丈，待天女、散花时问。"]'),
('song-ci-510','祝英台近','辛弃疾','宋','宋词','song-ci','祝英台近','[]','绿杨堤，青草渡。',95,'宋词/ci.song.11000.json','["绿杨堤，青草渡。", "花片水流去。", "百舌声中，唤起海棠睡。", "断肠几点愁红，蹄痕犹在，多应怨、夜来风雨。", "别情苦。", "马蹄踏遍长亭，归期又成误。", "帘卷青楼，回首在何处。", "画梁燕子双双，能言能语，不解说、相思一句。"]'),
('song-ci-511','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','看君人物汉西都。',86,'宋词/ci.song.11000.json','["看君人物汉西都。", "过吾庐。", "笑谈初。", "便说公卿，元自要通儒。", "一自梅花开了后，长怕说，赋归欤。", "而今别恨满江湖。", "怎消除。", "算何如。", "杖屦当时，闻早放教疏。", "今代故交新贵后，浑不寄，数行书。"]'),
('song-ci-512','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','云烟草树。',54,'宋词/ci.song.11000.json','["云烟草树。", "山北山南雨。", "溪上行人相背去。", "惟有啼鸦一处。", "门前万斛春寒。", "梅花可㬠摧残。", "使我长忘酒易，要君不作诗难。"]'),
('song-ci-513','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','莫笑吾家苍壁小，棱层势欲摩空。',70,'宋词/ci.song.11000.json','["莫笑吾家苍壁小，棱层势欲摩空。", "相知惟有主人翁。", "有心雄泰华，无意巧玲珑。", "天作高山谁得料，解嘲试倩扬雄。", "君看当日仲尼穷。", "从人贤子贡，自欲学周公。"]'),
('song-ci-514','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','记取年年为寿客，只今明月相随。',70,'宋词/ci.song.11000.json','["记取年年为寿客，只今明月相随。", "莫教弦管便生衣。", "引壶觞自酌，须富贵何时。", "入手清风词更好，细书白茧乌丝。", "海山问我几时归。", "枣瓜如可啖，直欲觅安期。"]'),
('song-ci-515','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','忆醉三山芳树下，几层风韵忘怀。',70,'宋词/ci.song.11000.json','["忆醉三山芳树下，几层风韵忘怀。", "黄金颜色五花开。", "味如庐橘熟。", "贵似荔枝来。", "闻道商山馀四老，橘中自酿秋醅。", "试呼名品细推排。", "重重香腑脏，偏殢圣贤杯。"]'),
('song-ci-516','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','夜语南堂新瓦响，三更急雨珊珊。',72,'宋词/ci.song.11000.json','["夜语南堂新瓦响，三更急雨珊珊。", "交情莫作细沙团。", "死生贫富际，试向此中看。", "记取他年《耆旧传》，与君名字牵连。", "清风一枕晚凉天。", "觉来还自笑，此梦倩谁园。"]'),
('song-ci-517','南乡子','辛弃疾','宋','宋词','song-ci','南乡子','[]','日日老莱衣。',66,'宋词/ci.song.11000.json','["日日老莱衣。", "更解风流蜡凤嬉。", "膝上放教文度去，须知。", "要使人看玉树枝。", "剩记乃翁诗。", "绿水红莲觅旧题。", "归骑春衫花满路，相期。", "来岁流觞曲水时。"]'),
('song-ci-518','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','有无一理谁差别。',64,'宋词/ci.song.11000.json','["有无一理谁差别。", "乐令区区浑未达。", "事言无处未尝无，试把所无凭理说。", "伯夷饥采西山蕨。", "何异捣齑餐杵铁。", "仲尼去卫又之陈，此是乘车入鼠穴。"]'),
('song-ci-519','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','客来底事逢迎晚。',64,'宋词/ci.song.11000.json','["客来底事逢迎晚。", "竹里鸣禽寻未见。", "日高犹苦圣贤中，门外谁酣蛮触战。", "多方为渴寻泉遍。", "何日成阴松种满。", "不辞长向水云来，只怕频烦鱼鸟倦。"]'),
('song-ci-520','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','何人半夜推山去。',64,'宋词/ci.song.11000.json','["何人半夜推山去。", "四面浮云猜是汝。", "常时相对两三峰，走遍溪头无觅处。", "西风瞥起云横渡。", "忽见东南天一柱。", "老僧拍手笑相夸，且喜青山依旧住。"]'),
('song-ci-521','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','青山不会乘云去。',64,'宋词/ci.song.11000.json','["青山不会乘云去。", "怕有愚公惊著汝。", "人间踏地出租钱，借使移将无著处。", "三星昨夜光移度。", "妙语来题桥上柱。", "黄花不插满头归，定倩白云遮且住。"]'),
('song-ci-522','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','少年才把笙歌𧣴',63,'宋词/ci.song.11000.json','["少年才把笙歌𧣴", "夏日非长秋夜短。", "因他老病不相饶，把好心情都做懒。", "故人别后书来劝。", "乍可停杯强吃饭。", "云何相遇酒边时，却道达人须饮满。"]'),
('song-ci-523','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','君如九酝台黏𧣴',63,'宋词/ci.song.11000.json','["君如九酝台黏𧣴", "我似茅柴风味短。", "几时秋水美人来，长恐扁舟乘兴懒。", "高怀自饮无人劝。", "马有青刍奴白饭。", "向来珠履玉簪人，颇觉斗量车载满。"]'),
('song-ci-524','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','狂歌击碎村醪𧣴',63,'宋词/ci.song.11000.json','["狂歌击碎村醪𧣴", "欲舞还怜衫袖短。", "身如溪上钓矶闲，心似道旁官堠懒。", "山中有酒提壶劝。", "好语多君堪鮓饭。", "至今有句落人间，渭水西风黄叶满。"]'),
('song-ci-525','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','趁得东风汗漫游。',64,'宋词/ci.song.11000.json','["趁得东风汗漫游。", "见他歌后怎生愁。", "事如芳草春长在，人似浮云影不留。", "眉黛敛，眼波流。", "十年薄幸谩扬州。", "明朝短棹轻衫梦，只在溪南罨画楼。"]'),
('song-ci-526','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','叹息频年廪未高。',64,'宋词/ci.song.11000.json','["叹息频年廪未高。", "新词空贺此丘遭。", "遥知醉帽时时落，见说吟鞭步步摇。", "乾玉唾，秃锥毛。", "只今明月费招邀。", "最怜乌鹊南飞句，不解风流见二乔。"]'),
('song-ci-527','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','戏马台前秋雁飞。',64,'宋词/ci.song.11000.json','["戏马台前秋雁飞。", "管弦歌舞更旌旗。", "要知黄菊清高处，不入当年二谢诗。", "倾白酒，绕东篱。", "只於陶令有心期。", "明朝重九浑潇洒，莫使尊前欠一枝。"]'),
('song-ci-528','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','水荇参差动绿波。',64,'宋词/ci.song.11000.json','["水荇参差动绿波。", "一池蛇影噤群蛙。", "因风野鹤饥犹舞，积雨山栀病不花。", "名利处，战争多。", "门前蛮触日干戈。", "不知更有槐安国，梦觉南柯日未斜。"]'),
('song-ci-529','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','出处从来自不齐。',64,'宋词/ci.song.11000.json','["出处从来自不齐。", "后车方载太公归。", "谁知孤竹夷齐子，正向空山赋采薇。", "黄菊嫩，晚香枝。", "一般同是采花时。", "蜂儿辛苦多官府，蝴蝶花间自在飞。"]'),
('song-ci-530','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','秋水长廊水石间。',64,'宋词/ci.song.11000.json','["秋水长廊水石间。", "有谁来共听潺湲。", "羡君人物东西晋，分我诗名大小山。", "穷自乐，懒方闲。", "人间路窄酒杯宽。", "看君不了痴儿事，又似风流靖长官。"]'),
('song-ci-531','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','壮岁旌旗拥万夫。',64,'宋词/ci.song.11000.json','["壮岁旌旗拥万夫。", "锦襜突骑渡江初。", "燕兵夜娖银胡䩮，汉箭朝飞金仆姑。", "追往事，叹今吾。", "春风不染白髭须。", "都将万字平戎策，换得东家种树书。"]'),
('song-ci-532','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','上巳风光好放怀。',64,'宋词/ci.song.11000.json','["上巳风光好放怀。", "忆君犹未看花回。", "茂林映带谁家竹，曲水流传第几杯。", "摛锦绣，写玫瑰。", "长年富贵属多才。", "要知此日生男好，曾有周公祓禊来。"]'),
('song-ci-533','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','去岁君家把酒杯。',64,'宋词/ci.song.11000.json','["去岁君家把酒杯。", "雪中曾见牡丹开。", "而今纨扇薰风里，又见疏枝月下梅。", "欢几许，醉方回。", "明朝归路有人摧。", "低声待向他家道，带得歌声满耳来。"]'),
('song-ci-534','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','溪边白鹭。',68,'宋词/ci.song.11000.json','["溪边白鹭。", "来吾告汝。", "溪里鱼儿堪数。", "主人怜汝汝怜鱼，要物我、欣然一处。", "白沙远浦。", "青泥别渚。", "剩有虾跳鳅舞。", "任君飞去饱时来，看头上、风吹一缕。"]'),
('song-ci-535','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','画栋新垂帘幕，华灯未放笙歌。',58,'宋词/ci.song.11000.json','["画栋新垂帘幕，华灯未放笙歌。", "一杯潋滟泛金波。", "先向太夫人贺。", "富贵吾应自有，功名不用渠多。", "只将绿鬓抵羲娥。", "金印须教斗大。"]'),
('song-ci-536','西江月','辛弃疾','宋','宋词','song-ci','西江月','["\u897f\u6e56"]','风月亭危致爽，管弦声脆休催。',58,'宋词/ci.song.11000.json','["风月亭危致爽，管弦声脆休催。", "主人只是旧时怀。", "锦瑟旁边须醉。", "玉殿何须侬去，沙堤只要公来。", "看看红药又翻阶。", "趁取西湖春会。"]'),
('song-ci-537','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','贪数明朝重九。',58,'宋词/ci.song.11000.json','["贪数明朝重九。", "不知过了中秋。", "人生有得许多愁。", "惟有黄花如旧。", "万象亭中殢酒。", "九江阁上扶头。", "城鸦唤我醉归休。", "细雨斜风时候。"]'),
('song-ci-538','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','醉里且贪欢笑，要愁那得工夫。',58,'宋词/ci.song.11000.json','["醉里且贪欢笑，要愁那得工夫。", "近来始觉古人书。", "信著全无是处。", "昨夜松边醉倒，问松我醉何如。", "只疑松动要来扶。", "以手推松曰去。"]'),
('song-ci-539','瑞鹧鸪','辛弃疾','宋','宋词','song-ci','瑞鹧鸪','[]','江头日日打头风。',64,'宋词/ci.song.11000.json','["江头日日打头风。", "憔悴归来邴曼容。", "郑贾正应求死鼠，叶公岂是好真龙。", "孰居无事陪犀首，未办求封遇万松。", "却笑千年曹孟德，梦中相对也龙锺。"]'),
('song-ci-540','瑞鹧鸪','辛弃疾','宋','宋词','song-ci','瑞鹧鸪','[]','期思溪上日千回。',64,'宋词/ci.song.11000.json','["期思溪上日千回。", "樟木桥边酒数杯。", "人影不随流水去，醉颜重带少年来。", "疏蝉响涩林逾静，冷蝶飞轻菊半开。", "不是长卿终慢世，只缘多病又非才。"]'),
('song-ci-541','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','无心云自来还去。',64,'宋词/ci.song.11000.json','["无心云自来还去。", "元共青山相尔汝。", "霎时迎雨障崔嵬，雨过却寻归路处。", "侵天翠竹何曾度。", "遥见屹然星砥柱。", "今朝不管乱云深，来伴仙翁山下住。"]'),
('song-ci-542','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','瘦筇倦作登高去。',64,'宋词/ci.song.11000.json','["瘦筇倦作登高去。", "却怕黄花相尔汝。", "岭头拭目望龙安，更在云烟遮断处。", "思量落帽人风度。", "休说当年功纪柱。", "谢公直是爱东山，毕竟东山留不住。"]'),
('song-ci-543','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','风前欲劝春光住。',64,'宋词/ci.song.11000.json','["风前欲劝春光住。", "春在城南芳草路。", "未随流落水边花，且作飘零泥上絮。", "镜中已觉星星误。", "人不负春春自负。", "梦回人远许多愁，只在梨花风雨处。"]'),
('song-ci-544','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','悠悠莫向文山去。',64,'宋词/ci.song.11000.json','["悠悠莫向文山去。", "要把襟裾牛马汝。", "遥知书带草边行，正在雀罗门里住。", "平生插架昌黎句。", "不似拾柴东野苦。", "侵天且拟凤凰巢，扫地从他鸖鹆舞。"]'),
('song-ci-545','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','琵琶亭畔多芳草。',64,'宋词/ci.song.11000.json','["琵琶亭畔多芳草。", "时对香炉峰一笑。", "偶然重傍玉溪东，不是白头谁觉老。", "普陀大士神通妙。", "影入石头光了了。", "看来持献可无言，长似慈悲颜色好。"]'),
('song-ci-546','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','江头一带斜阳树。',64,'宋词/ci.song.11000.json','["江头一带斜阳树。", "总是六朝人住处。", "悠悠兴废不关心，惟有沙洲双白鹭。", "仙人矶下多风雨。", "好卸征帆留不住。", "直须抖擞尽尘埃，却趁新凉秋水去。"]'),
('song-ci-547','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','少年风月，少年歌舞，老去方知堪羡。',70,'宋词/ci.song.11000.json','["少年风月，少年歌舞，老去方知堪羡。", "叹折腰、五斗赋归来，问走了、羊肠几遍。", "高车驷马，金章紫绶，传语渠侬稳便。", "问东湖、带得几多春，且看凌云笔健。"]'),
('song-ci-548','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','且对东君痛饮，莫教华发空催。',60,'宋词/ci.song.11000.json','["且对东君痛饮，莫教华发空催。", "琼瑰千字已盈怀。", "消得津头一醉。", "休唱《阳关》别去，只今凰诏归来。", "五云两两望三台。", "已觉精神聚会。"]'),
('song-ci-549','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','剩欲读书已懒，只因多病长闲。',58,'宋词/ci.song.11000.json','["剩欲读书已懒，只因多病长闲。", "听风听雨小窗眠。", "过了春光太半。", "往事如寻去鸟，清愁难解连环。", "流莺不肯入西园。", "唤起画梁飞燕。"]'),
('song-ci-550','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','金粟如来出世，蕊宫仙子乘风。',58,'宋词/ci.song.11000.json','["金粟如来出世，蕊宫仙子乘风。", "清香一袖意无穷。", "洗尽尘缘千种。", "长为西风作主，更居明月光中。", "十分秋意与玲珑。", "拼却今宵无梦。"]'),
('song-ci-551','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','八万四千偈后，更谁妙语披襟。',58,'宋词/ci.song.11000.json','["八万四千偈后，更谁妙语披襟。", "纫兰结佩有同心。", "唤取诗翁来饮。", "镂玉栽冰著句，高山流水知音。", "胸中不受一尘侵。", "却怕灵均独醒。"]'),
('song-ci-552','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','粉面都成醉梦，霜髯能几春秋。',60,'宋词/ci.song.11000.json','["粉面都成醉梦，霜髯能几春秋。", "来时诵我《伴牢愁》。", "一见尊前似旧。", "诗在阴何侧畔，字居罗赵前头。", "锦囊来往几时休。", "已遣蛾眉等候。"]'),
('song-ci-553','朝中措','辛弃疾','宋','宋词','song-ci','朝中措','[]','年年黄菊滟秋风。',57,'宋词/ci.song.11000.json','["年年黄菊滟秋风。", "更有拒霜红。", "黄似旧时宫额，红如此日芳容。", "青青未老，尊前要看，儿辈平戎。", "试酿西江为寿，西江绿水无穷。"]'),
('song-ci-554','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','溪回沙浅。',54,'宋词/ci.song.11000.json','["溪回沙浅。", "红杏都开遍。", "鸂鶒不知春水暖。", "犹傍垂杨春岸。", "片帆千里轻船。", "行人想见敧眠。", "谁似先生高举，一行白鹭青天。"]'),
('song-ci-555','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','明月到今宵，长是不如人约。',53,'宋词/ci.song.11000.json','["明月到今宵，长是不如人约。", "想见广寒宫殿，正云梳风掠。", "夜深休更唤笙歌，檐头雨声恶。", "不是小山词就，这一场寥索。"]'),
('song-ci-556','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','云气上林梢，毕竟非空非色。',53,'宋词/ci.song.11000.json','["云气上林梢，毕竟非空非色。", "风景不随人去，到而今留得。", "老无情味到篇章，诗债怕人索。", "却笑近来林下，有许多词客。"]'),
('song-ci-557','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','江摇病眼昏如雾。',52,'宋词/ci.song.11000.json','["江摇病眼昏如雾。", "送愁直到津头路。", "归念乐天诗。", "人生足别离。", "云屏深夜语。", "梦到君知否。", "玉箸莫偷垂。", "断肠天不知。"]'),
('song-ci-558','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','西风都是行人恨。',52,'宋词/ci.song.11000.json','["西风都是行人恨。", "马头渐喜归期近。", "试上小红楼。", "飞鸿字字愁。", "阑干闲倚处。", "一带山无数。", "不似远山横。", "秋波相共明。"]'),
('song-ci-559','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','功名饱听儿童说。',52,'宋词/ci.song.11000.json','["功名饱听儿童说。", "看公两眼明如月。", "万里勒燕然。", "老人书一编。", "玉阶方寸地。", "好趁风云会。", "他日赤松游。", "依然万户侯。"]'),
('song-ci-560','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','送君直上金銮殿。',52,'宋词/ci.song.11000.json','["送君直上金銮殿。", "情知不久须相见。", "一日甚三秋。", "愁来不自由。", "九重天一笑。", "定是留中了。", "白发少经过。", "此时愁奈何。"]'),
('song-ci-561','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','人间岁月堂堂去。',52,'宋词/ci.song.11000.json','["人间岁月堂堂去。", "劝君快上青云路。", "圣处一灯传。", "工夫萤雪边。", "曲生风味恶。", "辜负西窗约。", "沙岸片帆开。", "寄书无雁来。"]'),
('song-ci-562','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','红牙签上群仙格。',52,'宋词/ci.song.11000.json','["红牙签上群仙格。", "翠罗盖底倾城色。", "和雨泪阑干。", "沈香亭北看。", "东风休放去。", "怕有流莺诉。", "试问赏花人。", "晓妆匀未匀。"]'),
('song-ci-563','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','君家玉雪花如屋。',52,'宋词/ci.song.11000.json','["君家玉雪花如屋。", "未应山下成三宿。", "啼鸟几曾催。", "西风犹未来。", "山房连石径。", "云卧衣裳冷。", "倩得李延年。", "清歌送上天。"]'),
('song-ci-564','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','万里籋浮云，一喷空凡马。',54,'宋词/ci.song.11000.json','["万里籋浮云，一喷空凡马。", "叹息曹瞒《老骥》诗，伏枥如公者。", "山鸟哢窥檐，野鼠饥翻瓦。", "老我痴顽合住山，此地菟裘也。"]'),
('song-ci-565','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','晚来云淡秋光薄，落日晴天。',52,'宋词/ci.song.11000.json','["晚来云淡秋光薄，落日晴天。", "落日晴天。", "堂上风斜画烛烟。", "从渠去买人间恨，字字都圆。", "字字都圆。", "肠断西风十四弦。"]'),
('song-ci-566','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','寻常中酒扶头后，歌舞支持。',52,'宋词/ci.song.11000.json','["寻常中酒扶头后，歌舞支持。", "歌舞支持。", "谁把新词唤住伊。", "临歧也有旁人笑，笑己争知。", "笑己争知。", "明月楼空燕子飞。"]'),
('song-ci-567','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','此生自断天休问，独倚危楼。',52,'宋词/ci.song.11000.json','["此生自断天休问，独倚危楼。", "独倚危楼。", "不信人间别有愁。", "君来正是眠时节，君且归休。", "君且归休。", "说与西风一任秋。"]'),
('song-ci-568','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','近来愁似天来大，谁解相怜。',52,'宋词/ci.song.11000.json','["近来愁似天来大，谁解相怜。", "谁解相怜。", "又把愁来做个天。", "都将今古无穷事，放在愁边。", "放在愁边。", "却自移家向酒泉。"]'),
('song-ci-569','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','年年索尽梅花笑，疏影黄昏。',52,'宋词/ci.song.11000.json','["年年索尽梅花笑，疏影黄昏。", "疏影黄昏。", "香满东风月一痕。", "清诗冷落无人寄，雪艳冰魂。", "雪艳冰魂。", "浮玉溪头烟树村。"]'),
('song-ci-570','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','寿酒同斟喜有馀。',48,'宋词/ci.song.11000.json','["寿酒同斟喜有馀。", "朱颜却对白髭须。", "两人百岁恰乘除。", "婚嫁剩添儿女拜，平安频拆外家书。", "年年堂上寿星图。"]'),
('song-ci-571','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','歌串如珠个个匀。',48,'宋词/ci.song.11000.json','["歌串如珠个个匀。", "被花勾引笑和颦。", "向来惊动画梁尘。", "莫倚笙歌多乐事，相看红紫又抛人。", "旧巢还有燕泥新。"]'),
('song-ci-572','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','父老争言雨水匀。',48,'宋词/ci.song.11000.json','["父老争言雨水匀。", "眉头不似去年颦。", "殷勤谢却甑中尘。", "啼鸟有时能劝客，小桃无赖已撩人。", "梨花也作白头新。"]'),
('song-ci-573','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','这里裁诗话别离。',48,'宋词/ci.song.11000.json','["这里裁诗话别离。", "那边应是望归期。", "人言心急马行迟。", "去雁无凭传锦字，春泥抵死污人衣。", "海棠过了有荼䕷。"]'),
('song-ci-574','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','妙手都无斧凿瘢。',48,'宋词/ci.song.11000.json','["妙手都无斧凿瘢。", "饱参佳处却成颦。", "恰如春入浣花村。", "笔墨今宵光有艳，管弦从此悄无言。", "主人席次两眉轩。"]'),
('song-ci-575','添字浣溪沙・山花子','辛弃疾','宋','宋词','song-ci','添字浣溪沙・山花子','[]','句里明珠字字排。',56,'宋词/ci.song.11000.json','["句里明珠字字排。", "多情应也被春催。", "怪得名花和泪送，雨中栽。", "赤脚未安芳斛稳，娥眉早把橘枝来。", "报道锦薰笼底下，麝脐开。"]'),
('song-ci-576','添字浣溪沙・山花子','辛弃疾','宋','宋词','song-ci','添字浣溪沙・山花子','[]','记得瓢泉快活时。',56,'宋词/ci.song.11000.json','["记得瓢泉快活时。", "长年耽酒更吟诗。", "蓦地捉将来断送，老头皮。", "绕屋人扶行不得，闲窗学得鹧鸪啼。", "却有杜鹃能劝道，不如归。"]'),
('song-ci-577','添字浣溪沙・山花子','辛弃疾','宋','宋词','song-ci','添字浣溪沙・山花子','[]','日日闲看燕子飞。',56,'宋词/ci.song.11000.json','["日日闲看燕子飞。", "旧巢新垒画帘低。", "玉历今朝推戊己，住衔泥。", "先自春光留不住，那堪更著子规啼。", "一阵晚香吹不断，落花溪。"]'),
('song-ci-578','添字浣溪沙・山花子','辛弃疾','宋','宋词','song-ci','添字浣溪沙・山花子','[]','杨柳温柔是故乡。',56,'宋词/ci.song.11000.json','["杨柳温柔是故乡。", "纷纷蜂蝶去年场。", "大率一春风雨事，最难量。", "满把携来红粉面，堆盘更觉紫芝香。", "幸自曲生闲去了，又教忙。"]'),
('song-ci-579','减字木兰花','辛弃疾','宋','宋词','song-ci','减字木兰花','[]','僧窗夜雨。',52,'宋词/ci.song.11000.json','["僧窗夜雨。", "茶鼎熏炉宜小住。", "却恨春风。", "勾引诗来恼杀翁。", "狂歌未可。", "且把一尊料理我。", "我到亡何。", "却听侬家陌上歌。"]'),
('song-ci-580','减字木兰花','辛弃疾','宋','宋词','song-ci','减字木兰花','[]','昨朝官告。',52,'宋词/ci.song.11000.json','["昨朝官告。", "一百五年村父老。", "更莫惊疑。", "刚道人生七十稀。", "使君喜见。", "恰限华堂开寿宴。", "问寿如何。", "百代儿孙拥太婆。"]'),
('song-ci-581','醉太平','辛弃疾','宋','宋词','song-ci','醉太平','[]','态浓意远。',54,'宋词/ci.song.11000.json','["态浓意远。", "眉颦笑浅。", "薄罗衣窄絮风软。", "鬓云欺翠卷。", "南园花树春光暖。", "红香径里榆钱满。", "欲上秋千又惊懒。", "且归休怕晚。"]'),
('song-ci-582','太常引','辛弃疾','宋','宋词','song-ci','太常引','[]','仙机似欲织纤罗。',60,'宋词/ci.song.11000.json','["仙机似欲织纤罗。", "仿佛度金梭。", "无奈玉纤何。", "却弹作、清商恨多。", "珠帘影里，如花半面，绝胜隔帘歌。", "世路苦风波。", "且痛饮、公无度河。"]'),
('song-ci-583','太常引','辛弃疾','宋','宋词','song-ci','太常引','[]','论公耆德旧宗英。',62,'宋词/ci.song.11000.json','["论公耆德旧宗英。", "吴季子、百馀龄。", "奉使老於行。", "更看舞、听歌最精。", "须同卫武，九十入相，绿竹自青青。", "富贵出长生。", "记门外、清溪姓彭。"]'),
('song-ci-584','东坡引','辛弃疾','宋','宋词','song-ci','东坡引','[]','君如梁上燕。',70,'宋词/ci.song.11000.json','["君如梁上燕。", "妾如手中扇。", "团团青影双双伴。", "秋来肠欲断。", "黄昏泪眼。", "秋来肠欲断。", "青山隔岸。", "但咫尺、如天远。", "病来只谢傍人劝。", "龙华三会愿。", "龙华三会愿。"]'),
('song-ci-585','东坡引','辛弃疾','宋','宋词','song-ci','东坡引','[]','花梢红未足。',70,'宋词/ci.song.11000.json','["花梢红未足。", "条破惊新绿。", "重帘下遍阑干曲。", "有人春睡熟。", "有人春睡熟。", "鸣禽破梦，云偏目蹙。", "起来香腮褪红玉。", "花时爱与愁相续。", "罗裙过半幅。", "罗裙过半幅。"]'),
('song-ci-586','恋绣衾','辛弃疾','宋','宋词','song-ci','恋绣衾','[]','长夜偏冷添被儿。',68,'宋词/ci.song.11000.json','["长夜偏冷添被儿。", "枕头儿、移了又移。", "我自是笑别人底，却元来、当局者迷。", "如今只恨因缘浅，也不曾、抵死恨伊。", "合手下、安排了，那筵席、须有散时。"]'),
('song-ci-587','杏花天','辛弃疾','宋','宋词','song-ci','杏花天','[]','牡丹昨夜方开遍。',65,'宋词/ci.song.11000.json','["牡丹昨夜方开遍。", "毕竟是、今年春晚。", "荼䕷付与薰风管。", "燕子忙时莺懒。", "多病起、日长人倦。", "不待得、酒阑歌散。", "副能得见茶瓯面。", "却早安排肠断。"]'),
('song-ci-588','柳梢青','辛弃疾','宋','宋词','song-ci','柳梢青','[]','白鸟相迎，相怜相笑，满面尘埃。',63,'宋词/ci.song.11000.json','["白鸟相迎，相怜相笑，满面尘埃。", "华发苍颜，去时曾劝，闻早归来。", "而今岂是高怀。", "为千里、莼羹计哉。", "好把《移文》，从今日日，读取千回。"]'),
('song-ci-589','武陵春','辛弃疾','宋','宋词','song-ci','武陵春','[]','走去走来三百里，五日以为期。',56,'宋词/ci.song.11000.json','["走去走来三百里，五日以为期。", "六日归时已是疑。", "应是望多时。", "鞭个马儿归去也，心急马行迟。", "不免相烦喜鹊儿。", "先报那人知。"]'),
('song-ci-590','谒金门','辛弃疾','宋','宋词','song-ci','谒金门','[]','归去未。',53,'宋词/ci.song.11000.json','["归去未。", "风雨送春行李。", "一枕离愁头澈尾。", "如何消遣是。", "遥想归舟天际。", "绿鬓珑璁慵理。", "好梦未成莺唤起。", "粉香犹有殢。"]'),
('song-ci-591','酒泉子','辛弃疾','宋','宋词','song-ci','酒泉子','[]','流水无情，潮到空城头尽白，离歌一曲怨残阳。',53,'宋词/ci.song.11000.json','["流水无情，潮到空城头尽白，离歌一曲怨残阳。", "断人肠。", "东风官柳舞雕墙。", "三十六宫花溅泪，春声何处说兴亡。", "燕双双。"]'),
('song-ci-592','霜天晓角','辛弃疾','宋','宋词','song-ci','霜天晓角','[]','暮山层碧。',53,'宋词/ci.song.11000.json','["暮山层碧。", "掠岸西风急。", "一叶软红深处，应不是、利名客。", "玉人还伫立。", "绿窗生怨泣。", "万里衡阳归恨，先倩雁、寄消息。"]'),
('song-ci-593','点绛唇','辛弃疾','宋','宋词','song-ci','点绛唇','[]','隐隐轻雷，雨声不受春回护。',50,'宋词/ci.song.11000.json','["隐隐轻雷，雨声不受春回护。", "落梅如许。", "吹尽墙边去。", "春水无情，碍断溪南路。", "凭谁诉。", "寄声传语。", "没个人知处。"]'),
('song-ci-594','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','梅子褪花时，直与黄梅接。',48,'宋词/ci.song.11000.json','["梅子褪花时，直与黄梅接。", "烟雨几曾开，一春江里活。", "富贵使人忙，也有闲时节。", "莫作路旁花，长教人看杀。"]'),
('song-ci-595','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','悠悠万世功，矻矻当年苦。',48,'宋词/ci.song.11000.json','["悠悠万世功，矻矻当年苦。", "鱼自入深渊，人自居平土。", "红日又西沉，白浪长东去。", "不是望金山，我自思量禹。"]'),
('song-ci-596','昭君怨','辛弃疾','宋','宋词','song-ci','昭君怨','[]','夜雨剪残春韭。',48,'宋词/ci.song.11000.json','["夜雨剪残春韭。", "明日重斟别酒。", "君去问曹瞒。", "好公安。", "试看如今白发。", "却为中年离别。", "风雨正崔嵬。", "早归来。"]'),
('song-ci-597','一落索','辛弃疾','宋','宋词','song-ci','一落索','[]','锦帐如云处。',56,'宋词/ci.song.11000.json','["锦帐如云处。", "高不知重数。", "夜深银烛泪成行，算都把、心期付。", "莫待燕飞泥污。", "问花花诉。", "不知花定有情无，似却怕、新词妒。"]'),
('song-ci-598','如梦令','辛弃疾','宋','宋词','song-ci','如梦令','[]','燕子几曾归去。',40,'宋词/ci.song.11000.json','["燕子几曾归去。", "只在翠岩深处。", "重到画梁间，谁与旧巢为主。", "深许。", "深许。", "闻道凤凰来住。"]'),
('song-ci-599','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','一天霜月明，几处砧声起。',48,'宋词/ci.song.11000.json','["一天霜月明，几处砧声起。", "客梦已难成，秋色无边际。", "旦夕是重阳，菊有黄花蕊。", "只怕又登高，未饮心先醉。"]'),
('song-ci-600','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','老子当年，饱经惯、花期酒约。',115,'宋词/ci.song.11000.json','["老子当年，饱经惯、花期酒约。", "行乐处，轻裘缓带，绣鞍金络。", "明月楼台箫鼓夜，梨花院落秋千索。", "共何人、对饮五三锺，颜如玉。", "嗟往事，空萧索。", "怀新恨，又飘泊。", "但年来何待，许多幽独。", "海水连天凝望远，山风吹雨征衫薄。", "向此际、羸马独骎骎，情怀恶。"]'),
('song-ci-601','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','与君欲赴西楼约。',52,'宋词/ci.song.11000.json','["与君欲赴西楼约。", "西楼风急征衫薄。", "且莫上兰舟。", "怕人青泪流。", "临风横玉管。", "声散江天满。", "一夜旅中愁。", "蛩吟不忍休。"]'),
('song-ci-602','一翦梅','辛弃疾','宋','宋词','song-ci','一翦梅','[]','尘洒衣裾客路长。',72,'宋词/ci.song.11000.json','["尘洒衣裾客路长。", "霜林已晚，秋蕊犹香。", "别离触处是悲凉。", "梦里青楼，不忍思量。", "天字沈沈落日黄。", "云遮望眼，山割愁肠。", "满怀珠玉泪浪浪。", "欲倩西风，吹到兰房。"]'),
('song-ci-603','一翦梅','辛弃疾','宋','宋词','song-ci','一翦梅','[]','歌罢尊空月坠西。',72,'宋词/ci.song.11000.json','["歌罢尊空月坠西。", "百花门外，烟翠霏微。", "降纱笼烛照于飞。", "归去来兮。", "归去来兮。", "酒入香腮分外宜。", "行行问道，还肯相随。", "娇羞无力应人迟。", "何幸如之。", "何幸如之。"]'),
('song-ci-604','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','西真姊妹，料凡心忽起，共辞瑶阙。',120,'宋词/ci.song.11000.json','["西真姊妹，料凡心忽起，共辞瑶阙。", "燕燕莺莺相并比，的当两团儿雪。", "合韵歌喉，同茵舞袖，举措□□别。", "江梅影里，迥然双蕊奇绝。", "还听别院笙歌，仓皇走报，笑语浑重叠。", "拾翠洲边携手处，疑是桃根桃叶。", "并蒂芳莲，双头红药，不意俱攀折。", "今宵鸳帐，有同对影明月。"]'),
('song-ci-605','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','论心论相，便择术满眼，纷纷何物。',120,'宋词/ci.song.11000.json','["论心论相，便择术满眼，纷纷何物。", "踏碎铁鞋三百緉，不在危峰绝壁。", "龙友相逢，洼樽缓举，议论敲冰雪。", "何妨人道，圣时同见三杰。", "自是不日同舟，平戎破虏，岂由言轻发。", "任使穷通相鼓弄，恐是真□难灭。", "寄食王孙，丧家公子，谁握周公发。", "冰□皎皎，照人不下霜月。"]'),
('song-ci-606','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','妙龄秀发，湛灵台一点，天然奇绝。',120,'宋词/ci.song.11000.json','["妙龄秀发，湛灵台一点，天然奇绝。", "万壑千岩归健笔，扫尽平山风月。", "雪里疏梅，霜头寒菊，迥与馀花别。", "识人青眼，慨然怜我疏拙。", "遐想后日娥眉，两山横黛，谈笑风生颊。", "握手论文情极处，冰玉一时清洁。", "扫断尘劳，招呼萧散，满酌金蕉叶。", "醉乡深处，不知天地空阔。"]'),
('song-ci-607','江城子','辛弃疾','宋','宋词','song-ci','江城子','[]','留仙初试砑罗裙。',86,'宋词/ci.song.11000.json','["留仙初试砑罗裙。", "小腰身。", "可怜人。", "江国幽香，曾向雪中闻。", "过尽东园桃与李，还见此，一枝春。", "庾郎襟度最清真。", "挹芳尘。", "便情亲。", "南馆花深，清夜驻行云。", "拼却日高呼不起，灯半灭，酒微醺。"]'),
('song-ci-608','惜奴娇','辛弃疾','宋','宋词','song-ci','惜奴娇','[]','风骨萧然，称独立、群仙首。',93,'宋词/ci.song.11000.json','["风骨萧然，称独立、群仙首。", "春江雪、一枝梅秀。", "小样香檀，映朗玉、纤纤手。", "未久。", "转新声、泠泠山溜。", "曲里传情，更浓似、尊中酒。", "信倾盖、相逢如旧。", "别后相思，记敏政堂前柳。", "知否。", "又拼了、一场消瘦。"]'),
('song-ci-609','眼儿媚','辛弃疾','宋','宋词','song-ci','眼儿媚','[]','烟花丛里不宜他。',58,'宋词/ci.song.11000.json','["烟花丛里不宜他。", "绝似好人家。", "淡妆娇面，轻注朱唇，一朵梅花。", "相逢比著年时节，顾意又争些。", "来朝去也，莫因别个，忘了人咱。"]'),
('song-ci-610','如梦令','辛弃疾','宋','宋词','song-ci','如梦令','[]','韵胜仙风缥缈。',40,'宋词/ci.song.11000.json','["韵胜仙风缥缈。", "的皪娇波宜笑。", "串玉一声歌，占断多情风调。", "清妙。", "清妙。", "留住飞云多少。"]'),
('song-ci-611','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','翦烛西窗夜未阑。',64,'宋词/ci.song.11000.json','["翦烛西窗夜未阑。", "酒豪诗兴两联绵。", "香喷瑞兽金三尺，人插云梳玉一弯。", "倾笑语，捷飞泉。", "觥筹到手莫留连。", "明朝再作东阳约，肯把鸾胶续断弦。"]'),
('song-ci-612','踏莎行','辛弃疾','宋','宋词','song-ci','踏莎行','[]','萱草齐阶，芭蕉弄叶。',68,'宋词/ci.song.11000.json','["萱草齐阶，芭蕉弄叶。", "乱红点点团香蝶。", "过墙一阵海棠风，隔帘几处梨花雪。", "愁满芳心，酒潮红颊。", "年年此际伤离别。", "不妨横管小楼中，夜阑吹断千山月。"]'),
('song-ci-613','□□□','辛弃疾','宋','宋词','song-ci','□□□','[]','莺未老。',55,'宋词/ci.song.11000.json','["莺未老。", "花谢东风扫。", "秋千人倦彩绳闲，又被清明过了。", "日长减破夜长眠，别听笙箫吹晓。", "锦笺封与怨春诗，寄与归云缥缈。"]'),
('song-ci-614','谒金门','辛弃疾','宋','宋词','song-ci','谒金门','[]','山共水。',53,'宋词/ci.song.11000.json','["山共水。", "美满一千馀里。", "不避晓行并早起。", "此情都为你。", "不怕与人尤殢。", "只怕被人调戏。", "因甚无个阿鹊地。", "没工夫说里。"]'),
('song-ci-615','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','春动酒旗风，野店芳醪留客。',53,'宋词/ci.song.11000.json','["春动酒旗风，野店芳醪留客。", "系马水边幽寺，有梨花如雪。", "山僧欲看醉魂醒，茗碗泛香白。", "微记碧苔归路，袅一鞭春色。"]'),
('song-ci-616','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','花月赏心天，抬举多情诗客。',53,'宋词/ci.song.11000.json','["花月赏心天，抬举多情诗客。", "取次锦袍须贳，爱春醅浮雪。", "黄鹂何处故飞来，点破野雪白。", "一点暗红犹在，正不禁风色。"]'),
('song-ci-617','好事近','辛弃疾','宋','宋词','song-ci','好事近','["\u897f\u6e56"]','春意满西湖，湖上柳黄时节。',53,'宋词/ci.song.11000.json','["春意满西湖，湖上柳黄时节。", "濒水雾窗云户，贮楚宫人物。", "一年管领好花枝，东风共披拂。", "已约醉骑双凰，玩三山风月。"]'),
('song-ci-618','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','客子久不到，好景为君留。',114,'宋词/ci.song.11000.json','["客子久不到，好景为君留。", "西楼著意吟赏，何必问更筹。", "唤起一天明月，照我满怀冰雪，浩荡百川流。", "鲸饮未吞海，剑气已横秋。", "野光浮。", "天宇迥，物华幽。", "中州遗恨，不知今夜几人愁。", "谁念英雄老矣，不道功名蕞尔，决策尚悠悠。", "此事费分说，来日且扶头。"]'),
('song-ci-619','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','["\u6cf0\u5c71"]','泰岳倚空碧，汶□卷云寒。',114,'宋词/ci.song.11000.json','["泰岳倚空碧，汶□卷云寒。", "萃兹山水奇秀，列宿下人寰。", "八世家传素业，一举手攀丹桂，依约笑谈间。", "宾幕佐储副，和气满长安。", "分虎符，来近甸，自金銮。", "政平讼简无事，酒社与诗坛。", "会看沙堤归去，应使神京再复，款曲问家山。", "玉佩揖空阔，碧雾翳苍鸾。"]'),
('song-ci-620','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','世路风波恶。',142,'宋词/ci.song.11000.json','["世路风波恶。", "喜清时、边夫袖手，□将帷幄。", "正值春光二三月，两两燕穿帘幕。", "又怕个、江南花落。", "与客携壶连夜饮，任蟾光、飞上阑干角。", "何时唱，从军乐。", "归欤已赋居岩壑。", "悟人世、正类春蚕，自相缠缚。", "眼畔昏鸦千万点，□欠归来野鹤。", "都不恋、黑头黄阁。", "一咏一觞成底事，庆康宁、天赋何须药。", "金盏大，为君酌。"]'),
('song-ci-621','渔家傲','辛弃疾','宋','宋词','song-ci','渔家傲','[]','风月小斋模画舫。',72,'宋词/ci.song.11000.json','["风月小斋模画舫。", "绿窗朱户江湖样。", "酒是短桡歌是桨。", "和情放。", "醉乡稳到无风浪。", "自有拍浮千斛酿。", "从教日日蒲桃涨。", "门外独醒人也访。", "同俯仰。", "赏心却在鸱夷上。"]'),
('song-ci-622','霜天晓角','辛弃疾','宋','宋词','song-ci','霜天晓角','[]','雪堂迁客。',53,'宋词/ci.song.11000.json','["雪堂迁客。", "不得文章力。", "赋写曹刘兴废，千古事、泯陈迹。", "望中矶岸赤。", "直下江涛白。", "半夜一声长啸，悲天地、为予窄。"]'),
('song-ci-623','苏武慢','辛弃疾','宋','宋词','song-ci','苏武慢','[]','帐暖金丝，杯乾云液，战退夜□飂𩘟。',138,'宋词/ci.song.11000.json','["帐暖金丝，杯乾云液，战退夜□飂𩘟。", "障泥系马，扫路迎宾，先借落花春色。", "歌竹传觞，探梅得句，人在玉楼琼室。", "唤吴姬学舞，风流轻转，弄娇无力。", "尘世换、老尽青山，铺成明月，瑞物已深三尺。", "丰登意绪，婉娩光阴，都作暮寒堆积。", "回首驱羊旧节，入蔡奇兵，等闲陈迹。", "总无如现在，尊前一笑，坐中赢得。"]'),
('song-ci-624','绿头鸭・多丽','辛弃疾','宋','宋词','song-ci','绿头鸭・多丽','[]','叹飘零。',173,'宋词/ci.song.11000.json','["叹飘零。", "离多会少堪惊。", "又争如、天人有信，不同浮世难凭。", "占秋初、桂花散采，向夜久、银汉无声。", "凤驾催云，红帷卷月，泠泠一水会双星。", "素杼冷，临风休织，深诉隔年诚。", "飞光浅，青童语款，丹鹊桥平。", "看人间、争求新巧，纷纷女伴欢迎。", "避灯时、彩丝未整，拜月处、蛛网先成。", "谁念监州，萧条官舍，烛摇秋扇坐中庭。", "笑此夕、金钗无据，遗恨满蓬瀛。", "欹高枕，梧桐听雨，如是天明。"]'),
('song-ci-625','乌夜啼','辛弃疾','宋','宋词','song-ci','乌夜啼','[]','江头三月清明。',45,'宋词/ci.song.11000.json','["江头三月清明。", "柳风轻。", "巴峡谁知还是、洛阳城。", "春寂寂。", "娇滴滴。", "笑盈盈。", "一段乌丝阑上、记多情。"]'),
('song-ci-626','品令','辛弃疾','宋','宋词','song-ci','品令','[]','迢迢征路。',80,'宋词/ci.song.11000.json','["迢迢征路。", "又小舸、金陵去。", "西风黄叶，淡烟衰草，平沙将暮。", "回首高城，一步远如一步。", "江边朱户。", "忍追忆、分携处。", "今宵山馆，怎生禁得，许多愁绪。", "辛苦罗巾，搵取几行泪雨。"]'),
('song-ci-627','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','医者索酬劳，那得许多钱物。',53,'宋词/ci.song.11000.json','["医者索酬劳，那得许多钱物。", "只有一个整整，也盒盘盛得。", "下官歌舞转凄惶，剩得几枝笛。", "觑著这般火色，告妈妈将息。"]'),
('song-ci-628','金菊对芙蓉','辛弃疾','宋','宋词','song-ci','金菊对芙蓉','[]','远水生光，遥山耸翠，霁烟深锁梧桐。',120,'宋词/ci.song.11000.json','["远水生光，遥山耸翠，霁烟深锁梧桐。", "正零瀼玉露，淡荡金风。", "东篱菊有黄花吐，对映水、几簇芙蓉。", "重阳佳致，可堪此景，酒酽花浓。", "追念景物无穷。", "叹少年胸襟，忒煞英雄。", "把黄英红萼，甚物堪同。", "除非腰佩黄金印，座中拥、红粉娇容。", "此时方称情怀，尽拼一饮千锺。"]'),
('song-ci-629','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','瑞气笼清晓。',142,'宋词/ci.song.11000.json','["瑞气笼清晓。", "卷珠帘、次第笙歌，一时齐奏。", "无限神仙离蓬岛。", "凤驾鸾车初到。", "见拥个、仙娥窈窕。", "玉佩玎裆风缥缈。", "望娇姿、一似垂杨袅。", "天上有，世间少。", "刘郎正是当年少。", "更那堪、天教付与，最多才貌。", "玉树琼枝相映耀。", "谁与安排忒好。", "有多少、风流欢笑。", "直待来春成名了。", "马如龙、绿绶欺芳草。", "同富贵，又偕老。"]'),
('song-ci-630','好事近','辛弃疾','宋','宋词','song-ci','好事近','["\u897f\u6e56"]','日日过西湖，冷浸一天寒玉。',53,'宋词/ci.song.11000.json','["日日过西湖，冷浸一天寒玉。", "山色虽言如画，想画时难邈。", "前弦后管夹歌锺，才断又重续。", "相次藕花开也，几兰舟飞逐。"]'),
('song-ci-631','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','百花头上开，冰雪寒中见。',48,'宋词/ci.song.11000.json','["百花头上开，冰雪寒中见。", "霜月定相知，先识春风面。", "主人情意深，不管江妃怨。", "折我最繁枝，还许冰壶荐。"]'),
('song-ci-632','传言玉女','赵善扛','宋','宋词','song-ci','传言玉女','[]','璧月珠星，辉映小桃秾李。',89,'宋词/ci.song.11000.json','["璧月珠星，辉映小桃秾李。", "化工容易，与人间富贵。", "东风巷陌，春在暖红温翠。", "人来人去，笑歌声里。", "油壁青骢，第一番共燕喜。", "举头天上，有如人意。", "歌传乐府，犹是升平风味。", "明朝须判，醉眠花底。"]'),
('song-ci-633','好事近','赵善扛','宋','宋词','song-ci','好事近','[]','风动一川花，摇漾影迷红碧。',53,'宋词/ci.song.11000.json','["风动一川花，摇漾影迷红碧。", "人立杏花阴下，泛光风袭袭。", "琼枝碧月互相辉，春容泫将夕。", "罗盖暗承花雾，渍鲛绡香湿。"]'),
('song-ci-634','重叠金・菩萨蛮','赵善扛','宋','宋词','song-ci','重叠金・菩萨蛮','[]','楚宫杨柳依依碧。',52,'宋词/ci.song.11000.json','["楚宫杨柳依依碧。", "遥山翠隐横波溢。", "绝艳照秾春。", "春光欲醉人。", "纤纤芳草嫩。", "微步轻罗衬。", "花戴满头归。", "游蜂花上飞。"]'),
('song-ci-635','重叠金・菩萨蛮','赵善扛','宋','宋词','song-ci','重叠金・菩萨蛮','[]','玉关芳草黏天碧。',52,'宋词/ci.song.11000.json','["玉关芳草黏天碧。", "春风万里思行客。", "骑马向风嘶。", "道归犹未归。", "南云新有雁。", "望眼愁边断。", "膏沐为谁容。", "倚楼烟雨中。"]'),
('song-ci-636','重叠金・菩萨蛮','赵善扛','宋','宋词','song-ci','重叠金・菩萨蛮','[]','一川花月青春夜。',52,'宋词/ci.song.11000.json','["一川花月青春夜。", "玉容依约花阴下。", "月照曲阑干。", "红绡挹露寒。", "袖香温素手。", "意铄金卮酒。", "香远绣帘开。", "画楼吹落梅。"]'),
('song-ci-637','十拍子・破阵子','赵善扛','宋','宋词','song-ci','十拍子・破阵子','[]','柳絮飞时绿暗，荼䕷开后春酣。',72,'宋词/ci.song.11000.json','["柳絮飞时绿暗，荼䕷开后春酣。", "花外青帘迷酒思，陌上晴光收翠岚。", "佳辰三月三。", "解珮人逢游女，踏青草斗宜男。", "醉倚画阑阑槛北，梦绕清江江水南。", "飞鸾与共骖。"]'),
('song-ci-638','青玉案','赵善扛','宋','宋词','song-ci','青玉案','[]','一年陌上寻芳意。',80,'宋词/ci.song.11000.json','["一年陌上寻芳意。", "想人在、东风里。", "褪粉销红春有几。", "青翰飞去，紫云凝伫，往事如流水。", "烟横极浦山无际。", "暗解明珰问谁寄。", "乡在温柔何处是。", "轮囷香雾，静深庭院，帘影参差翠。"]'),
('song-ci-639','烛影摇红','赵善扛','宋','宋词','song-ci','烛影摇红','[]','桃李墙头，向人都似他年意。',116,'宋词/ci.song.11000.json','["桃李墙头，向人都似他年意。", "舞丝千丈颺晴光，骀青春无际。", "花气薰人自醉。", "傍垂杨、行行缓辔。", "倦游无奈，回首云山，归期犹未。", "玉锁楼空，鸟啼花外东风起。", "少年恩怨付波流，吟望朱阑倚。", "冉冉尘生客袂。", "对尊前、高情暂寄。", "洞天一笑，仙驭乘空，姑峰凝翠。"]'),
('song-ci-640','谒金门','赵善扛','宋','宋词','song-ci','谒金门','[]','新雨霁。',53,'宋词/ci.song.11000.json','["新雨霁。", "开遍满园桃李。", "波暖池塘风细细。", "一双花鸭戏。", "唤起春融睡美。", "扶醉宿妆慵理。", "移步避入花影里。", "绣裙低窣地。"]'),
('song-ci-641','宴清都','赵善扛','宋','宋词','song-ci','宴清都','[]','疏柳无情绪。',126,'宋词/ci.song.11000.json','["疏柳无情绪。", "都不管、渡头行客欲去。", "犹依赖得，玉光万顷，为人留住。", "相从岁月如骛，叹回首、离歌又赋。", "更举目、斜照沈沈，西风剪剪秋墅。", "君行定忆南池，歌筵舞地，花晨月午。", "八砖步日，三雍奏乐，送君云路。", "别情未抵遗爱，试听取、湖山共语。", "便可能、无意同倾，一尊露醑。"]'),
('song-ci-642','小重山','赵善扛','宋','宋词','song-ci','小重山','[]','汲水添瓶恰换花。',70,'宋词/ci.song.11000.json','["汲水添瓶恰换花。", "蜂儿争要采，打窗纱。", "青春谁与度年花。", "弦索暗，无绪几曾拿。", "春思正交加。", "马蹄声错认，客还家。", "花笺欲写寄天涯。", "羞人见，罗袖急忙遮。"]'),
('song-ci-643','感皇恩','赵善扛','宋','宋词','song-ci','感皇恩','[]','七十古来稀，吾生已半。',81,'宋词/ci.song.11000.json','["七十古来稀，吾生已半。", "莫把身心自萦绊。", "据他缘分，且恁随时消遣。", "但知逢酒饮，逢花看。", "林泉有约，风光无限。", "日上花梢起来晚。", "芒鞋竹杖，信步水村山馆。", "更寻三两个，清闲伴。"]'),
('song-ci-644','贺新郎','赵善扛','宋','宋词','song-ci','贺新郎','[]','昼永重帘卷。',141,'宋词/ci.song.11000.json','["昼永重帘卷。", "乍池塘、一番过雨，芰荷初展。", "竹引新梢半含粉，绿荫扶疏满院。", "过花絮、蝶稀蜂懒。", "窗户沈沈人不到，伴清幽、时有流莺啭。", "凝思久，意何限。", "玉钗坠枕风鬟颤。", "湛虚堂、壶冰莹彻，簟波零乱。", "自是仙姿清无暑，月影空垂素扇。", "破午睡、香销馀篆。", "一枕湖山千里梦，正白苹烟棹归来晚。", "云弄碧，楚天远。"]'),
('song-ci-645','喜迁莺','赵善扛','宋','宋词','song-ci','喜迁莺','[]','韶华骀荡。',126,'宋词/ci.song.11000.json','["韶华骀荡。", "看化工尽力，安排春仗。", "薄雾霏烟，软风轻日，物态与人交畅。", "鸟生弄巧千调，楼影垂空十丈。", "乱花柳，粲宝钿缨络、采丝帷帐。", "佳赏。", "辉艳冶，笑语盈盈，花面交相向。", "歌运长缫，酒凝深碧，和气盎然席上。", "好春易苦风雨，人意难逢舒放。", "但拍掌。", "醉陶然一笑，忘形天壤。"]'),
('song-ci-646','菩萨蛮','赵善括','宋','宋词','song-ci','菩萨蛮','[]','烟波江上西亭小。',52,'宋词/ci.song.11000.json','["烟波江上西亭小。", "晓来雨过惊秋早。", "飞栋倚晴空。", "凉生面面风。", "痴儿官事了。", "独自凭栏笑。", "何处有尘埃。", "扁舟归去来。"]'),
('song-ci-647','柳梢青','赵善括','宋','宋词','song-ci','柳梢青','[]','愁别欣逢。',61,'宋词/ci.song.11000.json','["愁别欣逢。", "人间离合，自古难同。", "写就茶经，注成花谱，何事西东。", "一尊良夜匆匆。", "怎忍见、轻帆短篷。", "汉水无情，楚云有意，目断飞鸿。"]'),
('song-ci-648','鹧鸪天','赵善括','宋','宋词','song-ci','鹧鸪天','[]','忆昔南楼旧使君。',64,'宋词/ci.song.11000.json','["忆昔南楼旧使君。", "与君携手蹑浮云。", "如今更到经行处，妙墨新诗得屡闻。", "淮南路，楚江分。", "离尊相属更论文。", "明朝一棹人千里，多少红愁与翠颦。"]'),
('song-ci-649','鹧鸪天','赵善括','宋','宋词','song-ci','鹧鸪天','[]','我是行人更送行。',64,'宋词/ci.song.11000.json','["我是行人更送行。", "潇潇风雨倍伤情。", "征帆西去何须急，飞诏东来分外荣。", "红袖湿，玉尊倾。", "不堪回首暮云平。", "小舟准拟随君去，要听霜天晓角声。"]'),
('song-ci-650','鹧鸪天','赵善括','宋','宋词','song-ci','鹧鸪天','[]','雨沐芙蓉秋意清。',64,'宋词/ci.song.11000.json','["雨沐芙蓉秋意清。", "可人风月满江城。", "怜风爱月方留恋，对月临风又送行。", "人渐远，酒须倾。", "只凭一醉遣多情。", "重来休厌刘郎老，明月清风有素盟。"]'),
('song-ci-651','沁园春','赵善括','宋','宋词','song-ci','沁园春','[]','虎啸风生，龙跃云飞，时不再来。',139,'宋词/ci.song.11000.json','["虎啸风生，龙跃云飞，时不再来。", "试凭高望远，长淮清浅，伤今怀古，故国氛埃。", "壮志求伸，匈奴未灭，早以家为何谓哉。", "多应是，待著鞭事了，税驾方回。", "稼轩聊尔名斋。", "笑学请樊迟心未开。", "似南阳高卧，莘郊自乐，磻溪韬略，傅野盐梅。", "植杖亭前，集山楼下，五桂三槐次第栽。", "功名遂，向急流勇退，肯恁徘徊。"]'),
('song-ci-652','沁园春','赵善括','宋','宋词','song-ci','沁园春','[]','问舍东湖，招隐西山，惠然肯来。',139,'宋词/ci.song.11000.json','["问舍东湖，招隐西山，惠然肯来。", "有閟香兰桂，无穷幽趣，隔溪车马，何处轻埃。", "微利虚名，朝荣暮辱，笑尔焉能浼我哉。", "闲欹枕，被幽禽唤觉，午梦惊回。", "无言独坐南斋。", "好唤取芳尊相对开。", "待醒时重醉，疏帘透月，醉时还醒，画角吹梅。", "无用千金，休悬六印，荆棘谁能满地栽。", "人间世，任游鵾独运，斥鷃低徊。"]'),
('song-ci-653','沁园春','赵善括','宋','宋词','song-ci','沁园春','[]','千里风湍，万叠云峰，自相送迎。',140,'宋词/ci.song.11000.json','["千里风湍，万叠云峰，自相送迎。", "叹扁舟如叶，漂流如梗，片帆如箭，聚散如萍。", "家在东湖，身来西浙，非为区区利与名。", "堪怜处，为雏饥犊暮，狗苟蝇营。", "平生。", "何辱何荣。", "且一任三才和五行。", "有鷃飞鹏奋，鹤长凫短，朱颜富贵，白发公卿。", "印漫累累，绶何若若，休羡行歌朱买臣。", "归来好，向严滩垂钓，谷口躬耕。"]'),
('song-ci-654','满江红','赵善括','宋','宋词','song-ci','满江红','[]','一雨连春，东湖涨、蒲萄新绿。',114,'宋词/ci.song.11000.json','["一雨连春，东湖涨、蒲萄新绿。", "湖上路，柳浓花艳，绿园红簇。", "尘世难逢开口笑，人生待足何时足。", "况南州高士是西邻，人如玉。", "行路唱，谁家曲。", "愁易感，欢难续。", "问轩裳於我，有何荣辱。", "众醉岂容君独醒，出林休恨风催木。", "叹惊弦、飞鸟尚知还，安巢宿。"]'),
('song-ci-655','满江红','赵善括','宋','宋词','song-ci','满江红','[]','三十年前，曾向此、舞风歌月。',115,'宋词/ci.song.11000.json','["三十年前，曾向此、舞风歌月。", "今依旧、江山如画，鬓须如雪。", "故友冥鸿随净社，旧时秋蚓横尘壁。", "赖庐峰、对我眼偏青，曾相识。", "开岫幌，携山屐。", "泉泻布，星飞石。", "为收帆舣棹，小留终日。", "休问重湖吹碧浪，且同五老浮琼液。", "待明朝、鹢首向东飞，清风力。"]'),
('song-ci-656','满江红','赵善括','宋','宋词','song-ci','满江红','[]','腾茂飞英，分忧愿、自然风力。',115,'宋词/ci.song.11000.json','["腾茂飞英，分忧愿、自然风力。", "千里静，江山改观，羽旄增色。", "林下风清公事少，笔端雷动奸豪息。", "听宴香、深处笑声长，文章客。", "丹诏自，天边得。", "宣室对，君心忆。", "趁良辰高会，履珠簪碧。", "和气回春徵酝酿，政声报最惟清白。", "看挥毫、万字扫云烟，吴笺湿。"]'),
('song-ci-657','鹧鸪天','赵善括','宋','宋词','song-ci','鹧鸪天','[]','画鹢翩翩去似飞。',64,'宋词/ci.song.11000.json','["画鹢翩翩去似飞。", "季鹰何事忽思归。", "风湍自送征帆隐，云巘须将彩笔挥。", "江作酒，海为卮。", "为君满酌不须辞。", "酒酣渴思回春梦，自笑何时是足时。"]'),
('song-ci-658','念奴娇','赵善括','宋','宋词','song-ci','念奴娇','[]','扬辉璧月，照层台缥缈，篷莱云气。',120,'宋词/ci.song.11000.json','["扬辉璧月，照层台缥缈，篷莱云气。", "玉宇清明仙语近，多少怨红愁翠。", "问我殷勤，几年尘土，依旧高标致。", "广寒别后，与谁曾共幽会。", "一日失脚人间，十常八九，底事如人意。", "狗苟蝇营真可笑，何乃比余於是。", "风月佳时，江山好处，无复怀愁悴。", "倚栏舒啸，六经时自心醉。"]'),
('song-ci-659','醉落魄・一斛珠','赵善括','宋','宋词','song-ci','醉落魄・一斛珠','[]','重阳时节。',67,'宋词/ci.song.11000.json','["重阳时节。", "可怜又是天崖客。", "扁舟小泊花溪侧。", "细雨斜风，不见秦楼月。", "白衣望断无消息。", "举觞一笑真难得。", "归兮学取陶彭泽。", "采菊东篱，悠然见山色。"]'),
('song-ci-660','摸鱼儿','赵善括','宋','宋词','song-ci','摸鱼儿','[]','喜连宵、四郊春雨。',140,'宋词/ci.song.11000.json','["喜连宵、四郊春雨。", "纷纷一阵红去。", "东君不爱闲桃李，春色尚馀分数。", "云影住。", "任绣勒香轮，且阻寻芳路。", "农家相语。", "渐南亩浮青，西江涨绿，芳沼点萍絮。", "西成事，端的今年不误。", "从他蝶恨蜂妒。", "莺啼也怨春多雨，不解与春分诉。", "新燕舞。", "犹记得、雕梁旧日空巢土。", "天涯劳苦。", "望故国江山，东风吹泪，渺渺在何处。"]'),
('song-ci-661','摸鱼儿','赵善括','宋','宋词','song-ci','摸鱼儿','[]','被杨花、带将春去，飘扬一路无定。',140,'宋词/ci.song.11000.json','["被杨花、带将春去，飘扬一路无定。", "满庭绿荫丝千尺，枝上旧香吹尽。", "幽梦醒。", "对晚色、秋千院落人初静。", "柔条弄影。", "奈翦翦轻风，冥冥细雨，惹起万千恨。", "云山路，休蹑高楼独凭。", "楚天一抹烟暝。", "娇莺百啭飞鸠去，何处可寻芳信。", "心自省。", "念咫尺、青楼应怪人薄幸。", "归期将近。", "料喜鹊先知，飞来报了，日日倚门等。"]'),
('song-ci-662','虞美人','赵善括','宋','宋词','song-ci','虞美人','[]','长空一夜霜风吼。',66,'宋词/ci.song.11000.json','["长空一夜霜风吼。", "寒色消残酒。", "问伊今夜在谁行。", "遗恨落花流水、误刘郎。", "尤云殢雨多情话。", "分付阿谁也。", "侬家有分受凄惶。", "只怕娇痴不睡、也思量。"]'),
('song-ci-663','好事近','赵善括','宋','宋词','song-ci','好事近','[]','月色透窗寒，一夜素衾霜湿。',53,'宋词/ci.song.11000.json','["月色透窗寒，一夜素衾霜湿。", "无寐起来搔首，正参横人寂。", "此心重省已回肠，何况是行役。", "欲弃利名归去，奈楚天云隔。"]'),
('song-ci-664','鹧鸪天','赵善括','宋','宋词','song-ci','鹧鸪天','[]','枉道黉堂是冷官。',64,'宋词/ci.song.11000.json','["枉道黉堂是冷官。", "深深青琐锁青鸾。", "新诗自得清歌举，和气都消永夜寒。", "花态净，酒杯宽。", "燕娇莺巧有馀欢。", "不因客里东阳瘦，好把西江一吸乾。"]'),
('song-ci-665','满江红','赵善括','宋','宋词','song-ci','满江红','[]','传语风光，须少驻、共君流转。',115,'宋词/ci.song.11000.json','["传语风光，须少驻、共君流转。", "谁忍见、绿肥红瘦，鲜欢多感。", "泽国千丝烟雨暗，江成一带云山远。", "看新荷、泛水学人愁，心常卷。", "羞鬓雪，凭花染。", "携酒阵，嫌杯浅。", "叹人生岂为，青衫槐板。", "记舞可怜宫柳细，写情但觉香笺短。", "上层楼、独倚有谁知，栏干暖。"]'),
('song-ci-666','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','[]','山险号北固，景胜冠南州。',114,'宋词/ci.song.11000.json','["山险号北固，景胜冠南州。", "洪涛江上乱云，山里簇红楼。", "堪笑萍踪无定，拟泊叶舟何许，无计可依刘。", "金阙自帷幄，玉垒老貔貅。", "问兴亡，成底事，几春秋。", "六朝人物，五胡妖雾不胜愁。", "休学楚囚垂泪，须把祖鞭先著，一鼓版图收。", "惟有金焦石，不逐水漂流。"]'),
('song-ci-667','好事近','赵善括','宋','宋词','song-ci','好事近','[]','风雨做春愁，桃杏一时零落。',53,'宋词/ci.song.11000.json','["风雨做春愁，桃杏一时零落。", "是处绿肥红瘦，怨东君情薄。", "行藏独倚望江楼，双燕度帘幕。", "回首故园应在，误秋千人约。"]'),
('song-ci-668','鹧鸪天','赵善括','宋','宋词','song-ci','鹧鸪天','[]','玉殿分荣两桂华。',64,'宋词/ci.song.11000.json','["玉殿分荣两桂华。", "灵根移植在长沙。", "风姨先绽无双蕊，月姊重开第一花。", "金榜烂，玉音加。", "从今稳步上天霞。", "休夸水击三千里，且歌笙歌十万家。"]'),
('song-ci-669','醉落魄・一斛珠','赵善括','宋','宋词','song-ci','醉落魄・一斛珠','[]','梯横画阁。',67,'宋词/ci.song.11000.json','["梯横画阁。", "碧栏干外江风恶。", "笑声欢意浮杯酌。", "秋水春山，相对称行乐。", "谁家青鸟穿帘幕。", "暗传空有阳台约。", "天公著意称停著。", "寒色人情，都恁两清薄。"]'),
('song-ci-670','醉落魄・一斛珠','赵善括','宋','宋词','song-ci','醉落魄・一斛珠','[]','梯横画阁。',67,'宋词/ci.song.11000.json','["梯横画阁。", "月明江静烟光薄。", "碧山回绕栏干角。", "一缕行云，忽向杯中落。", "樱歌柳舞俱柔弱。", "罗衣不耐江风恶。", "凭谁唤取双黄鹤。", "骑上瑶台，同赴金桃约。"]'),
('song-ci-671','朝中措','赵善括','宋','宋词','song-ci','朝中措','[]','东君著意在枝头。',57,'宋词/ci.song.11000.json','["东君著意在枝头。", "红紫自风流。", "贪引游蜂舞蝶，几多春事都休。", "三分好处，不随流水，即是闲愁。", "惟我惜花心在，更看红叶沈浮。"]'),
('song-ci-672','菩萨蛮','赵善括','宋','宋词','song-ci','菩萨蛮','[]','鹊桥巧雾随风远。',52,'宋词/ci.song.11000.json','["鹊桥巧雾随风远。", "蟾宫皓影凝空满。", "一点寿星明。", "祥光彻太清。", "周公天子传。", "礼乐新封鲁。", "功业焕旗常。", "钧天侍玉皇。"]'),
('song-ci-673','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','形胜视京兆，警跸驻钱塘。',114,'宋词/ci.song.11000.json','["形胜视京兆，警跸驻钱塘。", "光前诏后弹压，谁数汉张王。", "几百万家和气，五十馀年创见，天下一循良。", "有口皆歌颂，无地不耕桑。", "春过半，花锦烂，柳丝长。", "潭潭门卫森戟，宴寝正凝香。", "笑把湖山佳色，醉挹西湖晴滟，童艾祝霞觞。", "四海瞻华衮，千载侍吾皇。"]'),
('song-ci-674','满江红','赵善括','宋','宋词','song-ci','满江红','[]','海岳储祥，符昌运、挺生前哲。',115,'宋词/ci.song.11000.json','["海岳储祥，符昌运、挺生前哲。", "天赋与、飘然才气，凛然忠节。", "颖脱难藏冲斗剑，誓清行击中流楫。", "二十年、麾节遍江湖，恩威浃。", "香穗直，云峰列。", "觞羽急，鲸川竭。", "共介公眉寿，赞公贤业。", "出处已能齐二老，功名岂止超三杰。", "侍吾皇、千载带金重，头方黑。"]'),
('song-ci-675','醉蓬莱','赵善括','宋','宋词','song-ci','醉蓬莱','[]','正采铃坠盖，玉燕投怀，梦符佳月。',120,'宋词/ci.song.11000.json','["正采铃坠盖，玉燕投怀，梦符佳月。", "五百年间，诞中兴人杰。", "杖策归来，入关徒步，万里朝金阙。", "贯日精忠，凌云壮气，妙龄英发。", "名镇重湖，屡凭熊轼，恩满西江，载分龙节。", "有志澄清，誓击中流楫。", "谈笑封侯，雍容谋国，看掀天功业。", "待与斯民，庆公华衮，祝公黄发。"]'),
('song-ci-676','醉蓬莱','赵善括','宋','宋词','song-ci','醉蓬莱','[]','正百花堂下，山雨楼前，粲然梅柳。',120,'宋词/ci.song.11000.json','["正百花堂下，山雨楼前，粲然梅柳。", "和气回春，滟一尊芳酒。", "桂子兰孙，凤歌鸾舞，介我公眉寿。", "天上遐龄，人间独乐，古来稀有。", "壮日题桥，儿时击瓮，名遂功成，自然长久。", "琳馆偷闲，约赤城为友。", "紫诏重颁，黄扉稳步，好试调羹手。", "九世鸡窠，千秋麟阁，玉颜依旧。"]'),
('song-ci-677','醉蓬莱','赵善括','宋','宋词','song-ci','醉蓬莱','["\u592a\u6e56"]','正槐堂日永，梅雨消尘，麦风摇翠。',120,'宋词/ci.song.11000.json','["正槐堂日永，梅雨消尘，麦风摇翠。", "天祐昌辰，诞中兴嘉瑞。", "秀伟标姿，从容谋断，笑吐平戎计。", "汉节归来，边尘扫净，鼎司荣贵。", "间世良臣，威严辅政，妩媚承君，道襟冲粹。", "玉券金丹，称功名成遂。", "茂苑烟霞，太湖风月，聊伴凝香醉。", "补衮工夫，调羹手段，如今重试。"]'),
('song-ci-678','瑞鹤仙','赵善括','宋','宋词','song-ci','瑞鹤仙','[]','月华凝露掌。',127,'宋词/ci.song.11000.json','["月华凝露掌。", "正极目鸾霄，望风鲸壤。", "深宫注遐想。", "听点点花漏，盈盈仙仗。", "笙箫迎响。", "降琼轮、玄云步障。", "洞□扉、笑别蓬瀛，下应太平无象。", "俱仰。", "姆仪春煦，妇节冰清，道风夷旷。", "三迁教养。", "金阙里，玉音赏。", "况传家清白，满堂朱紫，相对兰荪竞长。", "待齐秦、汤沐疏封，赐灵寿杖。"]'),
('song-ci-679','鹊桥仙','赵善括','宋','宋词','song-ci','鹊桥仙','[]','星桥未就，月钩初挂，翠叶暗惊秋早。',68,'宋词/ci.song.11000.json','["星桥未就，月钩初挂，翠叶暗惊秋早。", "蕊珠宫里厌清闲，试回首、尘寰一笑。", "仙风道骨，姆仪家范，须信人间最少。", "一枝丹桂四兰荪，况千岁、灵椿未老。"]'),
('song-ci-680','贺新郎','赵善括','宋','宋词','song-ci','贺新郎','[]','绛雪堆云绿。',141,'宋词/ci.song.11000.json','["绛雪堆云绿。", "倚朱栏、鸾飞凤舞，乱红如簇。", "宫锦海沈肌理秀，极目明霞孤骛。", "对翠袖、天寒修竹。", "轻露有情添泪眼，粲精神、娇醉薰华屋。", "然宝篆，散清馥。", "江南到处多兰菊。", "更海棠、贪睡未醒，漫山粗俗。", "欲品此花为第一，真色生香俱足。", "又只怕、惊人凡目。", "把酒对花频管领，怕狂风骤雨难拘束。", "拾碎玉，泛醽醁。"]'),
('song-ci-681','霜天晓角','赵善括','宋','宋词','song-ci','霜天晓角','[]','楚天风色。',53,'宋词/ci.song.11000.json','["楚天风色。", "一夜波翻雪。", "舣岸锦帆不度，天有意、且留客。", "鼓声吹取急。", "离觞须举白。", "看去芳菲时候，日边听、好消息。"]'),
('song-ci-682','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','[]','碧云初返岫，潦水正鸣滩。',114,'宋词/ci.song.11000.json','["碧云初返岫，潦水正鸣滩。", "兰舟容与，歌舞偏称笑中看。", "烛影烘寒成暖，花色照人如画，一坐有馀欢。", "酒滟浮金盏，香缕霭雕盘。", "碧簪横，银漏永，玉樽乾。", "喧春鼓吹，翠袖起舞佩珊珊。", "记得山明水秀，何处朝云暮雨，常在梦魂间。", "多少难言事，都付两眉弯。"]'),
('song-ci-683','念奴娇','赵善括','宋','宋词','song-ci','念奴娇','[]','晓来膏雨，报一犁丰信，几枝娇色。',120,'宋词/ci.song.11000.json','["晓来膏雨，报一犁丰信，几枝娇色。", "岸草河沙明似镜，不到尘埃花陌。", "急管繁弦，香车宝勒，正阻寻春客。", "东风特起，半空微露晴碧。", "何况主意深勤，冰清才藻，玉润真圭璧。", "翠丽华堂横枕水，波底斜阳红湿。", "莲社风流，桃溪标致，便觉凡心息。", "玉尊倾尽，笑中归步钩月。"]'),
('song-ci-684','念奴娇','赵善括','宋','宋词','song-ci','念奴娇','[]','江南到处，被波光云影，留人行色。',120,'宋词/ci.song.11000.json','["江南到处，被波光云影，留人行色。", "昔我来时春正好，舞絮□飞南陌。", "今日登临，读书斋上，重作凭栏客。", "清溪毂细，夜来微涨新碧。", "两岸蘸水浓阴，断虹横障，一带连环璧。", "林外青山千万叠，雨歇半空犹湿。", "已倩双鳞，更须灵鹊，先报归消息。", "归来征袖，尽携千里风月。"]'),
('song-ci-685','鹊桥仙','赵善括','宋','宋词','song-ci','鹊桥仙','[]','花腮百媚，柳丝千尺，密影金铺碎日。',68,'宋词/ci.song.11000.json','["花腮百媚，柳丝千尺，密影金铺碎日。", "过云微雨报清明，半天外、烟娇雾湿。", "当歌有恨，问春无语，笑我如何久客。", "小园归去又残红，便□地、飞觞尚得。"]'),
('song-ci-686','鹊桥仙','赵善括','宋','宋词','song-ci','鹊桥仙','[]','东风唤我，西园闲坐，大醉高歌竟日。',68,'宋词/ci.song.11000.json','["东风唤我，西园闲坐，大醉高歌竟日。", "行藏独依画栏干，便忘了、征衫泪湿。", "亭高烟远，天低云近，相对逃名隐客。", "掀髯无语看青山，断不信、尘埃到得。"]'),
('song-ci-687','清平乐','赵善括','宋','宋词','song-ci','清平乐','[]','断云漏雨。',54,'宋词/ci.song.11000.json','["断云漏雨。", "依约西山暮。", "风定樯高须小住。", "不忍带将春去。", "此行抑有求欤。", "青衣拟问平都。", "万里一钩新月，相忘常在江湖。"]'),
('song-ci-688','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','[]','危台枕城堞，今昔几人游。',114,'宋词/ci.song.11000.json','["危台枕城堞，今昔几人游。", "绕城碧水一带，茂苑与长洲。", "寂寂弹琴风外，苒苒采香径畔，横截古溪头。", "极目暮云合，宋玉正悲秋。", "岘山碑，帝子阁，庾公楼。", "当时风物，如今烟水只供愁。", "处处山明水秀，岁岁春花秋月，何必美南州。", "故国未归去，萍梗叹漂流。"]'),
('song-ci-689','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','["\u592a\u6e56"]','雨霁彩虹卧，半夜水明楼。',114,'宋词/ci.song.11000.json','["雨霁彩虹卧，半夜水明楼。", "太湖极目，四面水尽是天流。", "几点鲈乡荻浦，万里鲸波雪浪，掀舞小渔舟。", "金饼挂蟾魄，时景正中秋。", "钓纶轻，兰棹稳，笑王侯。", "一蓑一笠，得意何必美封留。", "纵使金章鼎贵，何似玉樽倾到，一醉可消愁。", "玉女在何许，唤起与同游。"]'),
('song-ci-690','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','[]','佳客志淮海，贱子设樽罍。',114,'宋词/ci.song.11000.json','["佳客志淮海，贱子设樽罍。", "楚江昨夜清涨，短棹已安排。", "休问南楼风月，且念阳台云雨，几日却重来。", "银烛正凝泪，画鼓且休催。", "彩云飞，黄鹤举，两徘徊。", "林泉归去高卧，回首笑尘埃。", "我唱更凭君和，君起谁同我舞，莫惜玉山颓。", "他日扬州路，散策愿相陪。"]'),
('song-ci-691','水调歌头','赵善括','宋','宋词','song-ci','水调歌头','[]','浩叹对青史，循吏久无闻。',114,'宋词/ci.song.11000.json','["浩叹对青史，循吏久无闻。", "二年江右，赖公华节布阳春。", "才自搴帷问俗，无复埋轮当道，一路尽澄清。", "多少攀辕意，不待及瓜人。", "驻膏车，迟祖帐，倒离尊。", "满庭桃李绿阴，何处不深恩。", "此去玉音应问，底事金围微减，忧国更忧民。", "造膝一言语，四海入洪钧。"]'),
('song-ci-692','满江红','赵善括','宋','宋词','song-ci','满江红','[]','雨沐风梳，正梅柳、弄香逞色。',115,'宋词/ci.song.11000.json','["雨沐风梳，正梅柳、弄香逞色。", "谁忍听、送君南浦，阳关三叠。", "玉节前驱光照路，金杯争劝愁生席。", "泛锦樯、西去若登仙，乘槎客。", "春有意，寒无力。", "和风满，洪波息。", "笑庐峰湓浦，旧游陈迹。", "昔日蜚声台柏劲，他年坐对堂槐密。", "想轺车、不待政成时，追锋急。"]'),
('song-ci-693','满庭芳','赵善括','宋','宋词','song-ci','满庭芳','[]','蝶粉蜂黄，桃红李白，春风屡展愁眉。',118,'宋词/ci.song.11000.json','["蝶粉蜂黄，桃红李白，春风屡展愁眉。", "晓来雨过，应渐觉红稀。", "满径柔茵似染，新晴后、皱绿盈池。", "休孤负，幕天席地，逸饮酹金彝。", "东君，真好事，降唇歌雪，玉指鸣丝。", "念长卿多病，非药能治。", "试假瑶琴一弄，清音转、便许心知。", "从今去，园林好在，休学岘山碑。"]'),
('song-ci-694','好事近','赵善括','宋','宋词','song-ci','好事近','[]','新月巧穿山，桂树影高群木。',53,'宋词/ci.song.11000.json','["新月巧穿山，桂树影高群木。", "任使云遮烟锁，自春辉秋绿。", "我来折得最高枝，踏破一轮玉。", "宝斧修教园样，放十分光足。"]'),
('song-ci-695','满江红','程垓','宋','宋词','song-ci','满江红','[]','门掩垂杨，宝香度、翠帘重叠。',115,'宋词/ci.song.11000.json','["门掩垂杨，宝香度、翠帘重叠。", "春寒在，罗衣初试，素肌犹却。", "薄霭笼花天欲暮，小风送角声初咽。", "但独褰、幽幌悄无言，伤初别。", "衣上雨，眉间月。", "滴不尽，颦空切。", "羡栖梁归燕，入帘双蝶。", "愁绪多於花絮乱，柔肠过似丁香结。", "问甚时、重理锦囊书，从头说。"]'),
('song-ci-696','满江红','程垓','宋','宋词','song-ci','满江红','[]','水远山明，秋容淡、不禁摇落。',115,'宋词/ci.song.11000.json','["水远山明，秋容淡、不禁摇落。", "况正是、楼台高处，晚凉犹薄。", "月在衣裳风在袖，冰生枕簟香生幕。", "算四时、佳处是清秋，须行乐。", "东篱下，西窗角。", "寻旧菊，催新酌。", "笑广平何事，对秋萧索。", "摇叶声声深院宇，折荷寸寸闲池阁。", "待归来、闲把木犀花，重薰却。"]'),
('song-ci-697','最高楼','程垓','宋','宋词','song-ci','最高楼','[]','旧时心事，说著两眉羞。',103,'宋词/ci.song.11000.json','["旧时心事，说著两眉羞。", "长记得、凭肩游。", "缃裙罗袜桃花岸，薄衫轻扇杏花楼。", "几番行，几番醉，几番留。", "也谁料、春风吹已断。", "又谁料、朝云飞亦散。", "天易老，恨难酬。", "蜂儿不解知人苦，燕儿不解说人愁。", "旧情怀，消不尽，几时休。"]'),
('song-ci-698','南浦','程垓','宋','宋词','song-ci','南浦','[]','金鸭懒薰香，向晚来春酲，一枕无绪。',127,'宋词/ci.song.11000.json','["金鸭懒薰香，向晚来春酲，一枕无绪。", "浓绿涨瑶窗，东风外、吹尽乱红飞絮。", "无言伫立，断肠惟有流莺语。", "碧云欲暮。", "空惆怅，韶华一时虚度。", "追思旧日心情，记题叶西楼，吹花南浦。", "老去觉欢疏，伤春恨，都付断云残雨。", "黄昏院落，问谁犹在凭栏处。", "可堪杜宇。", "空只解声声，催他春去。"]'),
('song-ci-699','摊破江城子・江城梅花引','程垓','宋','宋词','song-ci','摊破江城子・江城梅花引','[]','娟娟霜月又侵门。',110,'宋词/ci.song.11000.json','["娟娟霜月又侵门。", "对黄昏。", "怯黄昏。", "愁把梅花，独自泛清尊。", "酒又难禁花又恼，漏声远，一更更，总断魂。", "断魂。", "断魂。", "不堪闻。", "被半温。", "香半温。", "睡也睡也，睡不稳、谁与温存。", "只有床前、红烛伴啼痕。", "一夜无眠连晓角，人瘦也，比梅花，瘦几分。"]'),
('song-ci-700','木兰花慢','程垓','宋','宋词','song-ci','木兰花慢','[]','倩娇莺姹燕，说不尽、此时情。',121,'宋词/ci.song.11000.json','["倩娇莺姹燕，说不尽、此时情。", "正小院春阑，芳园画锁，人去花零。", "凭高试回望眼，奈遥山远水隔重云。", "谁遣风狂雨横，便教无计留春。", "谁知雁杳与鸿冥。", "自难寄丁宁。", "纵柳院颦深，桃门笑在，知属何人。", "衣篝几回忘了，奈残香、犹有旧时熏。", "空使风头卷絮，为他飘荡花城。"]'),
('song-ci-701','八声甘州','程垓','宋','宋词','song-ci','八声甘州','[]','问东君、既解遣花开，不合放花飞。',118,'宋词/ci.song.11000.json','["问东君、既解遣花开，不合放花飞。", "念春风枝上，一分花减，一半春归。", "忍见千红万翠，容易涨桃溪。", "花自随流水，无计追随。", "不忍凭高南望，记旧时行处，芳意菲菲。", "叹年来春减，花与故人非。", "总使、梁园赋在，奈长卿、老去亦何为。", "空搔首，乱云堆里，立尽斜晖。"]'),
('song-ci-702','洞庭春色・沁园春','程垓','宋','宋词','song-ci','洞庭春色・沁园春','[]','锦字亲裁，泪巾偷裛，细说旧时。',136,'宋词/ci.song.11000.json','["锦字亲裁，泪巾偷裛，细说旧时。", "记笑桃门巷，妆窥宝靥，弄花庭前，香湿罗衣。", "几度相随游冶去，任月细风尖犹未归。", "多少事，有垂杨眼见，红烛心知。", "如今事都过也，但赢得、双鬓成丝。", "叹半妆红豆，相思有分，两分青镜，重合难期。", "惆怅一春飞絮，梦悠颺教人分付谁。", "销魂处，又梨花雨暗，半掩重扉。"]'),
('song-ci-703','四代好・宴清都','程垓','宋','宋词','song-ci','四代好・宴清都','[]','翠幕东风早。',125,'宋词/ci.song.11000.json','["翠幕东风早。", "兰窗梦，又被莺声惊觉。", "起来空对，平阶弱絮，满庭芳草。", "厌厌未忺怀抱。", "记柳外、人家曾到。", "凭画阑、那更春好花好，酒好人好。", "春好尚恐阑珊，花好又怕，飘零难保。", "直饶酒好□渑，未抵意中人好。", "相逢尽拼醉倒。", "况人与、才情未老。", "又岂关、春去春来，花愁花恼。"]'),
('song-ci-704','水龙吟','程垓','宋','宋词','song-ci','水龙吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','夜来风雨匆匆，故园定是花无几。',126,'宋词/ci.song.11000.json','["夜来风雨匆匆，故园定是花无几。", "愁多愁极，等闲孤负，一年芳意。", "柳困花慵，杏青梅小，对人容易。", "算好春长在，好花长见，元只是、人憔悴。", "回首池南旧事。", "恨星星、不堪重记。", "如今但有，看花老眼，伤时清泪。", "不怕逢花瘦，只愁怕、老来风味。", "待繁红乱处，留云借月，也须拼醉。"]'),
('song-ci-705','玉漏迟','程垓','宋','宋词','song-ci','玉漏迟','[]','一春浑不见，那堪又是，花飞时节。',117,'宋词/ci.song.11000.json','["一春浑不见，那堪又是，花飞时节。", "忍对危栏数曲，暮云千叠。", "门外星星柳眼，看还似、当时风月。", "愁万结。", "凭谁为我，殷勤低说。", "不是惯却春心，奈新燕传情，旧莺饶舌。", "冷篆馀香，莫放等闲消歇。", "纵使繁红褪尽，犹有、荼䕷堪折。", "魂梦切。", "如今不奈，飞来蝴蝶。"]'),
('song-ci-706','折红英・撷芳词','程垓','宋','宋词','song-ci','折红英・撷芳词','[]','桃花暖。',76,'宋词/ci.song.11000.json','["桃花暖。", "杨花乱。", "可怜朱户春强半。", "长记忆。", "探芳日。", "笑凭郎肩，殢红偎碧。", "惜惜惜。", "春宵短。", "离肠断。", "泪痕长向东风满。", "凭青翼。", "问消息。", "花谢春归，几时来得。", "忆忆忆。"]'),
('song-ci-707','上平西・金人捧露盘','程垓','宋','宋词','song-ci','上平西・金人捧露盘','[]','爱春归，忧春去，为春忙。',98,'宋词/ci.song.11000.json','["爱春归，忧春去，为春忙。", "旋点检、雨障云妨。", "遮红护绿，翠帷罗幕任高张。", "海棠明月杏花天，更惜浓芳。", "唤莺吟，招蝶拍，迎柳舞，倩桃妆。", "尽唤起、万籁笙簧。", "一觞一咏，尽教陶写绣心肠。", "笑他人世漫嬉游，拥翠偎香。"]'),
('song-ci-708','瑶阶草','程垓','宋','宋词','song-ci','瑶阶草','[]','空山子规叫，月破黄昏冷。',97,'宋词/ci.song.11000.json','["空山子规叫，月破黄昏冷。", "帘幕风轻，绿暗红又尽。", "自从别后，粉消香腻，一春成病。", "那堪昼闲日永。", "恨难整。", "起来无语，绿萍破处池光净。", "闷理残妆，照花独自怜瘦影。", "睡来又怕，饮来越醉，醒来却闷。", "看谁似我孤令。"]'),
('song-ci-709','碧牡丹','程垓','宋','宋词','song-ci','碧牡丹','[]','睡起情无著。',93,'宋词/ci.song.11000.json','["睡起情无著。", "晓雨尽，春寒弱。", "酒盏飘零，几日顿疏行乐。", "试数花枝，问此情何若。", "为谁开，为谁落。", "正愁却。", "不是花情薄。", "花元笑人萧索。", "旧观千红，至今冷梦难托。", "燕麦春风，更几人惊觉。", "对花羞，为花恶。"]'),
('song-ci-710','满庭芳','程垓','宋','宋词','song-ci','满庭芳','[]','南月惊乌，西风破雁，又是秋满平湖。',118,'宋词/ci.song.11000.json','["南月惊乌，西风破雁，又是秋满平湖。", "采莲人尽，寒色战菇蒲。", "旧信江南好景，一万里、轻觅莼鲈。", "谁知道，吴侬未识，蜀客已情孤。", "凭高，增怅望，湘云尽处，都是平芜。", "问故乡何日，重见吾庐。", "纵有荷纫芰制，终不似、菊短篱疏。", "归情远，三更雨梦，依旧绕庭梧。"]'),
('song-ci-711','念奴娇','程垓','宋','宋词','song-ci','念奴娇','[]','秋风秋雨，正黄昏、供断一窗愁绝。',120,'宋词/ci.song.11000.json','["秋风秋雨，正黄昏、供断一窗愁绝。", "带减衣宽谁念我，难忍重城离别。", "转枕褰帷，挑灯整被，总是相思切。", "知他别后，负人多少风月。", "不是怨极愁浓，只愁重见了，相思难说。", "料得新来魂梦里，不管飞来蝴蝶。", "排闷人间，寄愁天上，终有归时节。", "如今无奈，乱云依旧千叠。"]'),
('song-ci-712','雪狮儿','程垓','宋','宋词','song-ci','雪狮儿','[]','断云低晚，轻烟带暝，风惊罗幕。',110,'宋词/ci.song.11000.json','["断云低晚，轻烟带暝，风惊罗幕。", "数点梅花，香倚雪窗摇落。", "红炉对谑。", "正酒面、琼稣初削。", "云屏暖，不知门外，月寒风恶。", "迤逦慵云半掠。", "笑盈盈、闲弄宝筝弦索。", "暖极生春，已向横波先觉。", "花娇柳弱。", "渐倚醉、要人搂著。", "低告托。", "早把被香熏却。"]'),
('song-ci-713','摸鱼儿','程垓','宋','宋词','song-ci','摸鱼儿','[]','掩凄凉、黄昏庭院，角声何处呜咽。',141,'宋词/ci.song.11000.json','["掩凄凉、黄昏庭院，角声何处呜咽。", "矮窗曲屋风灯冷，还是苦寒时节。", "凝伫切。", "念翠被熏笼，夜夜成虚设。", "倚阑愁绝。", "听凤竹声中，犀影帐外，簌簌酿寒轻雪。", "伤心处，却忆当年轻别。", "梅花满园初发。", "吹香弄蕊无人见，帷有暮云千叠。", "情未彻。", "又谁料而今，好梦分胡越。", "不堪重说。", "但记得当初，重门锁处，犹有夜深月。"]'),
('song-ci-714','无闷','程垓','宋','宋词','song-ci','无闷','[]','天与多才，不合更与，殢柳怜花情分。',122,'宋词/ci.song.11000.json','["天与多才，不合更与，殢柳怜花情分。", "甚总为才情，恼人方寸。", "早是春残花褪。", "也不料、一春都成病。", "自失笑，因甚腰围半减，珠泪频搵。", "难省。", "也怨天、也自恨。", "怎免千般思忖。", "倩人说与，又却不忍。", "拼了一生愁闷。", "又只恐、愁多无人问。", "到这里，天也怜人，看他稳也不稳。"]'),
('song-ci-715','孤雁儿・御街行','程垓','宋','宋词','song-ci','孤雁儿・御街行','[]','在家不觉穷冬好。',94,'宋词/ci.song.11000.json','["在家不觉穷冬好。", "向客里、方知道。", "故园梅花正开时，记得清尊频倒。", "高烧红蜡，暖熏罗幌，一任花枝恼。", "如今客里伤怀抱。", "忍双鬓、随花老。", "小窗独自对黄昏，只有月华飞到。", "假饶真个，雁书频寄，何似归来早。"]'),
('song-ci-716','孤雁儿・御街行','程垓','宋','宋词','song-ci','孤雁儿・御街行','[]','双鬓乍绾横波溜。',94,'宋词/ci.song.11000.json','["双鬓乍绾横波溜。", "记当日、香心透。", "谁教容易逐鸡飞，输却春风先手。", "天公元也，管人憔悴，放出花枝瘦。", "几宵和月来相就。", "问何事、春山斗。", "祗应深院锁蝉娟，枉却娇花时候。", "何时为我，小梯横阁，试约黄昏后。"]'),
('song-ci-717','意难忘','程垓','宋','宋词','song-ci','意难忘','[]','花拥鸳房。',114,'宋词/ci.song.11000.json','["花拥鸳房。", "记驼肩髻小，约鬓眉长。", "轻身翻燕舞，低语转莺簧。", "相见处，便难忘。", "肯亲度瑶觞。", "向夜阑，歌翻郢曲，带换韩香。", "别来音信难将。", "似云收楚峡，雨散巫阳。", "相逢情有在，不语意难量。", "些个事，断人肠。", "怎禁得恓惶。", "待与伊、移根换叶，试又何妨。"]'),
('song-ci-718','一丛花','程垓','宋','宋词','song-ci','一丛花','[]','伤春时候一凭阑。',94,'宋词/ci.song.11000.json','["伤春时候一凭阑。", "何况别离难。", "东风只解催人去，也不道、莺老花残。", "青笺未约，红绡忍泪，无计锁征鞍。", "宝钗瑶钿一时闲。", "此恨苦天悭。", "如今直恁抛人去，也不念、人瘦衣宽。", "归来忍见，重楼淡月，依旧五更寒。"]'),
('song-ci-719','蓦山溪','程垓','宋','宋词','song-ci','蓦山溪','[]','老来风味，是事都无可。',102,'宋词/ci.song.11000.json','["老来风味，是事都无可。", "只爱小书舟，剩围着、琅玕几个。", "呼风约月，随分乐生涯，不羡富，不忧贫，不怕乌蟾堕。", "三杯径醉，转觉乾坤大。", "醉后百篇诗，尽从他、龙吟鹤和。", "升沈万事，还与本来天，青云上，白云间，一任安排我。"]'),
('song-ci-720','满江红','程垓','宋','宋词','song-ci','满江红','[]','葺屋为舟，身便是、烟波钓客。',111,'宋词/ci.song.11000.json','["葺屋为舟，身便是、烟波钓客。", "况人间元似，泛家浮宅。", "秋晚雨声篷背稳，夜深月影窗棂白。", "□满船诗酒满船书，随意索。", "也不怕，云涛隔。", "也不怕，风帆侧。", "但独醒还睡，自歌还拍。", "卧后从教秋鳝舞，醉来一任乾坤窄。", "恐有时、撑向大江头，占风色。"]'),
('song-ci-721','小桃红・连理枝','程垓','宋','宋词','song-ci','小桃红・连理枝','[]','不恨残花妥。',85,'宋词/ci.song.11000.json','["不恨残花妥。", "不恨残春破。", "只恨流光，一年一度，又催新火。", "纵青天白日系长绳，也留春得麽。", "花院重教锁。", "春事从教过。", "烧笋园林，尝梅台榭，有何不可。", "已安排、珍簟小胡床，待日长闲坐。"]'),
('song-ci-722','芭蕉雨','程垓','宋','宋词','song-ci','芭蕉雨','[]','雨过凉生藕叶。',79,'宋词/ci.song.11000.json','["雨过凉生藕叶。", "晚庭消尽暑，浑无热。", "枕簟不胜香滑。", "争奈宝帐情生，金尊意惬。", "玉人何处梦蝶。", "思一见冰雪。", "须写个贴儿、丁宁说。", "试问道、肯来麽，今夜小院无人，重楼有月。"]'),
('song-ci-723','红娘子・连理枝','程垓','宋','宋词','song-ci','红娘子・连理枝','[]','小小闲窗底。',85,'宋词/ci.song.11000.json','["小小闲窗底。", "曲曲深屏里。", "一枕新凉，半床明月，留人欢意。", "奈梅花引里唤人行，苦随他无计。", "几点清觞泪。", "数曲乌丝纸。", "见少离多，心长分短，如何得是。", "到如今、留下许都愁，枉教人憔悴。"]'),
('song-ci-724','醉落魄・一斛珠','程垓','宋','宋词','song-ci','醉落魄・一斛珠','[]','夏围初结。',67,'宋词/ci.song.11000.json','["夏围初结。", "绿深深处红千叠。", "杜鹃过尽芳菲歇。", "只道无春，满意春犹惬。", "折来一点如猩血。", "透明冠子轻盈贴。", "芳心蹙破情尤切。", "不管花残，犹自拣双叶。"]'),
('song-ci-725','一翦梅','程垓','宋','宋词','song-ci','一翦梅','[]','旧日心期不易招。',72,'宋词/ci.song.11000.json','["旧日心期不易招。", "重来孤负，几个良宵。", "寻常不见尽相邀。", "见了知他，许大无聊。", "昨夜梅花插翠翘。", "影落清溪，应也魂消。", "假饶真个住山腰。", "那个金章，换得渔樵。"]'),
('song-ci-726','一翦梅','程垓','宋','宋词','song-ci','一翦梅','[]','小会幽欢整及时。',72,'宋词/ci.song.11000.json','["小会幽欢整及时。", "花也相宜。", "人也相宜。", "宝香未断烛光低。", "莫厌杯迟。", "莫恨欢迟。", "夜渐深深漏渐稀。", "风已侵衣。", "露已沾衣。", "一杯重劝莫相违。", "何似休归。", "何自同归。"]'),
('song-ci-727','眼儿媚','程垓','宋','宋词','song-ci','眼儿媚','[]','一枝烟雨瘦东墙。',57,'宋词/ci.song.11000.json','["一枝烟雨瘦东墙。", "真个断人肠。", "不为天寒日暮，谁怜水远山长。", "相思月底，相思竹外，犹自禁当。", "只恐玉楼贪梦，输他一夜清香。"]'),
('song-ci-728','浪淘沙','程垓','宋','宋词','song-ci','浪淘沙','[]','山尽两溪头。',64,'宋词/ci.song.11000.json','["山尽两溪头。", "水合天浮。", "行人莫赋大江愁。", "且是芙蓉城下水，还送归舟。", "渔雁两悠悠。", "烟断云收。", "谁教此水却西流。", "载我相思千点泪，还与青楼。"]'),
('song-ci-729','雨中花令','程垓','宋','宋词','song-ci','雨中花令','[]','闻说海棠开尽了。',66,'宋词/ci.song.11000.json','["闻说海棠开尽了。", "怎生得、夜来一笑。", "颦绿枝头，落红点里，问有愁多少。", "小园闭门春悄悄。", "禁不得、瘦腰如袅。", "豆蔻浓时，酴醿香处，试把菱花照。"]'),
('song-ci-730','雨中花令','程垓','宋','宋词','song-ci','雨中花令','[]','旧日爱花心未了。',66,'宋词/ci.song.11000.json','["旧日爱花心未了。", "紧消得、花时一笑。", "几日春寒，连宵雨闷，不道幽欢少。", "记得去年深院悄。", "□梁畔，一枝香袅。", "说与西楼，后来明月，莫把菱花照。"]'),
('song-ci-731','雨中花令','程垓','宋','宋词','song-ci','雨中花令','[]','卷地芳草都过了。',66,'宋词/ci.song.11000.json','["卷地芳草都过了。", "花不语、对人含笑。", "花与人期，人怜花病，瘦似人多少。", "闻道重门深悄悄。", "愁不尽、露啼烟袅。", "断得相思，除非明月，不把花枝照。"]'),
('song-ci-732','凤栖梧・蝶恋花','程垓','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','九月江南烟雨里。',70,'宋词/ci.song.11000.json','["九月江南烟雨里。", "客枕凄凉，到晓浑无寐。", "起上小楼观海气。", "昏昏半约渔樵市。", "断雁西边家万里。", "料得秋来，笑我归无计。", "剑在床头书在几。", "未甘分付黄花泪。"]'),
('song-ci-733','凤栖梧・蝶恋花','程垓','宋','宋词','song-ci','凤栖梧・蝶恋花','["\u94b1\u5858\u6c5f"]','有客钱塘江上住。',70,'宋词/ci.song.11000.json','["有客钱塘江上住。", "十日斋居，九日愁风雨。", "断送一春弹指去。", "荷花又绕南山渡。", "湖上幽寻君已许。", "消息不来，望得行云暮。", "芳草梦魂应记取。", "不成忘却池塘句。"]'),
('song-ci-734','凤栖梧・蝶恋花','程垓','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','门外飞花风约住。',70,'宋词/ci.song.11000.json','["门外飞花风约住。", "消息江南，已酿黄梅雨。", "蜀客望乡归不去。", "当时不合催南渡。", "忧国丹心曾独许。", "纵吐长虹，不奈斜阳暮。", "莫道春光难揽取。", "少陵辨得寻花句。"]'),
('song-ci-735','凤栖梧・蝶恋花','程垓','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','薄薄窗油清似镜。',70,'宋词/ci.song.11000.json','["薄薄窗油清似镜。", "两面疏帘，四壁文书静。", "小篆焚香消日永。", "新来识得闲中性。", "人爱人嫌都莫问。", "絮自沾泥，不怕东风紧。", "只有诗狂消不尽。", "夜来题破窗花影。"]'),
('song-ci-736','凤栖梧・蝶恋花','程垓','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','九月重湖寒意早。',70,'宋词/ci.song.11000.json','["九月重湖寒意早。", "目断黄云，冉冉连衰草。", "惨别临江愁满抱。", "酒尊时事都相恼。", "闻道吴天消息好。", "鸳鸯西池，咫尺君应到。", "若见故人相问劳。", "为言未分书舟老。"]'),
('song-ci-737','愁倚阑・春光好','程垓','宋','宋词','song-ci','愁倚阑・春光好','[]','山无数，雨萧萧。',51,'宋词/ci.song.11000.json','["山无数，雨萧萧。", "路迢迢。", "不似芙蓉城下去，柳如腰。", "梦随春絮飘飘。", "知他在、第几朱桥。", "说与杜鹃休唤，怕魂销。"]'),
('song-ci-738','渔家傲','程垓','宋','宋词','song-ci','渔家傲','[]','野店无人霜似水。',72,'宋词/ci.song.11000.json','["野店无人霜似水。", "清灯照影寒侵被。", "门外行人催客起。", "因个事。", "老来方有思家泪。", "寄问梅花开也未。", "爱花只有归来是。", "想见小桥歌舞地。", "浑含喜。", "天涯不念人憔悴。"]'),
('song-ci-739','渔家傲','程垓','宋','宋词','song-ci','渔家傲','[]','独木小舟烟雨湿。',72,'宋词/ci.song.11000.json','["独木小舟烟雨湿。", "燕儿乱点春江碧。", "江上青山随意觅。", "人寂寂。", "落花芳草催寒食。", "昨夜青楼今日客。", "吹愁不得东风力。", "细拾残红书怨泣。", "流水急。", "不知那个传消息。"]'),
('song-ci-740','临江仙','程垓','宋','宋词','song-ci','临江仙','[]','送我南来舟一叶，谁教催动鸣榔。',70,'宋词/ci.song.11000.json','["送我南来舟一叶，谁教催动鸣榔。", "高城不见水茫茫。", "云湾才几曲，折尽九回肠。", "买酒浇愁愁不尽，江烟也共凄凉。", "和天瘦了也何妨。", "只愁今夜雨，更做泪千行。"]'),
('song-ci-741','临江仙','程垓','宋','宋词','song-ci','临江仙','[]','浓绿锁窗闲院静，照人明月团团。',70,'宋词/ci.song.11000.json','["浓绿锁窗闲院静，照人明月团团。", "夜长幽梦见伊难。", "瘦从香脸薄，愁到翠眉残。", "只道花时容易见，如今花尽春阑。", "画楼依旧五更寒。", "可怜红绣被，空记合时欢。"]'),
('song-ci-742','朝中措','程垓','宋','宋词','song-ci','朝中措','[]','矮窗西畔翠荷香。',57,'宋词/ci.song.11000.json','["矮窗西畔翠荷香。", "人在小池塘。", "何事未拈期局，却来闲倚胡床。", "金盆弄水，玉钗亸鬓，妆懒何妨。", "莫道困来不饮，今宵却恨天凉。"]'),
('song-ci-743','朝中措','程垓','宋','宋词','song-ci','朝中措','[]','华筵饮散撤芳尊。',57,'宋词/ci.song.11000.json','["华筵饮散撤芳尊。", "人影乱纷纷。", "且约玉骢留住，细将团凤平分。", "一瓯看取，招回酒兴，爽彻诗魂。", "歌罢清风两腋，归来明月千门。"]'),
('song-ci-744','朝中措','程垓','宋','宋词','song-ci','朝中措','[]','龙团分罢觉芳滋。',57,'宋词/ci.song.11000.json','["龙团分罢觉芳滋。", "歌彻碧云词。", "翠袖且留纤玉，沈香载捧冰垍。", "一声清唱，半瓯轻啜，愁绪如丝。", "记取临汾馀味，图教归后相思。"]'),
('song-ci-745','朝中措','程垓','宋','宋词','song-ci','朝中措','[]','真游六六洞中仙。',57,'宋词/ci.song.11000.json','["真游六六洞中仙。", "骑鹤下三天。", "休道日斜岁暮，行年方是韶华。", "相逢一笑，此心不动，须待明年。", "要得安排稳当，除非四十相连。"]'),
('song-ci-746','朝中措','程垓','宋','宋词','song-ci','朝中措','[]','片花飞后水东流。',57,'宋词/ci.song.11000.json','["片花飞后水东流。", "无计挽春留。", "香小谁栽杜若，梦回依旧扬州。", "破瓜年在，娇花艳冶，舞柳纤柔。", "莫道刘郎霜鬓，才情未放春休。"]'),
('song-ci-747','醉落魄・一斛珠','程垓','宋','宋词','song-ci','醉落魄・一斛珠','[]','风催雨促。',67,'宋词/ci.song.11000.json','["风催雨促。", "今番不似前欢足。", "早来最苦离情毒。", "唱我新词，掩著面儿哭。", "临行只怕人行远。", "殷勤更写多情曲。", "相逢已是腰如束。", "从此知他，还减几分玉。"]'),
('song-ci-748','酷相思','程垓','宋','宋词','song-ci','酷相思','[]','月挂霜林寒欲坠。',83,'宋词/ci.song.11000.json','["月挂霜林寒欲坠。", "正门外、催人起。", "奈离别、如今真个是。", "欲住也、留无计。", "欲去也、来无计。", "马上离魂衣上泪。", "各自个、供憔悴。", "问江路梅花开也未。", "春到也、须频寄。", "人到也、须频寄。"]'),
('song-ci-749','生查子','程垓','宋','宋词','song-ci','生查子','[]','溪光曲曲村，花影重重树。',48,'宋词/ci.song.11000.json','["溪光曲曲村，花影重重树。", "风物小桃源，春事还如许。", "情知送客来，又作寻芳去。", "可惜一春诗，总为闲愁赋。"]'),
('song-ci-750','生查子','程垓','宋','宋词','song-ci','生查子','[]','长记别郎时，月淡梅花影。',48,'宋词/ci.song.11000.json','["长记别郎时，月淡梅花影。", "梅影又横窗，不见江南信。", "无心换夕香，有分怜朝镜。", "不怕瘦棱棱，只怕梅开尽。"]'),
('song-ci-751','忆王孙','程垓','宋','宋词','song-ci','忆王孙','[]','萧萧梅雨断人行。',36,'宋词/ci.song.11000.json','["萧萧梅雨断人行。", "门掩残春绿荫生。", "翠被寒灯枕自横。", "梦初惊。", "窗外啼鹃催五更。"]'),
('song-ci-752','卜算子','程垓','宋','宋词','song-ci','卜算子','[]','枕簟暑风消，帘幕秋风动。',52,'宋词/ci.song.11000.json','["枕簟暑风消，帘幕秋风动。", "月到夜来愁处明，只照团衾凤。", "去意杳无凭，别语愁难送。", "一纸鱼笺枕底香，且做新来梦。"]'),
('song-ci-753','卜算子','程垓','宋','宋词','song-ci','卜算子','[]','独自上层楼，楼外青山远。',52,'宋词/ci.song.11000.json','["独自上层楼，楼外青山远。", "望到斜阳欲尽时，不见西飞雁。", "独自下层楼，楼下蛩声怨。", "待到黄昏月上时，依旧柔肠断。"]'),
('song-ci-754','卜算子','程垓','宋','宋词','song-ci','卜算子','[]','几日赏花天，月淡荼䕷小。',52,'宋词/ci.song.11000.json','["几日赏花天，月淡荼䕷小。", "写尽相思唤不来，又是花飞了。", "春在怕愁多，春去怜欢少。", "一夜安排梦不成，月堕西窗晓。"]'),
('song-ci-755','霜天晓角','程垓','宋','宋词','song-ci','霜天晓角','[]','几夜锁窗揭。',54,'宋词/ci.song.11000.json','["几夜锁窗揭。", "素蟾光似雪。", "恰恨照人欹枕，纱橱爽、簟纹滑。", "迤逦篆香裛。", "好坏谁共说。", "若是知人风味，来分取、半床月。"]'),
('song-ci-756','霜天晓角','程垓','宋','宋词','song-ci','霜天晓角','[]','玉清冰样洁。',54,'宋词/ci.song.11000.json','["玉清冰样洁。", "几夜相思切。", "谁料浓云遮拥，同心带、甚时结。", "匆匆休惜别。", "还有来时节。", "记取江阴归路，须共踏、夜深月。"]'),
('song-ci-757','乌夜啼','程垓','宋','宋词','song-ci','乌夜啼','[]','杨柳拖烟漠漠，梨花浸月溶溶。',56,'宋词/ci.song.11000.json','["杨柳拖烟漠漠，梨花浸月溶溶。", "吹香院落春还尽，憔悴立东风。", "只道芳时易见，谁知密约难通。", "芳园绕遍无人问，独自拾残红。"]'),
('song-ci-758','乌夜啼','程垓','宋','宋词','song-ci','乌夜啼','[]','白酒欺人易醉，黄花笑我多愁。',56,'宋词/ci.song.11000.json','["白酒欺人易醉，黄花笑我多愁。", "一年只有秋光好，独自却悲秋。", "风急常吹梦去，月迟多为人留。", "半黄橙子和诗卷，空自伴床头。"]'),
('song-ci-759','乌夜啼','程垓','宋','宋词','song-ci','乌夜啼','[]','绿外深深柳巷，红间曲曲花楼。',56,'宋词/ci.song.11000.json','["绿外深深柳巷，红间曲曲花楼。", "一春想见贪游冶，不道有人愁。", "三月东风易老，几宵明月难留。", "酴醿白尽窗前也，还肯醉来否。"]'),
('song-ci-760','瑞鹧鸪','程垓','宋','宋词','song-ci','瑞鹧鸪','[]','东风冷落旧梅台。',64,'宋词/ci.song.11000.json','["东风冷落旧梅台。", "犹喜山花拂面开。", "绀色染衣春意静，水沈熏骨晚风来。", "柔条不学丁香结，矮树仍参茉莉栽。", "安得方盆载幽植，道人随处作香材。"]'),
('song-ci-761','瑞鹧鸪','程垓','宋','宋词','song-ci','瑞鹧鸪','[]','门前杨柳绿成阴。',64,'宋词/ci.song.11000.json','["门前杨柳绿成阴。", "翠坞笼香径自深。", "迟日暖熏芳草眼，好风轻撼落花心。", "无多春恨莺难语，最晚朝眠蝶易寻。", "惟有狂醒不相贷，酿成憔悴到如今。"]'),
('song-ci-762','青玉案','程垓','宋','宋词','song-ci','青玉案','[]','宝林岩畔凌云路。',80,'宋词/ci.song.11000.json','["宝林岩畔凌云路。", "记藉草、寻梅去。", "咏绿书红知几度。", "行云归后，碧云遮断，寂寞人何处。", "一声长笛江天暮。", "别后谁吟倚楼句。", "匀面照溪心已许。", "欲凭锦字，写人愁去，生怕梨花雨。"]'),
('song-ci-763','好事近','程垓','宋','宋词','song-ci','好事近','[]','别梦记春前，春尽苦无归日。',53,'宋词/ci.song.11000.json','["别梦记春前，春尽苦无归日。", "想见鹊声庭院，误几回消息。", "万重离恨万重山，无处说思忆。", "只有路傍双堠，也随人孤只。"]'),
('song-ci-764','好事近','程垓','宋','宋词','song-ci','好事近','[]','天淡一帘秋，明月几时来得。',53,'宋词/ci.song.11000.json','["天淡一帘秋，明月几时来得。", "何事桂底香近，把清光邀勒。", "人间明晦总由天，何必问通塞。", "且为人如月好，醉莫分南北。"]'),
('song-ci-765','好事近','程垓','宋','宋词','song-ci','好事近','[]','烟尽戍楼空，又是一帘佳月。',53,'宋词/ci.song.11000.json','["烟尽戍楼空，又是一帘佳月。", "何事山城留滞，负好花时节。", "烧灯翦彩没心情，应有翠娥说。", "欲借好风吹恨，奈乱云愁叠。"]'),
('song-ci-766','好事近','程垓','宋','宋词','song-ci','好事近','[]','急雨闹冰荷，销尽一襟烦暑。',53,'宋词/ci.song.11000.json','["急雨闹冰荷，销尽一襟烦暑。", "趁取晚凉幽会，近翠阴浓处。", "风梢危滴撼珠矶，洒面得新句。", "莫怪玉壶倾尽，待月明归去。"]'),
('song-ci-767','点绛唇','程垓','宋','宋词','song-ci','点绛唇','[]','梅雨收黄，暑风依旧闲庭院。',50,'宋词/ci.song.11000.json','["梅雨收黄，暑风依旧闲庭院。", "露荷轻颤。", "只有香浮面。", "挂起西窗，月澹无人见。", "幽情远。", "随钗低扇。", "好个凉方便。"]'),
('song-ci-768','如梦令','程垓','宋','宋词','song-ci','如梦令','[]','风入藕花翻动。',40,'宋词/ci.song.11000.json','["风入藕花翻动。", "夜气与香俱纵。", "月又带风来，凉意一襟谁共。", "情重。", "情重。", "可惜短宵无梦。"]'),
('song-ci-769','清平乐','程垓','宋','宋词','song-ci','清平乐','[]','山城桃李。',54,'宋词/ci.song.11000.json','["山城桃李。", "催促春无几。", "日日为花须早起。", "犹□惜花无计。", "阿谁留得春风。", "长教绕绿围红。", "莫遣十分芳意，输他万点愁容。"]'),
('song-ci-770','清平乐','程垓','宋','宋词','song-ci','清平乐','[]','秋香谁买。',54,'宋词/ci.song.11000.json','["秋香谁买。", "散入琉璃界。", "点缀小红全不碍。", "还却铅华馀债。", "夜来月底相期。", "一枝未觉香迟。", "恰似青绫帐底，绛罗初试裙儿。"]'),
('song-ci-771','清平乐','程垓','宋','宋词','song-ci','清平乐','[]','疏疏整整。',54,'宋词/ci.song.11000.json','["疏疏整整。", "风急花无定。", "红烛照筵寒欲凝。", "时见筛帘玉影。", "夜深明月笼纱。", "醉归凉面香料。", "犹有惜梅心在，满庭误作吹花。"]'),
('song-ci-772','清平乐','程垓','宋','宋词','song-ci','清平乐','[]','绿深红少。',55,'宋词/ci.song.11000.json','["绿深红少。", "柳外横桥小。", "双燕不知幽梦好。", "惊起碧窗春晓。", "起来瞢�┒嗍薄�", "玉台金镜慵移。", "多少春愁未说，却来闲数花枝。"]'),
('song-ci-773','望秦川・南歌子','程垓','宋','宋词','song-ci','望秦川・南歌子','[]','柳弱眠初醒，梅残舞尚痴。',62,'宋词/ci.song.11000.json','["柳弱眠初醒，梅残舞尚痴。", "春阴将冷傍帘帷。", "又是东风和恨、向人归。", "乐事灯前记，愁肠酒后知。", "老来无计遣芳时。", "只有闲情随分、品花枝。"]'),
('song-ci-774','望秦川・南歌子','程垓','宋','宋词','song-ci','望秦川・南歌子','[]','竹粉翻新箨，荷花拭靓妆。',62,'宋词/ci.song.11000.json','["竹粉翻新箨，荷花拭靓妆。", "断云侵晚度横塘。", "小扇斜钗依约、傍牙床。", "蘸蜜分红荔，倾筒泻碧香。", "醉时风雨醒时凉。", "明月多情依旧、过西厢。"]'),
('song-ci-775','望秦川・南歌子','程垓','宋','宋词','song-ci','望秦川・南歌子','[]','翠黛随妆浅，铢衣称体香。',62,'宋词/ci.song.11000.json','["翠黛随妆浅，铢衣称体香。", "好风偏与十分凉。", "却扇含情独自、绕池塘。", "碧藕丝丝嫩，红榴叶叶双。", "牵丝摘叶为谁忙。", "情到厌厌拼醉、又何妨。"]'),
('song-ci-776','天仙子','程垓','宋','宋词','song-ci','天仙子','[]','惨惨霜林冬欲尽。',80,'宋词/ci.song.11000.json','["惨惨霜林冬欲尽。", "又是溪梅寒弄影。", "矮窗曲屋夜烧香，人已静。", "灯垂烬。", "点滴芭蕉和雨听。", "约个归期犹未定。", "一夜梦魂终不稳。", "知他勾得许多情，真个闷。", "无人问。", "说与画楼应不信。"]'),
('song-ci-777','望江南・忆江南','程垓','宋','宋词','song-ci','望江南・忆江南','[]','篷上雨，篷底有人愁。',64,'宋词/ci.song.11000.json','["篷上雨，篷底有人愁。", "身在汉江东畔去，不知家在锦江头。", "烟水两悠悠。", "吾老矣，心事几时休。", "沈水熨香年似日，薄云垂帐夏如秋。", "安得小书舟。"]'),
('song-ci-778','南歌子','程垓','宋','宋词','song-ci','南歌子','[]','雨燕翻新幕，风鹃绕旧枝。',62,'宋词/ci.song.11000.json','["雨燕翻新幕，风鹃绕旧枝。", "画堂春尽日迟迟。", "又是一番平绿、涨西池。", "病起尊难尽，腰宽带易垂。", "不堪村落子规啼。", "问道行人一去、几时归。"]'),
('song-ci-779','南歌子','程垓','宋','宋词','song-ci','南歌子','[]','淡霭笼青琐，轻寒薄翠绡。',62,'宋词/ci.song.11000.json','["淡霭笼青琐，轻寒薄翠绡。", "有人憔悴带宽腰。", "又见东风、不忍见柔条。", "闷酒尊难寻，闲香篆易销。", "夜来溪雪已平桥。", "溪上梅魂凭仗、一相招。"]'),
('song-ci-780','南歌子','程垓','宋','宋词','song-ci','南歌子','[]','梅坞飞香定，兰窗翠色齐。',62,'宋词/ci.song.11000.json','["梅坞飞香定，兰窗翠色齐。", "水边沙际又春归。", "领略东风、能有几人知。", "爱月眠须晚，寻花去未迟。", "谁家庭院更芳菲。", "费尽才情、休负一春诗。"]'),
('song-ci-781','南歌子','程垓','宋','宋词','song-ci','南歌子','[]','荷盖倾新绿，榴巾蹙旧红。',62,'宋词/ci.song.11000.json','["荷盖倾新绿，榴巾蹙旧红。", "水亭烟榭晚凉中。", "又是一钩新月、静房栊。", "丝藕清如雪，幮纱薄似空。", "好维今夜与谁同。", "唤取玉人来共、一帘风。"]'),
('song-ci-782','南歌子','程垓','宋','宋词','song-ci','南歌子','[]','野水寻溪路，青山踏晚春。',62,'宋词/ci.song.11000.json','["野水寻溪路，青山踏晚春。", "偶来相值却锺情。", "一树琼瑶洗尽、客衣襟。", "曲沼通诗梦，幽窗净俗尘。", "何时散发伴襜裙。", "后夜相思生怕、月愁人。"]'),
('song-ci-783','南乡子','程垓','宋','宋词','song-ci','南乡子','[]','几日诉离尊。',66,'宋词/ci.song.11000.json','["几日诉离尊。", "歌尽阳关不忍分。", "此度天涯真个去，销魂。", "相送黄花落叶村。", "斜日又黄昏。", "萧寺无人半掩门。", "今夜粉香明月泪，休论。", "只要罗巾记旧痕。"]'),
('song-ci-784','浪淘沙','程垓','宋','宋词','song-ci','浪淘沙','[]','才合又轻离。',64,'宋词/ci.song.11000.json','["才合又轻离。", "心事多违。", "小窗灯影记亲移。", "可奈酒酣花困处，不省人归。", "山翠又如眉。", "肠断幽期。", "相思有梦阿谁知。", "莫遣重来风絮乱，不似当时。"]'),
('song-ci-785','浪淘沙','程垓','宋','宋词','song-ci','浪淘沙','[]','老去懒寻花。',64,'宋词/ci.song.11000.json','["老去懒寻花。", "独自生涯。", "几枝疏影浸窗纱。", "昨夜月来人不睡，看尽横斜。", "门外欲啼鸦。", "香意凌霞。", "从渠千树绕人家。", "世上一枝元也足，不要随他。"]'),
('song-ci-786','摊破南乡子','程垓','宋','宋词','song-ci','摊破南乡子','[]','休赋惜春诗。',76,'宋词/ci.song.11000.json','["休赋惜春诗。", "留春住、说与人知。", "一年已负东风瘦，说愁说恨，数期数刻，只望归时。", "莫怪杜鹃啼。", "真个也、唤得人归。", "归来休恨花开了，梁间燕子，且教知道，人也双飞。"]'),
('song-ci-787','祝英台・祝英台近','程垓','宋','宋词','song-ci','祝英台・祝英台近','[]','坠红轻，浓绿润，深院又春晚。',95,'宋词/ci.song.11000.json','["坠红轻，浓绿润，深院又春晚。", "睡起厌厌，无语小妆懒。", "可堪三月风光，五更魂梦，又都被、杜鹃催攒。", "怎消遣。", "人道愁与春归，春归愁未断。", "闲倚银屏，羞怕泪痕满。", "断肠沈水重熏，瑶琴闲理，奈依旧、夜寒人远。"]'),
('song-ci-788','虞美人','程垓','宋','宋词','song-ci','虞美人','[]','轻红短白东城路。',66,'宋词/ci.song.11000.json','["轻红短白东城路。", "忆得分襟处。", "柳丝无赖舞春柔。", "不系离人、只解系离愁。", "如今花谢春将老。", "柳下无人到。", "月明门外子规啼。", "唤得人愁、争似唤人归。"]'),
('song-ci-789','长相思','程垓','宋','宋词','song-ci','长相思','[]','对重阳。',44,'宋词/ci.song.11000.json','["对重阳。", "感重阳。", "身在西风天一方。", "年年人断肠。", "景凄凉。", "客凄凉。", "纵有黄花祗异乡。", "晚云连梦长。"]'),
('song-ci-790','长相思','程垓','宋','宋词','song-ci','长相思','[]','酒孤斟。',44,'宋词/ci.song.11000.json','["酒孤斟。", "客孤吟。", "戏马台荒露草深。", "英雄何处寻。", "爱登临。", "莫登临。", "定是愁来关客心。", "暮天烟水沈。"]'),
('song-ci-791','长相思','程垓','宋','宋词','song-ci','长相思','[]','风敲窗。',44,'宋词/ci.song.11000.json','["风敲窗。", "雨敲窗。", "窗外芭蕉云作幢。", "声声愁对床。", "剔银缸。", "点银缸。", "梦采芙蓉隔一江。", "几时蝴蝶双。"]'),
('song-ci-792','鹊桥仙','程垓','宋','宋词','song-ci','鹊桥仙','[]','角声吹月，风声落枕，梦与柔肠俱断。',68,'宋词/ci.song.11000.json','["角声吹月，风声落枕，梦与柔肠俱断。", "谁教当日太情浓，颺不下、新愁一段。", "黄花开了，梅花开未，曾约那时相见。", "莫教容易负幽期，怕真个、孤他泪眼。"]'),
('song-ci-793','醉落魄・一斛珠','程垓','宋','宋词','song-ci','醉落魄・一斛珠','[]','晚凉时节。',67,'宋词/ci.song.11000.json','["晚凉时节。", "翠梧风定蝉声歇。", "有人睡起香浮颊。", "倚著阑干，笑拣青荷叶。", "如今往事愁难说。", "曲池依旧闲风月。", "田田翠盖香罗叠。", "留得露痕，都是泪珠结。"]'),
('song-ci-794','减字木兰花','程垓','宋','宋词','song-ci','减字木兰花','[]','双双相并。',52,'宋词/ci.song.11000.json','["双双相并。", "一点红边偏照映。", "玉翦云裁。", "不比浮花共蒂开。", "几回心曲。", "选胜摘来情自足。", "插向云鬟。", "要与仙郎比并看。"]'),
('song-ci-795','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','春悄悄。',53,'宋词/ci.song.11000.json','["春悄悄。", "红到一枝先巧。", "酒入半腮微带卯。", "粉寒香未饱。", "芳意枝头偏闹。", "困尽蜂须莺爪。", "拟倩玉纤和露拗。", "情多愁易搅。"]'),
('song-ci-796','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','花簇簇。',53,'宋词/ci.song.11000.json','["花簇簇。", "触眼万条垂玉。", "小院春深窗锁绿。", "水沈风断续。", "明月又侵楼曲。", "羞向枕囊拘束。", "只待夜深清影足。", "醉来花底宿。"]'),
('song-ci-797','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','乌帽侧。',53,'宋词/ci.song.11000.json','["乌帽侧。", "行遍杏花春色。", "野意青青分陇麦。", "人家烟水隔。", "春事莫催行客。", "弹指青梅堪摘。", "醉倚暮天江拍拍。", "雨晴沙路白。"]'),
('song-ci-798','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','花半湿。',53,'宋词/ci.song.11000.json','["花半湿。", "一霎晚云笼密。", "天气未佳风又急。", "小庭愁独立。", "酒病起来无力。", "懊恼篆烟锁碧。", "一饷春情无处觅。", "小屏山数尺。"]'),
('song-ci-799','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','春夜雨。',53,'宋词/ci.song.11000.json','["春夜雨。", "催润柳塘花坞。", "小院深深门几许。", "画帘香一缕。", "独立晚庭凝伫。", "细把花枝闲数。", "燕子不来天欲暮。", "说愁无处所。"]'),
('song-ci-800','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','风阵阵。',53,'宋词/ci.song.11000.json','["风阵阵。", "吹落杨花无定。", "酒病厌厌三月尽。", "花檀红自隐。", "新绿轩窗清润。", "月影又移墙影。", "手拈青梅无处问。", "一春长闷损。"]'),
('song-ci-801','谒金门','程垓','宋','宋词','song-ci','谒金门','[]','浓睡醒。',53,'宋词/ci.song.11000.json','["浓睡醒。", "惊对一帘秋影。", "桐叶乍零风不定。", "半窗疏雨影。", "愁与年光不尽。", "老入星星双鬓。", "只拟上楼寻远信。", "雁遥烟水暝。"]'),
('song-ci-802','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','["\u897f\u6e56"]','日下船篷人未起。',70,'宋词/ci.song.11000.json','["日下船篷人未起。", "一个燕儿，说尽伤春意。", "江上残花能有几。", "风催雨促成容易。", "湖海客心千万里。", "著力东风，推得人行未。", "相次桃花三月水。", "菱歌谁伴西湖醉。"]'),
('song-ci-803','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','满路梅英飞雪粉。',70,'宋词/ci.song.11000.json','["满路梅英飞雪粉。", "临水人家，先得春光嫩。", "楼底杏花楼外影。", "墙东柳线墙西恨。", "撷翠揉红何处问。", "暖入眉峰，已作伤春困。", "归路月痕弯一寸。", "芳心只为东风损。"]'),
('song-ci-804','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','寒意勒花春未足。',72,'宋词/ci.song.11000.json','["寒意勒花春未足。", "只有东风，不管春拘束。", "杨柳满城吹又绿。", "可人青眼还相属。", "小叶星星眠未熟。", "看尽行人，唱彻《阳关曲》。", "心事一春何计续。", "芳条未展眉先蹙。"]'),
('song-ci-805','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','晴带溪光春自媚。',70,'宋词/ci.song.11000.json','["晴带溪光春自媚。", "绕翠萦青，来约东风醉。", "云补断山疏复缀。", "雨回绿野清还丽。", "拄杖不妨舒客意。", "临水人家，问有花开未。", "江左风流今有几。", "逢春不要人憔悴。"]'),
('song-ci-806','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','翠幕成阴帘拂地。',70,'宋词/ci.song.11000.json','["翠幕成阴帘拂地。", "池馆无人，四面生凉意。", "荷气竹香俱细细。", "分明著莫清风袂。", "玉枕如冰笙似水。", "才亸横钗，早被莺呼起。", "今夜月明人未睡。", "只消三四分来醉。"]'),
('song-ci-807','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','画阁红炉屏四向。',70,'宋词/ci.song.11000.json','["画阁红炉屏四向。", "梅拥寒香，次第侵帷帐。", "烛影半低花影幌。", "修眉正在花枝傍。", "殢粉偎香羞一饷。", "未识春风，已觉春情荡。", "醉里不知霜月上。", "归来已踏梅花浪。"]'),
('song-ci-808','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','楼角吹花烟月堕。',70,'宋词/ci.song.11000.json','["楼角吹花烟月堕。", "的皪韶研，又向梅心破。", "钗上采旛看一个。", "赏心已觉春生坐。", "莫恨年华风雨过。", "人日嬉游，次第连灯火。", "翠幄高张金盏大。", "已拼醉袖随香亸。"]'),
('song-ci-809','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','小院菊残烟雨细。',70,'宋词/ci.song.11000.json','["小院菊残烟雨细。", "天气凄凉，恼得人憔悴。", "被暖橙香羞早起。", "玉钗一任慵云坠。", "楼上珠帘钩也未。", "数尺遥山，供尽伤高意。", "伫立不禁残酒味。", "绣罗依旧和香睡。"]'),
('song-ci-810','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','小院秋光浓欲滴。',70,'宋词/ci.song.11000.json','["小院秋光浓欲滴。", "独自钩帘，细数归鸿翼。", "鸿断天高无处觅。", "矮窗催暝蛩催织。", "凉月去人才数尺。", "断发萧骚，醉傍西风立。", "愁眼望天收不得。", "露华衣上三更湿。"]'),
('song-ci-811','蝶恋花','程垓','宋','宋词','song-ci','蝶恋花','[]','晴日溪山春可数。',70,'宋词/ci.song.11000.json','["晴日溪山春可数。", "水绕池塘，知有人家住。", "寻日寻花花不语。", "旧时春恨还如许。", "苦恨东风无意绪。", "只解催花，不解催人去。", "日晚荒烟迷古戍。", "断魂正在梅花浦。"]'),
('song-ci-812','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','和风暖日西郊路。',52,'宋词/ci.song.11000.json','["和风暖日西郊路。", "游人又踏青山去。", "何处碧云衫。", "映溪才两三。", "疏松分翠黛。", "故作羞春态。", "回首杏烟消。", "月明归渡桥。"]'),
('song-ci-813','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','春回绿野烟光薄。',52,'宋词/ci.song.11000.json','["春回绿野烟光薄。", "低花矮柳田家乐。", "陇麦又青青。", "喧蜂闲趁人。", "野翁忘近远。", "怪识刘郎面。", "断却小桥溪。", "怕人溪外知。"]'),
('song-ci-814','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','画桥拍拍春江绿。',52,'宋词/ci.song.11000.json','["画桥拍拍春江绿。", "行人正在春江曲。", "花润接平川。", "有人花底眠。", "东风元自好。", "只怕催花老。", "安得万垂杨。", "系教春日长。"]'),
('song-ci-815','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','平芜冉冉连云绿。',52,'宋词/ci.song.11000.json','["平芜冉冉连云绿。", "斜阳衬雨明溪足。", "小鸭睡晴沙。", "翠烘三两花。", "春光闲婉娩。", "尽日无人见。", "试著小屏山。", "图归云际看。"]'),
('song-ci-816','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','山头翠树调莺舌。',52,'宋词/ci.song.11000.json','["山头翠树调莺舌。", "山腰野菜飞黄蝶。", "来为等闲休。", "去成多少愁。", "小庭花木改。", "犹有啼痕在。", "别后不曾看。", "怕花和泪残。"]'),
('song-ci-817','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','罗衫乍试寒犹怯。',52,'宋词/ci.song.11000.json','["罗衫乍试寒犹怯。", "妒花风雨连三月。", "灯冷闭门时。", "有愁谁得知。", "此情真个苦。", "只为当时语。", "莫道絮沾泥。", "絮飞魂亦飞。"]'),
('song-ci-818','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','夜来花底莺饶舌。',52,'宋词/ci.song.11000.json','["夜来花底莺饶舌。", "把人心事分明说。", "许大好因缘。", "只成容易传。", "春阑无好计。", "唯有归来是。", "从此玉台前。", "晓妆休太妍。"]'),
('song-ci-819','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','小窗荫绿清无暑。',52,'宋词/ci.song.11000.json','["小窗荫绿清无暑。", "篆香终日萦兰炷。", "冰簟涨寒涛。", "清风一枕高。", "有日团扇却。", "门掩庭花落。", "少待月侵床。", "教他魂梦凉。"]'),
('song-ci-820','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','暑庭消尽风鸣树。',52,'宋词/ci.song.11000.json','["暑庭消尽风鸣树。", "树鸣风尽消庭暑。", "横枕一声莺。", "莺声一枕横。", "扇纨低粉面。", "面粉低纨扇。", "凉月淡侵床。", "床侵淡月凉。"]'),
('song-ci-821','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','东风有意留人住。',52,'宋词/ci.song.11000.json','["东风有意留人住。", "熏风无意催人去。", "去住两茫然。", "相逢成短缘。", "平生花柳笑。", "过后关心少。", "今日奈情何。", "为伊饶恨多。"]'),
('song-ci-822','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','去年恰好双星节。',52,'宋词/ci.song.11000.json','["去年恰好双星节。", "鹊桥未渡人离别。", "不恨障云生。", "恨他真个行。", "天涯消息近。", "不见乘鸾影。", "楼外鹧鸪声。", "几回和梦惊。"]'),
('song-ci-823','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','浅寒带暝和烟下。',52,'宋词/ci.song.11000.json','["浅寒带暝和烟下。", "轻阴挟雨随风洒。", "翠幕护重帘。", "篆香销半奁。", "平生风雨夜。", "怕近芭蕉下。", "今夕定愁多。", "萧萧声奈何。"]'),
('song-ci-824','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','客窗曾剪灯花弄。',52,'宋词/ci.song.11000.json','["客窗曾剪灯花弄。", "谁教来去如春梦。", "冷落旧梅台。", "小桃相次开。", "人间春易老。", "只有山中好。", "闲却槿花篱。", "莫教溪外知。"]'),
('song-ci-825','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','晓烟笼日浮山翠。',52,'宋词/ci.song.11000.json','["晓烟笼日浮山翠。", "春风著水回川媚。", "远近碧重重。", "人家山色中。", "野花香自度。", "似识幽人处。", "安得著三间。", "与山终日闲。"]'),
('song-ci-826','菩萨蛮','程垓','宋','宋词','song-ci','菩萨蛮','[]','扶犁野老田东睡。',52,'宋词/ci.song.11000.json','["扶犁野老田东睡。", "插花山女田西醉。", "醉眼眩东西。", "看看桃满溪。", "耕桑山下足。", "纨绮人间俗。", "莫管旧东风。", "从教吹软红。"]'),
('song-ci-827','木兰花・玉楼春','程垓','宋','宋词','song-ci','木兰花・玉楼春','[]','疏枝半作窥窗老。',64,'宋词/ci.song.11000.json','["疏枝半作窥窗老。", "又是一年春意早。", "风低小院得香迟，月傍女墙和影好。", "去年苦被离情恼。", "今日逢花休草草。", "后时花紫尽从他，且趁先春拼醉倒。"]'),
('song-ci-828','鹧鸪天','程垓','宋','宋词','song-ci','鹧鸪天','[]','昨夜思量直到明。',64,'宋词/ci.song.11000.json','["昨夜思量直到明。", "拂明心绪更愁人。", "风披露叶高低怨，冷雨寒烟各自轻。", "休赖酒，莫求神。", "为谁教尔许多情。", "如今早被思量损，好更当时做弄成。"]'),
('song-ci-829','入塞','程垓','宋','宋词','song-ci','入塞','[]','好思量。',65,'宋词/ci.song.11000.json','["好思量。", "正秋风、半夜长。", "奈银缸一点，耿耿背西窗。", "衾又凉。", "枕又凉。", "露华凄凄月半床。", "照得人、真个断肠。", "窗前谁浸木犀黄。", "花也香。", "梦也香。"]'),
('song-ci-830','桃源忆故人','程垓','宋','宋词','song-ci','桃源忆故人','[]','粉霜拂拂凝香砌。',56,'宋词/ci.song.11000.json','["粉霜拂拂凝香砌。", "酝酿梅花天气。", "月上小窗如水。", "冷浸人无寐。", "平生可惯闲憔悴。", "担负新愁不起。", "消遣夜长无计。", "只倚熏香睡。"]'),
('song-ci-831','愁倚阑・春光好','程垓','宋','宋词','song-ci','愁倚阑・春光好','[]','春犹浅，柳初芽。',52,'宋词/ci.song.11000.json','["春犹浅，柳初芽。", "杏初花。", "杨柳杏花交影处，有人家。", "玉窗明暖烘霞。", "小屏上、水远山斜。", "昨夜酒多春睡重，莫惊他。"]'),
('song-ci-832','乌夜啼','程垓','宋','宋词','song-ci','乌夜啼','[]','静院槐风绿涨，小窗梅雨黄垂。',58,'宋词/ci.song.11000.json','["静院槐风绿涨，小窗梅雨黄垂。", "欲看春事留连处，惟有夜寒知。", "魂梦长闲消午醉，扫花共坐风凉。", "归来窗北有胡床。", "兴在羲皇以上。"]'),
('song-ci-833','忆秦娥','程垓','宋','宋词','song-ci','忆秦娥','[]','青门深。',56,'宋词/ci.song.11000.json','["青门深。", "海棠开尽春阴阴。", "春阴阴。", "万重云水，一寸归心。", "玉楼深锁烟消沈。", "知他何日同登临。", "同登临。", "待收红泪，细说如今。"]'),
('song-ci-834','忆秦娥','程垓','宋','宋词','song-ci','忆秦娥','[]','情脉脉。',56,'宋词/ci.song.11000.json','["情脉脉。", "半黄橙子和香擘。", "和香擘。", "分明记得，袖香熏窄。", "别来人远关山隔。", "见梅不忍和花摘。", "和花摘。", "有书无雁，寄谁归得。"]'),
('song-ci-835','忆秦娥','程垓','宋','宋词','song-ci','忆秦娥','[]','愁无语。',52,'宋词/ci.song.11000.json','["愁无语。", "黄昏庭院黄梅雨。", "黄梅雨。", "新愁一寸，旧愁千缕。", "杜鹃叫断空山苦。", "相思欲计人何许。", "一重云断，一重山阻。"]'),
('song-ci-836','西江月','程垓','宋','宋词','song-ci','西江月','[]','众绿初围夏荫，老红犹驻春妆。',58,'宋词/ci.song.11000.json','["众绿初围夏荫，老红犹驻春妆。", "画帘燕子日偏长。", "静看新雏来往。", "□□□□□□，□□□□□□。", "□□□□□□□。", "□□□□□□。"]'),
('song-ci-837','西江月','程垓','宋','宋词','song-ci','西江月','[]','□□□□□□，□□□□□□。',59,'宋词/ci.song.11000.json','["□□□□□□，□□□□□□。", "□□□□□□□。", "□□□□□□。", "汲井漫随兰炷，心情半怯罗衣。", "粉香消尽无人觑，只门外、子规啼。"]'),
('song-ci-838','乌夜啼','程垓','宋','宋词','song-ci','乌夜啼','[]','墙外雨肥梅子，阶前水绕荷花。',60,'宋词/ci.song.11000.json','["墙外雨肥梅子，阶前水绕荷花。", "阴阴庭户熏风满，水纹簟、怯菱芽。", "春尽难凭燕语，日长惟有蜂卫。", "沈香火冷珠帘暮，个人在、碧窗纱。"]'),
('song-ci-839','浣溪沙','程垓','宋','宋词','song-ci','浣溪沙','[]','天女殷勤著意多。',48,'宋词/ci.song.11000.json','["天女殷勤著意多。", "散花犹记病维摩。", "肯来丈室问云何。", "腰佩摘来烦玉笋，鬓香分处想秋波。", "不知真个有情麽。"]'),
('song-ci-840','浣溪沙','程垓','宋','宋词','song-ci','浣溪沙','[]','遥想当年出凤雏。',48,'宋词/ci.song.11000.json','["遥想当年出凤雏。", "王□风有未全疏。", "祗今朱绂为谁纡。", "芳草池塘春梦后，粉香帘幕晓晴初。", "一簪华发要人梳。"]'),
('song-ci-841','浣溪沙','程垓','宋','宋词','song-ci','浣溪沙','[]','翠葆扶疏傍药阑。',48,'宋词/ci.song.11000.json','["翠葆扶疏傍药阑。", "乱红飘洒满书单。", "清明时节又看看。", "小雨勒成春尾恨，东风偏作夜来寒。", "琴心老尽不须弹。"]'),
('song-ci-842','浣溪沙','程垓','宋','宋词','song-ci','浣溪沙','[]','薄日移影午暑空。',48,'宋词/ci.song.11000.json','["薄日移影午暑空。", "一杯何事便潮红。", "扇纨挥尽却疏慵。", "早睡青怀冰枕外，夜来消息雨荷中。", "不须留烛眩房栊。"]'),
('song-ci-843','浣溪沙','程垓','宋','宋词','song-ci','浣溪沙','[]','闲倚前荣小扇车。',48,'宋词/ci.song.11000.json','["闲倚前荣小扇车。", "晚妆无力亸云鸦。", "凝情香落一庭花。", "笑挽清风归玉枕，懒随缺月傍窗纱。", "羞红两脸上娇霞。"]'),
('song-ci-844','鹧鸪天','程垓','宋','宋词','song-ci','鹧鸪天','[]','木落江空又一秋。',64,'宋词/ci.song.11000.json','["木落江空又一秋。", "天寒几日不登楼。", "红绡帐里橙犹在，青琐窗深菊未收。", "新画阁，小书舟。", "篆烟熏得晚香留。", "只因贪伴开炉酒，恼得红儿一夜讴。"]'),
('song-ci-845','鹧鸪天','程垓','宋','宋词','song-ci','鹧鸪天','[]','泪湿芙蓉城上花。',64,'宋词/ci.song.11000.json','["泪湿芙蓉城上花。", "片飞何事苦参差。", "锁深不奈莺无语，巢稳争如燕有家。", "情未老，鬓先华。", "可怜各自淡生涯。", "桃花不解知人意，犹自沾泥也学他。"]'),
('song-ci-846','一落索','程垓','宋','宋词','song-ci','一落索','[]','门外莺寒杨柳。',58,'宋词/ci.song.11000.json','["门外莺寒杨柳。", "正减欢疏酒。", "春阴早是做人愁，更何况、花飞后。", "莫倚东风消瘦。", "有酴醿入手。", "尽偎香玉醉何妨，任花落、愁依旧。"]'),
('song-ci-847','一落索','程垓','宋','宋词','song-ci','一落索','[]','小小腰身相称。',58,'宋词/ci.song.11000.json','["小小腰身相称。", "更著人心性。", "一声歌起绣帘阴，都遏住、行云影。", "闻道玉郎家近。", "被春风勾引。", "从今莫怪一东看，自压尽、人间韵。"]'),
('song-ci-848','破阵子','程垓','宋','宋词','song-ci','破阵子','[]','小小红泥院宇，深深翠色屏帷。',72,'宋词/ci.song.11000.json','["小小红泥院宇，深深翠色屏帷。", "簇定熏炉酥酒软，门外东风寒不知。", "恰疑三月时。", "钗影半欹绿子，歌声轻度红儿。", "醉里不愁更漏断，更要梅花看几枝。", "起来霜月低。"]'),
('song-ci-849','一翦梅','程垓','宋','宋词','song-ci','一翦梅','[]','斗转参横一夜霜。',72,'宋词/ci.song.11000.json','["斗转参横一夜霜。", "玉律声中，又报新阳。", "起来无绪赋行藏。", "只喜人间，一线添长。", "帘幕垂垂月半廊。", "节物心情，都付椒觞。", "年华渐晚鬓毛苍。", "身外功名，休苦思量。"]'),
('song-ci-850','木兰花・玉楼春','程垓','宋','宋词','song-ci','木兰花・玉楼春','[]','别时已有重来愿。',64,'宋词/ci.song.11000.json','["别时已有重来愿。", "谁料情多天不管。", "分明咫尺是青楼，抵死浓云遮得遍。", "寄声只倚西飞雁。", "雁落书回空是怨。", "领愁归去有谁知，水又茫茫山又断。"]'),
('song-ci-851','生查子','程垓','宋','宋词','song-ci','生查子','[]','兰帷夜色高，绣被春寒拥。',48,'宋词/ci.song.11000.json','["兰帷夜色高，绣被春寒拥。", "何事玉楼人，屡踏杨花梦。", "分明相见陈，不道幽情重。", "乞个好因缘，莫待来生种。"]'),
('song-ci-852','满庭芳','虞俦','宋','宋词','song-ci','满庭芳','[]','色染莺黄，枝横鹤瘦，玉奴蝉蜕花间。',118,'宋词/ci.song.11000.json','["色染莺黄，枝横鹤瘦，玉奴蝉蜕花间。", "铅华不御，慵态尽欹鬟。", "冷淡琐窗烟雾，来清供、莞尔怡颜。", "狂蜂蝶，还须敛衽，何得傍高闲。", "西山。", "招隐处，寒云缭绕，流水回环。", "念风前绰约，雪后清孱。", "别是仙韵道标，应羞对、舞袖弓弯。", "怀真赏，今宵归梦，一饷许跻攀。"]'),
('song-ci-853','临江仙','虞俦','宋','宋词','song-ci','临江仙','[]','万壑千岩秋色里，歌眉醉眼争妍。',70,'宋词/ci.song.11000.json','["万壑千岩秋色里，歌眉醉眼争妍。", "一枝娇柳趁么弦。", "疑非香案吏，诏到小蓬天。", "乐事便成陈迹也，依人小月娟娟。", "尊前空唱短因缘。", "引船风又起，吹过浙江边。"]'),
('song-ci-854','阮郎归','徐似道','宋','宋词','song-ci','阮郎归','[]','茶寮山上一头陀。',56,'宋词/ci.song.11000.json','["茶寮山上一头陀。", "新来学者麽。", "蝤蛑螃蟹与乌螺。", "知他放几多。", "有一物，是蜂窝。", "姓牙名老婆。", "虽然无奈得它何。", "如何放得它。"]'),
('song-ci-855','浪淘沙','徐似道','宋','宋词','song-ci','浪淘沙','[]','风紧浪淘生。',64,'宋词/ci.song.11000.json','["风紧浪淘生。", "蛟吼鼍鸣。", "家人睡著怕人惊。", "只有一翁扪虱坐，依约三更。", "雪又打残灯。", "欲暗还明。", "有谁知我此时情。", "独对梅花倾一盏，还又诗成。"]'),
('song-ci-856','瑞鹤仙令・临江仙','徐似道','宋','宋词','song-ci','瑞鹤仙令・临江仙','["\u897f\u6e56"]','西子湖边春正好，输他公子王孙。',70,'宋词/ci.song.11000.json','["西子湖边春正好，输他公子王孙。", "落花香趁马蹄温。", "暖烟桃叶渡，晴日柳枝门。", "中有能诗狂处士，闲将一鹤随轩。", "百钱买只下湖船。", "就他弦管里，醉过杏花天。"]'),
('song-ci-857','一剪梅・一翦梅','徐似道','宋','宋词','song-ci','一剪梅・一翦梅','[]','道学从来不则声。',72,'宋词/ci.song.11000.json','["道学从来不则声。", "行也东铭。", "坐也西铭。", "爷娘死后更伶丁。", "也不看经。", "也不斋僧。", "却言渊子太狂生。", "行也轻轻。", "坐也轻轻。", "他年青史总无名。", "你也能亨。", "我也能亨。"]'),
('song-ci-858','失调名','徐似道','宋','宋词','song-ci','失调名','[]','问竹平安，点花番次。',10,'宋词/ci.song.11000.json','["问竹平安，点花番次。"]'),
('song-ci-859','蓦山溪','徐安国','宋','宋词','song-ci','蓦山溪','[]','青梅骨瘦，已有生春意。',100,'宋词/ci.song.11000.json','["青梅骨瘦，已有生春意。", "椒萼露微花，便觉香魂旖旎。", "惜花公子，可是赋情深，携瘦竹，绕疏篱，终日成孤倚。", "赏心乐事，又也何曾废。", "烟露湿铅华，误啼妆、三年客里。", "江南芳信，政自不愆期，吴山远，越山长，梦寐添憔悴。"]'),
('song-ci-860','鹧鸪天','徐安国','宋','宋词','song-ci','鹧鸪天','[]','翠幕围香夜正迟。',64,'宋词/ci.song.11000.json','["翠幕围香夜正迟。", "红麟生焰烛交辉。", "纤腰趁拍轻於柳，娇面添妆韵似梅。", "凝远恨，惜芳期。", "十年幽梦彩云飞。", "多情不管霜髯满，犹欲杯翻似旧时。"]'),
('song-ci-861','满江红','徐安国','宋','宋词','song-ci','满江红','[]','挥手华堂，重整顿、选花场屋。',115,'宋词/ci.song.11000.json','["挥手华堂，重整顿、选花场屋。", "撩鼻观、飞浮杂沓，异香芬馥。", "金缕尚馀闲态度，冰姿早作新妆束。", "恨尊前、缺典费思量，无松竹。", "蜂蝶恨，何时足。", "桃李怨，成粗俗。", "为情深、拼了一生愁独。", "菊信谩劳频探问，兰心未许相随逐。", "想从今、无暇斸蔷薇，锄罂粟。"]'),
('song-ci-862','满江红','徐安国','宋','宋词','song-ci','满江红','[]','争献交酬，消受取、真山真水。',115,'宋词/ci.song.11000.json','["争献交酬，消受取、真山真水。", "供不尽、杯螺浮碧，髻鬟拥翠。", "莫便等闲嗟去国，固因特地经仙里。", "奉周旋、惟有老先生，门堪倚。", "追往驾，烟宵里。", "终旧学，今无计。", "叹白头犹记，壮年标致。", "一乐堂深文益著，风雩亭在词难继。", "问有谁、熟识晦庵心，南轩意。"]'),
('song-ci-863','祝英台・祝英台近','黄人杰','宋','宋词','song-ci','祝英台・祝英台近','[]','异乡中，行色里，随分庆初度。',95,'宋词/ci.song.11000.json','["异乡中，行色里，随分庆初度。", "老子今年，五十又还五。", "任他坎止流行，吴头楚尾，本来是、乾坤逆旅。", "贵和富。", "此事都付浮云，无必也无固。", "用即为龙，不用即为鼠。", "便教老却英雄，草庐烟舍，也须有、著闲人处。"]'),
('song-ci-864','酹江月・念奴娇','黄人杰','宋','宋词','song-ci','酹江月・念奴娇','[]','年时今日，御双凫曾到、蓬壶方丈。',120,'宋词/ci.song.11000.json','["年时今日，御双凫曾到、蓬壶方丈。", "元是王孙生此夕，红紫娇春成行。", "数曲栏干，一双蓂荚，正傍瑶阶长。", "风帘斜处，有时新燕来往。", "犹记不住称觞，挥毫著语，更与书扁榜。", "转首还逢汤饼客，景物依然和畅。", "待赋新词，说些消息，教倩飞琼唱。", "南班虚席，看随丹诏东上。"]'),
('song-ci-865','感皇恩','黄人杰','宋','宋词','song-ci','感皇恩','["\u897f\u6e56"]','秋色满西湖，雨添新绿。',81,'宋词/ci.song.11000.json','["秋色满西湖，雨添新绿。", "一派烟光望中足。", "清香十里，画舸去来相逐。", "酒酣时听得，渔家曲。", "人道似郎，郎还第六。", "云水相逢未谙熟。", "晚来风静，闲浸几枝红玉。", "水神应不禁，江妃浴。"]'),
('song-ci-866','念奴娇','黄人杰','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','西湖胜绝，有栖云楼观，蟠空丘壑。',120,'宋词/ci.song.11000.json','["西湖胜绝，有栖云楼观，蟠空丘壑。", "玉鉴光中天不老，人在蓬壶行乐。", "画舫藏春，垂杨系马，幽处笙箫作。", "京华狂客，也忘身世飘泊。", "行时载酒寻芳，湖湾堤曲，放浪红尘脚。", "借景留欢排日醉，不负莺花盟约。", "忍缓东风，耐烦迟日，休恁匆匆著。", "温存桃李，莫教一顿开却。"]'),
('song-ci-867','浣溪沙','黄人杰','宋','宋词','song-ci','浣溪沙','[]','的皪江梅共蜡梅。',48,'宋词/ci.song.11000.json','["的皪江梅共蜡梅。", "剪金裁玉一时开。", "黄姑相伴雪儿来。", "别驾公馀无个事，得将诗酒与栽培。", "为春留客小徘徊。"]'),
('song-ci-868','生查子','黄人杰','宋','宋词','song-ci','生查子','[]','烟雨不多时，肥得梅如许。',48,'宋词/ci.song.11000.json','["烟雨不多时，肥得梅如许。", "早有点儿酸，诮没星儿苦。", "飞燕恶禁持，又待衔春去。", "容著水精盐，觅个调羹处。"]'),
('song-ci-869','柳梢青','黄人杰','宋','宋词','song-ci','柳梢青','[]','恰则年时。',61,'宋词/ci.song.11000.json','["恰则年时。", "风前雪底，初见南枝。", "可㬠匆匆，花才清瘦，子已红肥。", "安排酒盏相随。", "看金弹、累累四垂。", "渴后情怀，鼎中风味，惟有心知。"]'),
('song-ci-870','蓦山溪','黄人杰','宋','宋词','song-ci','蓦山溪','[]','翠环惊报，叶底梅如弹。',102,'宋词/ci.song.11000.json','["翠环惊报，叶底梅如弹。", "小摘试尝看，齿微酸、生香不断。", "烟丸露颗，肥得颊儿红，还欲近，浅黄时，风雨催残半。", "何如珍重，剩著冰盘荐。", "持酒劝飞仙，似江梅、累累子满。", "饶将风味，成就与东君，随鼎鼐，著形盐，早趁调羹便。"]'),
('song-ci-871','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','小队旌旗，又催送、元戎领客。',115,'宋词/ci.song.11000.json','["小队旌旗，又催送、元戎领客。", "政十顷、荷香微度，草烟横碧。", "杨柳参差新合翠，水天上下俱齐色。", "傍野桥、容与绕重湖，严城侧。", "花作阵，舟为宅。", "敲羯鼓，鸣羌笛。", "渐夜凉风进，酒杯无力。", "遥想汉中鸡肋地，未应万里回金勒。", "看便随、飞诏下南州，朝京国。"]'),
('song-ci-872','点绛唇','蔡戡','宋','宋词','song-ci','点绛唇','[]','纤手工夫，采丝五色交相映。',50,'宋词/ci.song.11000.json','["纤手工夫，采丝五色交相映。", "同心端正。", "上有双鸳并。", "皓腕轻缠，结就相思病。", "凭谁信。", "玉肌宽尽。", "却系心儿紧。"]'),
('song-ci-873','水调歌头','蔡戡','宋','宋词','song-ci','水调歌头','[]','肃霜靡衰草，骤雨洗寒空。',114,'宋词/ci.song.11000.json','["肃霜靡衰草，骤雨洗寒空。", "刀弓斗力增劲，万马骤西风。", "细看外围合阵，忽变横斜曲直，妙在指麾中。", "号令肃诸将，谈笑听元戎。", "坐中客，休笑我，已衰翁。", "十年重到，今日此会与谁同。", "差把龙锺鹤发，来对虎头燕颔，年少总英雄。", "飞镞落金碗，酣醉吸长虹。"]'),
('song-ci-874','水调歌头','蔡戡','宋','宋词','song-ci','水调歌头','[]','拥节出闽峤，易镇上岷山。',114,'宋词/ci.song.11000.json','["拥节出闽峤，易镇上岷山。", "东西崄岨，分陕初不在荣观。", "痛念两河未复，独作中流砥柱，屹若障狂澜。", "极目神京远，百万虎貔闲。", "趁良时，摅豹略，勇声欢。", "风飞雷厉，威行逆虏胆生寒。", "汉寝周原如旧，一扫腥膻丑类，谈笑定三关。", "识取投机会，莫作等闲看。"]'),
('song-ci-875','鹧鸪天','何澹','宋','宋词','song-ci','鹧鸪天','[]','庾岭移来傍桂丛。',64,'宋词/ci.song.11000.json','["庾岭移来傍桂丛。", "绕花安敢望凌风。", "癯儒合作孤芳伴，四面相看一笑同。", "冰照座，玉横空。", "雪花零落暗香中。", "有人醉倚阑干畔，付与江南老画工。"]'),
('song-ci-876','桃源忆故人','何澹','宋','宋词','song-ci','桃源忆故人','[]','拍堤芳草随人去。',55,'宋词/ci.song.11000.json','["拍堤芳草随人去。", "洞口山无重数。", "翦朝露成树。", "争晚渔翁住。", "今人忍听秦人语。", "只有花无今古。", "欲饮仙家寿醑。", "记取桥边路。"]'),
('song-ci-877','满江红','何澹','宋','宋词','song-ci','满江红','[]','灯夕筵开，人物共、英词三绝。',115,'宋词/ci.song.11000.json','["灯夕筵开，人物共、英词三绝。", "环坐处、袖中珠玉，郢中春雪。", "红烛星繁销夜漏，紫霞香满催歌拍。", "算新年、何处不风光，三山别。", "云表殿，千层结。", "花籍锦，添明月。", "更浮屠七塔，万枝争发。", "多谢一天驱宿霭，故教三日成佳节。", "更何须、海上觅蓬莱，真仙阙。"]'),
('song-ci-878','满江红','何澹','宋','宋词','song-ci','满江红','[]','乐禁初开，平地耸、海山清绝。',115,'宋词/ci.song.11000.json','["乐禁初开，平地耸、海山清绝。", "千里内、欢声和气，可融霜雪。", "盛事终将椽笔记，新歌翻入梨园拍。", "道古来、南国做元宵，今宵别。", "灯万碗，花千结。", "星斗上，天浮月。", "向玉绳低处，笙箫高发。", "人物尽夸长乐郡，儿童争庆烧灯节。", "疑此身、清梦到华胥，朝金阙。"]'),
('song-ci-879','鹧鸪天','何澹','宋','宋词','song-ci','鹧鸪天','[]','好景良辰造物悭。',64,'宋词/ci.song.11000.json','["好景良辰造物悭。", "一年灯火遽摧残。", "雨淋夹道星千点，雪阻游人路九盘。", "停社舞，撤宾筵。", "谩烧银烛照金莲。", "不如我入香山社，一盏青灯说夜禅。"]'),
('song-ci-880','满江红','陈三聘','宋','宋词','song-ci','满江红','[]','薄日轻云，天气好、相将祈谷。',115,'宋词/ci.song.11000.json','["薄日轻云，天气好、相将祈谷。", "民情喜、颂声洋溢，清风斯穆。", "饮酒不多元有量，吟诗无数添新轴。", "对古人、一笑我真愚，君无俗。", "斜川路，经行熟。", "黄花在，归心足。", "问渊明去后，有谁能属。", "神武衣冠惊梦里，江湖渔钓论心曲。", "但从今、散发更披襟，谁能束。"]'),
('song-ci-881','满江红','陈三聘','宋','宋词','song-ci','满江红','[]','天岂无情，天若道、有情也老。',115,'宋词/ci.song.11000.json','["天岂无情，天若道、有情也老。", "功名事、问天因甚，蒙人不了。", "好伴云烟耕谷口，休将翰墨传江表。", "算鬓边、能得几春风，惊秋早。", "陶令尹，张京兆。", "怀舒啸，贪荣耀。", "尽南柯一梦，漏残钟晓。", "滕阁暮霞孤鹜举，庾楼明月乌飞绕。", "念老来、於此兴无穷，知音少。"]'),
('song-ci-882','满江红','陈三聘','宋','宋词','song-ci','满江红','[]','绀縠浮空，山拥髻、晚来风急。',115,'宋词/ci.song.11000.json','["绀縠浮空，山拥髻、晚来风急。", "吹骤雨、藕花千柄，艳妆新浥。", "窥鉴粉光犹有泪，凌波罗袜何曾湿。", "讶汉宫、朝罢玉皇归，凝情立。", "尊前恨，歌三叠。", "身外事，轻飞叶。", "怅当年空击，誓江孤楫。", "云色远连平野尽，夕阳偏傍疏林入。", "看月明、冷浸碧琉璃，君须吸。"]'),
('song-ci-883','满江红','陈三聘','宋','宋词','song-ci','满江红','[]','斜日熔金，三万顷、棹歌齐举。',115,'宋词/ci.song.11000.json','["斜日熔金，三万顷、棹歌齐举。", "风不动、采苹双桨，翠鬟相语。", "月殿欲浮蟾兔魄，海神不放鱼龙舞。", "到今宵、秋气十分清，无今古。", "君试唤，扁舟侣。", "来伴我，潇湘渚。", "共夷犹春浪，笑歌秋浦。", "霸越独高身退后，尘缨未濯人谁许。", "叹酒杯、不到子陵台，刘伶土。"]'),
('song-ci-884','千秋岁','陈三聘','宋','宋词','song-ci','千秋岁','[]','当年渔隐，路转桃溪汇。',87,'宋词/ci.song.11000.json','["当年渔隐，路转桃溪汇。", "流水下，青山外。", "客行花径曲，月上松门对。", "撑艇子，雪中蓑笠亲曾载。", "老去谁倾盖。", "腰瘦频移带。", "人健否，花仍在。", "明年春更好，来向花前醉。", "青鬓改，恁时难拼千金买。"]'),
('song-ci-885','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','酒力先从脸晕生。',48,'宋词/ci.song.11000.json','["酒力先从脸晕生。", "粉妆新丽笑相迎。", "晓寒高护彩云轻。", "不语似愁春力浅，有情应恨烛花明。", "更於何处觅倾城。"]'),
('song-ci-886','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','翠幕遮笼锦一丛。',48,'宋词/ci.song.11000.json','["翠幕遮笼锦一丛。", "尊前初见浅深红。", "淡云和月影葱茏。", "醉态只疑春睡里，啼妆愁听雨声中。", "更烧银烛醉东风。"]'),
('song-ci-887','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','不怕春寒更出游。',48,'宋词/ci.song.11000.json','["不怕春寒更出游。", "兰桡飞动却惊鸥。", "烟光佳处辄迟留。", "屏曲未曾歌醉梦，眉尖空只锁闲愁。", "从教丝柳绊行舟。"]'),
('song-ci-888','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','越浦潮来信息通。',48,'宋词/ci.song.11000.json','["越浦潮来信息通。", "吴山不见暮云重。", "人生何事各西东。", "烟外好花红浅淡，雨馀芳草绿葱茏。", "苦无欢意敌春浓。"]'),
('song-ci-889','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','点检尊前花柳丛。',48,'宋词/ci.song.11000.json','["点检尊前花柳丛。", "於中偏占牡丹风。", "等闲言语惯迎逢。", "扇影不摇珠的皪，钗梁斜亸玉玲珑。", "梦魂长向楚江东。"]'),
('song-ci-890','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','不跃银鞍与绣鞯。',48,'宋词/ci.song.11000.json','["不跃银鞍与绣鞯。", "曲筇芒跷见衰年。", "寻幽来立渡头船。", "碧涧芹羹珍下箸，红莲香饭乐归田。", "不妨尊酒兴悠然。"]'),
('song-ci-891','浣溪沙','陈三聘','宋','宋词','song-ci','浣溪沙','[]','帘押低垂月影疏。',48,'宋词/ci.song.11000.json','["帘押低垂月影疏。", "梅枝和雪玉相扶。", "儿家春信入来无。", "半坠宝钗慵览镜，任偏罗髻却拈书。", "琴心谁与问相如。"]'),
('song-ci-892','朝中措','陈三聘','宋','宋词','song-ci','朝中措','[]','朝来和气满西山。',57,'宋词/ci.song.11000.json','["朝来和气满西山。", "拄颊小阑干。", "柳色野塘幽兴，梅花纸帐轻寒。", "三杯淡酒，玉腴蔬嫩，青缕堆盘。", "细写池塘诗梦，玉人翦做春幡。"]'),
('song-ci-893','朝中措','陈三聘','宋','宋词','song-ci','朝中措','[]','求田何处是生涯。',57,'宋词/ci.song.11000.json','["求田何处是生涯。", "双鬓已先华。", "随分夏凉冬暖，赏心秋月春花。", "吾年如此，愁来问酒，困后呼茶。", "结社竹林诗老，卜邻江上渔家。"]'),
('song-ci-894','朝中措','陈三聘','宋','宋词','song-ci','朝中措','[]','去年曾醉杏花坊。',57,'宋词/ci.song.11000.json','["去年曾醉杏花坊。", "柳色间轻黄。", "重觅旧时行迹，春风满路梅香。", "平沙岸草，夫差故国，知是吾乡。", "梦断数声柔橹，只应已过横塘。"]'),
('song-ci-895','朝中措','陈三聘','宋','宋词','song-ci','朝中措','["\u897f\u6e56"]','草堂春过一分馀。',57,'宋词/ci.song.11000.json','["草堂春过一分馀。", "幽事酒醒初。", "琴调细鸣焦木，矢声不断铜壶。", "关心药裹，忘年蓑笠，自著潜夫。", "雨后长镵东麓，月明短艇西湖。"]'),
('song-ci-896','朝中措','陈三聘','宋','宋词','song-ci','朝中措','[]','秋山横截半湖光。',57,'宋词/ci.song.11000.json','["秋山横截半湖光。", "湖渚橘枝黄。", "纨扇罢摇蟾影，练衣已怯风凉。", "插红裂蟹，银丝鲙鲫，莫负传觞。", "醉里乾坤广大，人间宠辱兼忘。"]'),
('song-ci-897','蝶恋花','陈三聘','宋','宋词','song-ci','蝶恋花','[]','阊阖城西山四面。',70,'宋词/ci.song.11000.json','["阊阖城西山四面。", "鸭绿鳞鳞，轻拍横塘岸。", "一阵东风羊角转。", "望中已觉孤帆远。", "独恨寻芳来较晚。", "柘老桑稠，农务村村遍。", "山鸟劝酤官酒贱。", "炊烟深巷听缫茧。"]'),
('song-ci-898','南柯子・南歌子','陈三聘','宋','宋词','song-ci','南柯子・南歌子','[]','别后惊人远，归心怯橹柔。',62,'宋词/ci.song.11000.json','["别后惊人远，归心怯橹柔。", "晚天凉思冷於秋。", "冷浸一溪明月、水弥流。", "醉里狂仍在，吟馀趣极幽。", "夜深何用数更筹。", "别有好风吹酒、不须求。"]'),
('song-ci-899','南柯子・南歌子','陈三聘','宋','宋词','song-ci','南柯子・南歌子','[]','烟树观前浦，风苹听远洲。',62,'宋词/ci.song.11000.json','["烟树观前浦，风苹听远洲。", "等闲来上水边楼。", "怅望天涯、何处有归舟。", "香断灯花夜，歌停扇影秋。", "欲缄尺素说离愁。", "不见双鱼、空有大江流。"]'),
('song-ci-900','南柯子・南歌子','陈三聘','宋','宋词','song-ci','南柯子・南歌子','[]','月傍云头吐，风将雨脚吹。',62,'宋词/ci.song.11000.json','["月傍云头吐，风将雨脚吹。", "夜深乌鹊向南飞。", "应是星娥颦恨、入双眉。", "旧怨垂千古，新欢只片时。", "一年屈指数佳期。", "到得佳期别了、又相思。"]'),
('song-ci-901','水调歌头','陈三聘','宋','宋词','song-ci','水调歌头','[]','玉鉴十分满，清露一年秋。',114,'宋词/ci.song.11000.json','["玉鉴十分满，清露一年秋。", "漂流踪迹，谁念楚尾与吴头。", "此夜刮明尘眼。", "望极好张诗胆。", "何处有高楼。", "浩荡银潢冷，缥缈白云浮。", "笑劳生，难坎止，亦乘流。", "阑干拍碎，清夜起舞不胜愁。", "万里关河依旧。", "一寸功名乌有。", "清泪滴衣裘。", "老去心空在，归梦绕苹洲。"]'),
('song-ci-902','水调歌头','陈三聘','宋','宋词','song-ci','水调歌头','[]','有客念行役，劲气凛於秋。',114,'宋词/ci.song.11000.json','["有客念行役，劲气凛於秋。", "男儿未老，衔命如虏亦风流。", "决定平戎方略，恢复旧燕封壤，安用割鸿沟。", "莫献肃霜马，好衣白狐裘。", "我何人，怀壮节，但凝愁。", "平生未逢知己，哙伍实堪羞。", "金马文章何在，玉鼎勋庸何有，一笑等云浮。", "拼断好风月，羯鼓打梁州。"]'),
('song-ci-903','西江月','陈三聘','宋','宋词','song-ci','西江月','[]','诗眼曾逢花面，画图还识春娇。',58,'宋词/ci.song.11000.json','["诗眼曾逢花面，画图还识春娇。", "当年风格太妖饶。", "粉腻酥柔更好。", "酒晕不温香脸，玉慵犹怯轻绡。", "春风别后又秋高。", "再见只应人老。"]'),
('song-ci-904','西江月','陈三聘','宋','宋词','song-ci','西江月','[]','春事已浓多日，游人偏盛今年。',58,'宋词/ci.song.11000.json','["春事已浓多日，游人偏盛今年。", "梨花寒食雨馀天。", "鸭绿含风浪浅。", "翠袖半黏飞粉，罗衣尚怯轻寒。", "不辞归路委香钿。", "门外东风如箭。"]'),
('song-ci-905','鹊桥仙','陈三聘','宋','宋词','song-ci','鹊桥仙','[]','银潢仙仗，离多会少，朝暮世情休妒。',68,'宋词/ci.song.11000.json','["银潢仙仗，离多会少，朝暮世情休妒。", "夜深风露洒然秋，又莫是、轻分泪雨。", "云收雾散，漏残更尽，遥想双星情绪。", "凭谁批敕诉天公，待留住、今宵休去。"]'),
('song-ci-906','宜男草','陈三聘','宋','宋词','song-ci','宜男草','[]','摇落丹枫素秋后。',74,'宋词/ci.song.11000.json','["摇落丹枫素秋后。", "舞长亭、尚馀衰柳。", "别梦回、忆得霜柑分我，应自有、浓香噀手。", "宿酲谁解三杯酒。", "晓山横、望中衔斗。", "人去也、纵得相逢似旧，问当日、红颜在否。"]'),
('song-ci-907','宜男草','陈三聘','宋','宋词','song-ci','宜男草','[]','绿水黏天净无浪。',72,'宋词/ci.song.11000.json','["绿水黏天净无浪。", "转东风、縠纹微涨。", "个中趣、莫遣人知，容我日日、扁舟独往。", "平生书癖已无恙。", "解名缰、更逃羁网。", "春近也、梅柳频看，枝上玉蕊、金丝暗长。"]'),
('song-ci-908','秦楼月・忆秦娥','陈三聘','宋','宋词','song-ci','秦楼月・忆秦娥','[]','云衣薄。',56,'宋词/ci.song.11000.json','["云衣薄。", "春晴自有东风掠。", "东风掠。", "试听枝上，几声乾鹊。", "曲屏心事新题却。", "离愁何用堆眉角。", "堆眉角。", "今朝莫是，打头风恶。"]'),
('song-ci-909','秦楼月・忆秦娥','陈三聘','宋','宋词','song-ci','秦楼月・忆秦娥','[]','花前狭。',56,'宋词/ci.song.11000.json','["花前狭。", "翠茵围坐花阴合。", "花阴合。", "闲情不似，一双狂蝶。", "春沟何处寻红叶。", "春寒料想罗衣怯。", "罗衣怯。", "午醺醒未，翠衾重叠。"]'),
('song-ci-910','秦楼月・忆秦娥','陈三聘','宋','宋词','song-ci','秦楼月・忆秦娥','[]','光风薄。',56,'宋词/ci.song.11000.json','["光风薄。", "杨花欲谢春应觉。", "春应觉。", "一庭红叶，粉花吹落。", "冶游无复飞红索。", "凭高独上湖边阁。", "湖边阁。", "黄昏独倚，画阑西角。"]'),
('song-ci-911','秦楼月・忆秦娥','陈三聘','宋','宋词','song-ci','秦楼月・忆秦娥','[]','青楼缺。',56,'宋词/ci.song.11000.json','["青楼缺。", "楼心人待黄昏月。", "黄昏月。", "入帘无奈，柳绵吹雪。", "谁人弄笛声呜咽。", "伤春未解丁香结。", "丁香结。", "鳞鸿何处，路遥江阔。"]'),
('song-ci-912','秦楼月・忆秦娥','陈三聘','宋','宋词','song-ci','秦楼月・忆秦娥','[]','青膏集。',56,'宋词/ci.song.11000.json','["青膏集。", "新雷忽起龙蛇蛰。", "龙蛇蛰。", "柳塘风快，水流声急。", "伤心有泪凭谁浥。", "尊前容易青衫湿。", "青衫湿。", "渡头人去，野船鸥立。"]'),
('song-ci-913','念奴娇','陈三聘','宋','宋词','song-ci','念奴娇','[]','浮云吹尽，卷长空、千顷都凝寒碧。',120,'宋词/ci.song.11000.json','["浮云吹尽，卷长空、千顷都凝寒碧。", "兔杵无声风露冷，天也应怜人寂。", "故遣姮娥，驾蟾飞上，玉宇元同色。", "天津何事，此时偏界南北。", "不但对影三人，我歌君和，我舞君须拍。", "涤洗胸中愁万斛，莫问今宵何夕。", "老矣休论，著鞭安用，一笑真狂客。", "夜深归去，烂然溪上阡陌。"]'),
('song-ci-914','念奴娇','陈三聘','宋','宋词','song-ci','念奴娇','[]','晴风丽日，算东君、坼遍梅心桃萼。',120,'宋词/ci.song.11000.json','["晴风丽日，算东君、坼遍梅心桃萼。", "独有名花开殿后，一笑嫣然如昨。", "黄袂层肤，霞冠高拥，多态春才觉。", "雨巾风帽，故人来趁花约。", "好是罗绮添春，香风环坐，半醉金钗落。", "老去心情难似旧，手拈花枝为乐。", "麝馥萦愁，妆花凝恨，莫惜金荷酌。", "酒阑花睡，梦魂重到京洛。"]'),
('song-ci-915','念奴娇','陈三聘','宋','宋词','song-ci','念奴娇','[]','水空高下，望沈沈一色，浑然苍碧。',120,'宋词/ci.song.11000.json','["水空高下，望沈沈一色，浑然苍碧。", "天籁不鸣凉有露，金气横秋寂寂。", "玉宇琼楼，望中何处，月到天中极。", "御风归去，不愁衣袂无力。", "此夜飘泊孤篷，短歌谁和，自笑狂踪迹。", "咫尺蓝桥仙路远，窅窅云英消息。", "疏影婆娑，恍然身世，我是尊前客。", "一声凄怨，倚楼谁弄长笛。"]'),
('song-ci-916','念奴娇','陈三聘','宋','宋词','song-ci','念奴娇','[]','馀霞飞绮，望长天、顷刻云容凝碧。',120,'宋词/ci.song.11000.json','["馀霞飞绮，望长天、顷刻云容凝碧。", "今夕江皋风力软，明日波心头白。", "客舸东流，语离深夜，遣我新愁积。", "春融花丽，定知天相行色。", "别后一纸乡书，故人相问，好趁秋鸿翼。", "空有佳人千点泪，锦字机中曾织。", "利锁名缰，古今同是，谁失知谁得。", "来朝愁望，旧楼何处西北。"]'),
('song-ci-917','念奴娇','陈三聘','宋','宋词','song-ci','念奴娇','[]','扁舟此计，问当年、谁与寻盟鸥鸟。',120,'宋词/ci.song.11000.json','["扁舟此计，问当年、谁与寻盟鸥鸟。", "许国勋名彝鼎在，风月不妨吟笑。", "碧草台边，红云溪上，寿杖扶诗老。", "水浮天处，未应俗驾曾到。", "盛事埒美知章，鉴湖君赐，宸翰今题号。", "指点飞烟轻霭外，有路直通仙岛。", "蓑笠渔船，琴书客坐，清夜尊罍倒。", "未须归去，片蟾初上林表。"]'),
('song-ci-918','惜分飞','陈三聘','宋','宋词','song-ci','惜分飞','[]','莫唱骊驹容首聚。',58,'宋词/ci.song.11000.json','["莫唱骊驹容首聚。", "花径重来微步。", "从此朝天去。", "故山怨鹤栖猿侣。", "试卜西园春在否。", "无奈濛濛细雨。", "明日长亭路。", "断魂芳草人何处。"]'),
('song-ci-919','梦玉人引','陈三聘','宋','宋词','song-ci','梦玉人引','[]','别来何处，酒醒后，梦难觅。',105,'宋词/ci.song.11000.json','["别来何处，酒醒后，梦难觅。", "晚日溪亭，清晓便挂帆席。", "满载离愁，指去程、还作江南行客。", "目断层城，数迢迢山驿。", "素巾空染，泪痕斑、应是暗中滴。", "记得轻分，玉箫犹自凄咽。", "昨夜东风，梅柳惊春色。", "料伊也、没心情，过却好天良夕。"]'),
('song-ci-920','梦玉人引','陈三聘','宋','宋词','song-ci','梦玉人引','[]','倚阑干久，人不见，暮云碧。',105,'宋词/ci.song.11000.json','["倚阑干久，人不见，暮云碧。", "芳草池塘，春梦暗惊诗客。", "昨夜溪梅，向空山、雪里轻匀颜色。", "好赠行人，折枝南枝北。", "雨巾风帽，昔追游、谁念旧踪迹。", "料得疏篱，暗香时度风息。", "淡月微云，有何人消得。", "便归去、踏溪桥，慰我经年思忆。"]'),
('song-ci-921','如梦令','陈三聘','宋','宋词','song-ci','如梦令','[]','红紫不将春住。',40,'宋词/ci.song.11000.json','["红紫不将春住。", "风定更飘无数。", "溪涨绿含风，短艇晚横沙渡。", "归去。", "归去。", "肯念西池鸳鹭。"]'),
('song-ci-922','如梦令','陈三聘','宋','宋词','song-ci','如梦令','[]','珍重故人相许。',40,'宋词/ci.song.11000.json','["珍重故人相许。", "来向水亭幽处。", "文字间金钗，消尽晚天微暑。", "无雨。", "无雨。", "不比寻常端午。"]'),
('song-ci-923','菩萨蛮','陈三聘','宋','宋词','song-ci','菩萨蛮','[]','筇枝探得梅开了。',52,'宋词/ci.song.11000.json','["筇枝探得梅开了。", "青鞋渐踏江头草。", "日日作东风。", "海棠相次红。", "离多良会少。", "此计应须早。", "莫待作行人。", "却将愁送春。"]'),
('song-ci-924','菩萨蛮','陈三聘','宋','宋词','song-ci','菩萨蛮','[]','春城办得红蕖了。',52,'宋词/ci.song.11000.json','["春城办得红蕖了。", "红蕖未点春先到。", "新月入新年。", "方才今夜圆。", "云屏谁为隔。", "肠断金钗客。", "好语写春幡。", "都教席上看。"]'),
('song-ci-925','菩萨蛮','陈三聘','宋','宋词','song-ci','菩萨蛮','[]','杨花满院飞红索。',52,'宋词/ci.song.11000.json','["杨花满院飞红索。", "春光不似人情薄。", "楼阁断霞明。", "梨花开晚晴。", "玉虬香散后。", "扶困三杯酒。", "不是听思归。", "归心思此时。"]'),
('song-ci-926','临江仙','陈三聘','宋','宋词','song-ci','临江仙','[]','夜饮只愁更漏促，留连笑罥蔷薇。',70,'宋词/ci.song.11000.json','["夜饮只愁更漏促，留连笑罥蔷薇。", "歌声缭绕彻帘帏。", "坐中清泪落，梁上暗尘飞。", "重睹舞腰惊束素，不应更褪罗衣。", "别来容易见来稀。", "次公狂已甚，不醉亦忘归。"]'),
('song-ci-927','临江仙','陈三聘','宋','宋词','song-ci','临江仙','[]','白首故人重会面，论交尔汝忘形。',70,'宋词/ci.song.11000.json','["白首故人重会面，论交尔汝忘形。", "从今心迹喜双清。", "飞鸿追往事，为蝶笑馀生。", "琥珀杯浓春正好，此怀端为君倾。", "旧时猿鹤敢寒盟。", "鸠居从拙计，鹏翼任高程。"]'),
('song-ci-928','减字木兰花','陈三聘','宋','宋词','song-ci','减字木兰花','[]','凝云不动。',52,'宋词/ci.song.11000.json','["凝云不动。", "玉海无声千丈冻。", "来倚阑干。", "襟袖凭虚彻骨寒。", "归心易折。", "后夜月明应恨别。", "罨画图边。", "著我披蓑上钓船。"]'),
('song-ci-929','减字木兰花','陈三聘','宋','宋词','song-ci','减字木兰花','[]','东篱黄菊。',52,'宋词/ci.song.11000.json','["东篱黄菊。", "细拈香枝人事熟。", "少缓芳尊。", "且醉侬家麴米春。", "老人斋戒。", "底事新来移角带。", "归梦相关。", "明月松江万顷宽。"]'),
('song-ci-930','减字木兰花','陈三聘','宋','宋词','song-ci','减字木兰花','[]','盈盈袅袅。',52,'宋词/ci.song.11000.json','["盈盈袅袅。", "欲问卿卿还好好。", "无奈娇何。", "折折湘裙薄薄罗。", "尊前顾曲。", "舞作回风花拍促。", "压尽时流。", "棋里输伊一百筹。"]'),
('song-ci-931','减字木兰花','陈三聘','宋','宋词','song-ci','减字木兰花','[]','先生困熟。',52,'宋词/ci.song.11000.json','["先生困熟。", "万卷书中聊托宿。", "似怯清寒。", "更爇都梁向博山。", "游仙梦杳。", "啼鸟声中春又晓。", "未著乌纱。", "独坐溪亭数落花。"]'),
('song-ci-932','减字木兰花','陈三聘','宋','宋词','song-ci','减字木兰花','[]','殷勤举白。',52,'宋词/ci.song.11000.json','["殷勤举白。", "昨夜东风犹有雪。", "莫恨春迟。", "曾见梅花第一枝。", "阴晴未决。", "早晚清明新火活。", "梦绕秦楼。", "欲趁归潮上客舟。"]'),
('song-ci-933','鹧鸪天','陈三聘','宋','宋词','song-ci','鹧鸪天','[]','酒晕从教上脸丹。',64,'宋词/ci.song.11000.json','["酒晕从教上脸丹。", "春愁何事点眉山。", "都将别后深深意，且向尊前细细看。", "多少恨，说应难。", "粉巾空染泪斓斑。", "炉猊筝雁长闲却，明月楼心夜正寒。"]'),
('song-ci-934','鹧鸪天','陈三聘','宋','宋词','song-ci','鹧鸪天','[]','指剥春葱去采苹。',64,'宋词/ci.song.11000.json','["指剥春葱去采苹。", "衣丝秋藕不沾尘。", "眼波明处偏宜笑，眉黛愁来也解颦。", "巫峡路，忆行云。", "几番曾梦曲江春。", "相逢细把银釭照，犹恐今宵梦似真。"]'),
('song-ci-935','鹧鸪天','陈三聘','宋','宋词','song-ci','鹧鸪天','[]','昨夜东风怒不成。',64,'宋词/ci.song.11000.json','["昨夜东风怒不成。", "晓来犹自扫残英。", "半酸梅子连枝重，无力杨花到地轻。", "情易感，涕先零。", "玉虬香冷更凄清。", "事如芳草绵绵远，恨比浮云冉冉生。"]'),
('song-ci-936','鹧鸪天','陈三聘','宋','宋词','song-ci','鹧鸪天','[]','翦碎霜绡巧作团。',64,'宋词/ci.song.11000.json','["翦碎霜绡巧作团。", "玉纤特地破朝寒。", "疏花好向钗横见，瘦影难敲月堕看。", "将旧恨，入眉弯。", "不须多样缕金旛。", "当时千点东风泪，怪见妆成粉未乾。"]'),
('song-ci-937','好事近','陈三聘','宋','宋词','song-ci','好事近','[]','我欲御天风，飞上广寒宫阙。',53,'宋词/ci.song.11000.json','["我欲御天风，飞上广寒宫阙。", "撼动一轮秋桂，照人间愁绝。", "归来须著酒消磨，玉面点红缬。", "起舞为君狂醉，更何须邀月。"]'),
('song-ci-938','好事近','陈三聘','宋','宋词','song-ci','好事近','[]','枝上几多春，数点不融香雪。',53,'宋词/ci.song.11000.json','["枝上几多春，数点不融香雪。", "纵有笔头千字，也难夸清绝。", "艳桃秾李敢争妍，清怨笛中咽。", "试策短筇溪上，看影浮波月。"]'),
('song-ci-939','卜算子','陈三聘','宋','宋词','song-ci','卜算子','[]','雪后竹枝风，醉梦风吹醒。',52,'宋词/ci.song.11000.json','["雪后竹枝风，醉梦风吹醒。", "瘦立寒阶满地春，淡月梅花影。", "门外辘轳寒，晓汲喧金井。", "长笛何人更倚楼，玉指风前冷。"]'),
('song-ci-940','卜算子','陈三聘','宋','宋词','song-ci','卜算子','[]','涧下水声寒，壑底松风静。',52,'宋词/ci.song.11000.json','["涧下水声寒，壑底松风静。", "时有清香度竹来，步月寻疏影。", "往事属东风，试问花应省。", "曾是花前把酒人，别梦溪堂冷。"]'),
('song-ci-941','三登乐','陈三聘','宋','宋词','song-ci','三登乐','[]','南北相逢，重借问、古今齐楚。',90,'宋词/ci.song.11000.json','["南北相逢，重借问、古今齐楚。", "烛花红、夜阑共语。", "怅六朝兴废，但倚空高树。", "目断帝乡，梦迷雁浦。", "故人疏、梅驿断，音书有数。", "塞鸿归、过来又去。", "正春浓，依旧作、天涯行旅。", "伤心望极，淡烟细雨。"]'),
('song-ci-942','三登乐','陈三聘','宋','宋词','song-ci','三登乐','[]','注望晓山，晴色丽、晨餐应饱。',91,'宋词/ci.song.11000.json','["注望晓山，晴色丽、晨餐应饱。", "縠纹平、涨天渺渺。", "倚藤枝、撑艇子，昔游曾到。", "江山自古，水云转好。", "怅年来、心纵在，盟寒鸥鸟。", "故人中、黑头渐少。", "问几时、寻旧约，石矶重扫。", "一竿钓月，鬓霜任老。"]'),
('song-ci-943','三登乐','陈三聘','宋','宋词','song-ci','三登乐','["\u6d1e\u5ead\u6e56"]','久蛰群虬，犹未肆、新雷初启。',91,'宋词/ci.song.11000.json','["久蛰群虬，犹未肆、新雷初启。", "鼓东风、雨膏为洗。", "望横塘、越溪路，石湖烟水。", "西接洞庭，下连甫里。", "忆当年、归计早，扁舟从此。", "祖清风、相门有几。", "圃堂高、应解笑，纷纷蜗蚁。", "锦囊雪月，更看醉里。"]'),
('song-ci-944','三登乐','陈三聘','宋','宋词','song-ci','三登乐','[]','一品归来，强健日、小园幽圃。',91,'宋词/ci.song.11000.json','["一品归来，强健日、小园幽圃。", "扁舟兴、恐天未许。", "想当年、持汉节，众齐咻楚。", "丹忠此日，盛名千古。", "掞词章、师海内，纬文经武。", "莫寒盟、故山旧侣。", "到鲈乡、还又是，秋风斜雨。", "鸣刀鲙雪，未应便去。"]'),
('song-ci-945','浪淘沙','陈三聘','宋','宋词','song-ci','浪淘沙','[]','风雨晚春天。',64,'宋词/ci.song.11000.json','["风雨晚春天。", "芳兴慵悭。", "浅红稠绿满园间。", "独有梨花三四朵，留住春寒。", "年少跃金鞍。", "咫尺关山。", "倦飞如我已知还。", "洒向东风千点泪，衣上重看。"]'),
('song-ci-946','虞美人','陈三聘','宋','宋词','song-ci','虞美人','[]','融融睡觉东风息。',66,'宋词/ci.song.11000.json','["融融睡觉东风息。", "行到溪亭侧。", "一枝梅玉似人人。", "索笑依然消瘦、不禁春。", "相逢试问情多少。", "应怪山翁老。", "翠罗高护结花邻。", "一任馀芳争学、捧心颦。"]'),
('song-ci-947','虞美人','陈三聘','宋','宋词','song-ci','虞美人','[]','天公意向人情满。',66,'宋词/ci.song.11000.json','["天公意向人情满。", "灯月教同看。", "中秋虽是十分明。", "不比今宵处处、有华灯。", "艳桃秾李歌阑后。", "更醉青楼酒。", "不妨饮尽玉东西。", "横笛声中春色、要君知。"]'),
('song-ci-948','虞美人','陈三聘','宋','宋词','song-ci','虞美人','[]','飞琼晓压梅枝重。',66,'宋词/ci.song.11000.json','["飞琼晓压梅枝重。", "酒面羊羔冻。", "谁将缟带逐车翻。", "明月秦楼昨夜、不胜寒。", "何须卷起重帘幕。", "愁怕春罗薄。", "玉杯持劝醉厌厌。", "无奈有人笼袖、出香尖。"]'),
('song-ci-949','虞美人','陈三聘','宋','宋词','song-ci','虞美人','[]','乾红翦碎烦纤玉。',66,'宋词/ci.song.11000.json','["乾红翦碎烦纤玉。", "相并黄金粟。", "汉宫素面说明妃。", "马上秋风应解、著燕支。", "黄昏小树堪愁绝。", "不比梅花月。", "满天风露透肌凉。", "插取双枝归去、是谁香。"]'),
('song-ci-950','醉落魄・一斛珠','陈三聘','宋','宋词','song-ci','醉落魄・一斛珠','[]','东风寒绝。',21,'宋词/ci.song.11000.json','["东风寒绝。", "江城待得花枝发。", "欲知此夜碧天阔。"]'),
('song-ci-951','眼儿媚','陈三聘','宋','宋词','song-ci','眼儿媚','[]','酸。',17,'宋词/ci.song.11000.json','["酸。", "何人为我，丁宁驿使，来到江干。"]'),
('song-ci-952','水调歌头','石孝友','宋','宋词','song-ci','水调歌头','[]','君恩九鼎重，臣命一毫轻。',114,'宋词/ci.song.11000.json','["君恩九鼎重，臣命一毫轻。", "出身事主，刚甚须作不平鸣。", "老却西山薇蕨，闲损南窗松菊，羞死汉公卿。", "豺狼敢横道，草木要知名。", "秋已素，人又去，若为情。", "长沙何在，风送呜咽暮潮声。", "举棹却寻归路，挥麈莫谈时事，得酒且频倾。", "一片古时月，千里伴君行。"]'),
('song-ci-953','宝鼎现','石孝友','宋','宋词','song-ci','宝鼎现','[]','雪梅清瘦，月桂圆冷，天街新霁。',192,'宋词/ci.song.11000.json','["雪梅清瘦，月桂圆冷，天街新霁。", "想帝辇、三朝薄暮，催促烛龙开扇雉。", "正拜舞、捧玉卮为寿，花满香铺凤髓。", "罄禹穴、胥涛万顷，春入南山声里。", "鼎轴元老诗书帅。", "体宸衷、双奉亲意。", "勤色养、行春惜花，夜欢宴、瑶池衣彩戏。", "鼓淑气、遍湖山千里。", "惊破悭红涩翠。", "笑那个痴儿无赖。", "打得金鱼坠地。", "休念太守当年，曾手把青藜照字。", "对珠帘云栋，收拾太平歌舞辍。", "庆母爱、小宽王事。", "馀沥□肠，看不日、归步沙堤，又赞重华孝治。"]'),
('song-ci-954','眼儿媚','石孝友','宋','宋词','song-ci','眼儿媚','[]','何须著粉更施朱。',58,'宋词/ci.song.11000.json','["何须著粉更施朱。", "元不在妆梳。", "寻常结束，珊珊环佩，短短裙襦。", "花羞柳妒空撩乱，冰雪做肌肤。", "而今便好，小名弄玉，小字琼奴。"]'),
('song-ci-955','眼儿媚','石孝友','宋','宋词','song-ci','眼儿媚','[]','愁云淡淡雨潇潇。',58,'宋词/ci.song.11000.json','["愁云淡淡雨潇潇。", "暮暮复朝朝。", "别来应是，眉峰翠减，腕玉香销。", "小轩独坐相思处，情绪好无聊。", "一丛萱草，几竿修竹，数叶芭蕉。"]'),
('song-ci-956','临江仙','石孝友','宋','宋词','song-ci','临江仙','[]','一霎狂云惊雨过，月华恰到帘帷。',70,'宋词/ci.song.11000.json','["一霎狂云惊雨过，月华恰到帘帷。", "槛前叠石翠参差。", "洞房相见处，灯火乍凉时。", "睡玉眠花愁夜短，匆匆共惜佳期。", "风梧不动酒醒迟。", "好同蝴蝶梦，飞上凤皇枝。"]'),
('song-ci-957','临江仙','石孝友','宋','宋词','song-ci','临江仙','[]','醉袖吟鞭行色里，帽檐低处风斜。',70,'宋词/ci.song.11000.json','["醉袖吟鞭行色里，帽檐低处风斜。", "晚山一半被云遮。", "残阳明远水，古木集栖鸦。", "暮去朝来缘底事，不如早早还家。", "曲屏深幌小窗纱。", "翠沾眉上柳，红搵脸边花。"]'),
('song-ci-958','临江仙','石孝友','宋','宋词','song-ci','临江仙','[]','买笑当歌何处好，小楼四面江山。',70,'宋词/ci.song.11000.json','["买笑当歌何处好，小楼四面江山。", "玉梅枝上卸馀寒。", "雨随春到急，风向晚来颠。", "任自腰围都瘦损，肯教欢意阑珊。", "引杯相属莫留残。", "花如人竞好，人与月争圆。"]'),
('song-ci-959','临江仙','石孝友','宋','宋词','song-ci','临江仙','[]','枕上莺声初破睡，峭寒轻透帘帏。',70,'宋词/ci.song.11000.json','["枕上莺声初破睡，峭寒轻透帘帏。", "起来惆怅有谁知。", "雨狂风转急，揉损好花枝。", "薄幸别来春又老，等闲误却佳期。", "斜阳影里立多时。", "远山何事□，相对蹙修眉。"]'),
('song-ci-960','临江仙','石孝友','宋','宋词','song-ci','临江仙','[]','常记梦云楼上住，残灯影里迟留。',70,'宋词/ci.song.11000.json','["常记梦云楼上住，残灯影里迟留。", "依稀绿惨更红羞。", "露痕双脸泪，山样两眉愁。", "数片轻帆天际去，云涛烟浪悠悠。", "今宵独宿古江头。", "水腥鱼菜市，风碎荻花洲。"]'),
('song-ci-961','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','收拾眉尖眼尾情。',64,'宋词/ci.song.11000.json','["收拾眉尖眼尾情。", "当筵相见便相亲。", "偷传翡翠歌中意，暗合鸳鸯梦里身。", "云态度，月精神。", "月流云散两无情。", "觉来一枕凄凉恨，不敢分明说向人。"]'),
('song-ci-962','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','收拾眉尖眼尾情。',64,'宋词/ci.song.11000.json','["收拾眉尖眼尾情。", "夜来真个梦倾城。", "鸳鸯有底情难尽，蝴蝶无端梦易惊。", "愁一掬，月三更。", "绣帏应好睡轻盈。", "知他莫有相怜分，展转寻思直到明。"]'),
('song-ci-963','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','别后应怜信息疏。',64,'宋词/ci.song.11000.json','["别后应怜信息疏。", "西风几度到庭梧。", "夜来纵有鸳鸯梦，春去空馀蛱蝶图。", "烟树远，塞鸿孤。", "垂垂天影带平芜。", "凭谁写此相思曲，寄与冯川郑小奴。"]'),
('song-ci-964','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','家在东湖湖上头。',64,'宋词/ci.song.11000.json','["家在东湖湖上头。", "别来风月为谁留。", "落霞孤鹜齐飞处，南浦西山相对愁。", "真了了，好休休。", "莫教辜负菊花秋。", "浮云富贵何须羡，画饼声名肯浪求。"]'),
('song-ci-965','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','花漏声乾月隐墙。',64,'宋词/ci.song.11000.json','["花漏声乾月隐墙。", "琯灰迎晓透新阳。", "物情渐逐云容好，欢意偏随日脚长。", "山作鼎，玉为浆。", "寿杯丛处艳梅妆。", "醉乡路接华胥国，应梦朝天侍赭黄。"]'),
('song-ci-966','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','玉烛调元黍律匀。',64,'宋词/ci.song.11000.json','["玉烛调元黍律匀。", "迎长嘉节属芳辰。", "云如惜雨钩牵雪，梅不禁风漏泄春。", "天意好，物华新。", "偷闲赢取酒边身。", "太平朝野都无事，且与莺花作主人。"]'),
('song-ci-967','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','一夜冰澌满玉壶。',64,'宋词/ci.song.11000.json','["一夜冰澌满玉壶。", "五更喜气动洪炉。", "门前桃李知麟集，庭下芝兰看鲤趋。", "泉脉动，草心苏。", "日长添得绣工夫。", "试询补衮弥缝手，真个曾添一线无。"]'),
('song-ci-968','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','一别音尘两杳然。',64,'宋词/ci.song.11000.json','["一别音尘两杳然。", "不堪虚度菊花天。", "惊秋远雁横斜字，噪晚哀蝉断续弦。", "好将息，恶姻缘。", "凉宵如水复如年。", "梦魂不怕风波险，飞过江西阿那边。"]'),
('song-ci-969','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','屏障重重翠幕遮。',64,'宋词/ci.song.11000.json','["屏障重重翠幕遮。", "兰膏烟暖篆香斜。", "相思树上双栖翼，连理枝头并蒂花。", "敧凤髻，亸乌纱。", "云慵雨困兴无涯。", "个中赢取平生事，兔走乌飞一任他。"]'),
('song-ci-970','卜算子','石孝友','宋','宋词','song-ci','卜算子','[]','人自蕊宫来，微步香云拥。',52,'宋词/ci.song.11000.json','["人自蕊宫来，微步香云拥。", "小试樽前白雪歌，叶叶秋声动。", "一剪艳波横，两点愁山重。", "收拾眉尖眼尾情，作个鸳鸯梦。"]'),
('song-ci-971','卜算子','石孝友','宋','宋词','song-ci','卜算子','[]','见也如何暮。',52,'宋词/ci.song.11000.json','["见也如何暮。", "别也如何遽。", "别也应难见也难，后会难凭据。", "去也如何去。", "住也如何住。", "住也应难去也难，此际难分付。"]'),
('song-ci-972','卜算子','石孝友','宋','宋词','song-ci','卜算子','[]','折得月中枝，坐惜青春老。',52,'宋词/ci.song.11000.json','["折得月中枝，坐惜青春老。", "及至归来能几时，又踏关山道。", "满眼秋光好。", "相见应须早。", "若趁重阳不到家，只怕黄花笑。"]'),
('song-ci-973','卜算子','石孝友','宋','宋词','song-ci','卜算子','[]','冷蕊閟红香，瘦节攒苍玉。',52,'宋词/ci.song.11000.json','["冷蕊閟红香，瘦节攒苍玉。", "更著堂堂十八翁，取友三人足。", "惜此岁寒姿，移向屏山曲。", "纸帐熏炉结胜缘，故伴仙郎宿。"]'),
('song-ci-974','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','露叶披残露颗传。',64,'宋词/ci.song.11000.json','["露叶披残露颗传。", "明星著地月流天。", "不辞独赏穷今夜，应为相逢忆去年。", "辜窈窕，负蝉娟。", "谁知两处照孤眠。", "姮娥不怕离人怨，有甚心情独自圆。"]'),
('song-ci-975','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','万里羁孤困一箪。',64,'宋词/ci.song.11000.json','["万里羁孤困一箪。", "平头四十误儒冠。", "舜弦广播薰风暖，邹律潜消黍谷寒。", "楼谩倚，剑休弹。", "看君行复上金銮。", "凤池波里求馀润，蚖肆泥中岂久蟠。"]'),
('song-ci-976','渔家傲','石孝友','宋','宋词','song-ci','渔家傲','[]','射虎将军搴绣帽。',72,'宋词/ci.song.11000.json','["射虎将军搴绣帽。", "西园公子南山豹。", "共跨龙媒衔凤沼。", "风色好。", "宫花御柳迎人笑。", "剑履醒醒天日表。", "集英殿下春来早。", "双鹗盘空擎百鸟。", "归来了。", "蓝袍锦水光相照。"]'),
('song-ci-977','渔家傲','石孝友','宋','宋词','song-ci','渔家傲','[]','夜半潮声来枕上。',72,'宋词/ci.song.11000.json','["夜半潮声来枕上。", "击残梦破惊魂荡。", "见说钱塘雄气象。", "披衣望。", "碧波堆里排银浪。", "月影徘徊天滉漾。", "金戈铁马森相向。", "洗尽尘根磨业障。", "增豪放。", "从公笔力诗词壮。"]'),
('song-ci-978','洞仙歌','石孝友','宋','宋词','song-ci','洞仙歌','[]','芙蓉院宇，露下秋容瘦。',103,'宋词/ci.song.11000.json','["芙蓉院宇，露下秋容瘦。", "龟鹤仙人献长寿。", "问蓬山别后，几度春归，归去晚，开得蟠桃厮勾。", "人间游戏好，鲸背风高，那更相将凤雏九。", "事苹蘩，工翰墨，才德兼全，人总道、古今稀有。", "尽从他、乌兔促年华，看绿鬓朱颜，镇长依旧。"]'),
('song-ci-979','念奴娇','石孝友','宋','宋词','song-ci','念奴娇','[]','半千宝运，瑞清朝、诞育人间英物。',120,'宋词/ci.song.11000.json','["半千宝运，瑞清朝、诞育人间英物。", "暖律吹灰春到也，迟日光腾东壁。", "婺女双溪，沈郎八咏，辉映皆冰雪。", "储精毓秀，几年一个人杰。", "须信和气随人，粉梅欺黛柳，娇春争发。", "翠幕重重称寿处，莲炬蕙烟明灭。", "鼎席犹虚，九重频念此，衮衣华发。", "明年今夜，凤池应醉花月。"]'),
('song-ci-980','念奴娇','石孝友','宋','宋词','song-ci','念奴娇','[]','闷红颦翠，惜流年、忍对艳阳时节。',120,'宋词/ci.song.11000.json','["闷红颦翠，惜流年、忍对艳阳时节。", "白玉楼成人去后，两地音尘都绝。", "鸾鉴分飞，梦云零乱，欢意今衰飒。", "墨痕红淡，忆曾题遍红叶。", "须信后约难凭，臂啮鬟剪，也只成虚说。", "满眼凄凉无限事，付与丁香愁结。", "欲语情酸，临岐步懒，怅望兰舟发。", "出门谁伴，泪昏一片孤月。"]'),
('song-ci-981','念奴娇','石孝友','宋','宋词','song-ci','念奴娇','[]','平湖阁上，正残虹挂雨，微云擎月。',120,'宋词/ci.song.11000.json','["平湖阁上，正残虹挂雨，微云擎月。", "万顷琉璃秋向冷，忍便翠销红歇。", "北海樽罍，西园游宴，兴逸湖山发。", "飞尘不到，坐移蓬岛珠阙。", "莫厌笑口频开，少年行乐事，转头胡越。", "公子多情真爱客，敢惮深杯百罚。", "太一舟轻，芙蓉城锁，醉指神仙窟。", "乘风归去，尽教吹乱华发。"]'),
('song-ci-982','念奴娇','石孝友','宋','宋词','song-ci','念奴娇','[]','平湖阁上，正雌霓将卷，雄风初发。',120,'宋词/ci.song.11000.json','["平湖阁上，正雌霓将卷，雄风初发。", "醉倚危栏吟眺处，月在篷莱溟渤。", "蓬叶香浮，桂华光放，翻动蛟鼍窟。", "踏轮谁信，宓妃曾借尘袜。", "人世景物堪悲，等闲都换了，朱颜云发。", "遥想广寒秋到早，闲著几多空阔。", "太白诗魂，玉川风腋，自有飞仙骨。", "嫦娥为伴，夜深同驾霜月。"]'),
('song-ci-983','念奴娇','石孝友','宋','宋词','song-ci','念奴娇','[]','麦秋天气，正玉杓斡暑，熏弦鸣律。',120,'宋词/ci.song.11000.json','["麦秋天气，正玉杓斡暑，熏弦鸣律。", "浴佛生朝初过也，还数佳辰三日。", "筮水呈祥，梦熊叶庆，宝运符千一。", "太平朝野，异人端为时出。", "须信家世蝉联，乃翁遗范在，子孙逢吉。", "雾隐巢云聊寄傲，行矣飞英腾实。", "瀑布泉清，炉峰气秀，光映霞觞溢。", "萱堂争看，彩衣红堕双橘。"]'),
('song-ci-984','醉落魄・一斛珠','石孝友','宋','宋词','song-ci','醉落魄・一斛珠','[]','友莺梦蝶。',67,'宋词/ci.song.11000.json','["友莺梦蝶。", "寻花问柳深相结。", "教春去后群芳歇。", "零落朋游，辜负好时节。", "眼边愁绪多于发。", "迢迢一水通吴越。", "旧欢新恨都休说。", "坐暖残红，沈醉碧天阔。"]'),
('song-ci-985','醉落魄・一斛珠','石孝友','宋','宋词','song-ci','醉落魄・一斛珠','[]','鸾孤凤只。',67,'宋词/ci.song.11000.json','["鸾孤凤只。", "而今怎忍轻抛掷。", "知他别后谁怜惜。", "一味恓惶，辜负我思忆。", "云山万叠烟波急。", "短书频寄征鸿翼。", "相逢后会知何日。", "去也奴哥，千万好将息。"]'),
('song-ci-986','醉落魄・一斛珠','石孝友','宋','宋词','song-ci','醉落魄・一斛珠','[]','空庭草积。',67,'宋词/ci.song.11000.json','["空庭草积。", "吹花风去春无迹。", "锁鸾深处应相忆。", "红染罗巾，颦损眉山碧。", "曲屏尘暗双鸂鶒。", "醉衾不暖炉烟湿。", "一帘暝色人孤寂。", "梦里灯残，心上雨声滴。"]'),
('song-ci-987','醉落魄・一斛珠','石孝友','宋','宋词','song-ci','醉落魄・一斛珠','[]','红娇翠弱。',67,'宋词/ci.song.11000.json','["红娇翠弱。", "怨人珠泪频偷落。", "归期莫负青笺约。", "雨断云销，总是初情薄。", "夜深秋气生帘幕。", "半衾依旧空闲却。", "故人何处孤舟泊。", "两岸秋声，一夜风涛恶。"]'),
('song-ci-988','丑奴儿・采桑子','石孝友','宋','宋词','song-ci','丑奴儿・采桑子','[]','凌花镜里桃花笑，清影团团。',52,'宋词/ci.song.11000.json','["凌花镜里桃花笑，清影团团。", "月淡风寒。", "深夜移灯许细观。", "武陵溪上当时事，何处飞鸾。", "泪纸惊澜。", "飘尽红英不忍看。"]'),
('song-ci-989','西江月','石孝友','宋','宋词','song-ci','西江月','[]','歌彻秋娘金缕，醉扳织女云车。',58,'宋词/ci.song.11000.json','["歌彻秋娘金缕，醉扳织女云车。", "而今谁复荐相如。", "拔剑茫然四顾。", "好景凭诗断送，闲愁著酒消除。", "镜中丝发莫惊呼。", "春满珠帘绣户。"]'),
('song-ci-990','西江月','石孝友','宋','宋词','song-ci','西江月','[]','脉脉无端心事，厌厌不奈春酲。',58,'宋词/ci.song.11000.json','["脉脉无端心事，厌厌不奈春酲。", "越罗衫薄峭寒轻。", "试问几番花信。", "万点风头柳絮，数声柳外啼莺。", "斜阳还傍小窗明。", "门掩黄昏人静。"]'),
('song-ci-991','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','六十仙翁抱桂栽。',64,'宋词/ci.song.11000.json','["六十仙翁抱桂栽。", "果符吉梦诞英才。", "上天与降麒麟种。", "明月还生蚌蛤胎。", "华阁启，玳筵开。", "快呼玉手捧金罍。", "要知远地无功客，曾到高门作贺来。"]'),
('song-ci-992','踏莎行','石孝友','宋','宋词','song-ci','踏莎行','[]','沈水销红，屏山掩素。',68,'宋词/ci.song.11000.json','["沈水销红，屏山掩素。", "锁窗醉枕惊眠处。", "芰荷香里散秋风，芭蕉叶上鸣秋雨。", "飞阁愁登，倚阑凝伫。", "孤鸿影没江天暮。", "行云懒寄好音来，断云暗逐斜阳去。"]'),
('song-ci-993','望海潮','石孝友','宋','宋词','song-ci','望海潮','[]','离情冰泮，归心云扰，黯然凝伫江皋。',129,'宋词/ci.song.11000.json','["离情冰泮，归心云扰，黯然凝伫江皋。", "柳色摇金，梅香弄粉，依稀满眼春娇。", "常记极游遨。", "更与持玉斝，因解金貂。", "郎去翟塘，妾家巫峡水迢迢。", "别来暗减风标。", "奈碧云暗断，翠被香消。", "春草生池，芳尘凝榭，凄凉月夕花朝。", "千里梦魂劳。", "但鸟啼渡口，猿响山椒。", "拟把无穷幽恨，万叠写霜绡。"]'),
('song-ci-994','虞美人','石孝友','宋','宋词','song-ci','虞美人','[]','醉寻芳草城头路。',66,'宋词/ci.song.11000.json','["醉寻芳草城头路。", "底事频凝伫。", "丽谯直下小层楼。", "鸳瓦重重匀砌、几重愁。", "睡红颦翠春风面。", "咫尺无由见。", "从教笑语落檐楹。", "图得香闺依约、认郎声。"]'),
('song-ci-995','虞美人','石孝友','宋','宋词','song-ci','虞美人','[]','月娥弄影当窗照。',66,'宋词/ci.song.11000.json','["月娥弄影当窗照。", "疑是巫山晓。", "芙蓉帐里睡魂惊。", "浅拂轻匀犹恐、已天明。", "高楼未放梅花弄。", "却就鸳衾拥。", "舞腰纤瘦不禁春。", "姿意任郎撩乱、一梳云。"]'),
('song-ci-996','水龙吟','石孝友','宋','宋词','song-ci','水龙吟','[]','旧游曾记当年，凤城雨露开晴昼。',126,'宋词/ci.song.11000.json','["旧游曾记当年，凤城雨露开晴昼。", "端门发钥，御炉烟暗，宫花影覆。", "帝念民劳，俾乘轺传，暂临牛斗。", "散阳和四照，春光万井，来小试、调元手。", "职业才华竞秀。", "汉廷臣、无出其右。", "九重眷倚，频虚槐鼎，争迎衮绣。", "爽气西山，绿波南浦，酿成芳酒。", "趁锋车未到，霞觞共祝，百千长寿。"]'),
('song-ci-997','长相思','石孝友','宋','宋词','song-ci','长相思','[]','你又痴。',44,'宋词/ci.song.11000.json','["你又痴。", "我又迷。", "到此痴迷两为谁。", "问天天怎知。", "长相思。", "极相思。", "愿得姻缘未尽时。", "今生重共伊。"]'),
('song-ci-998','长相思','石孝友','宋','宋词','song-ci','长相思','[]','红依稀。',44,'宋词/ci.song.11000.json','["红依稀。", "绿依稀。", "寒勒花梢开较迟。", "蝶魂空自迷。", "怕人疑。", "使人疑。", "人道闲愁想未知。", "歌眉因甚低。"]'),
('song-ci-999','长相思','石孝友','宋','宋词','song-ci','长相思','[]','蝶团飞。',44,'宋词/ci.song.11000.json','["蝶团飞。", "莺乱啼。", "陌上花开人未归。", "碧台歌舞稀。", "月入扉。", "风满帷。", "坐到黄昏人静时。", "清愁君不知。"]'),
('song-ci-0','长相思','石孝友','宋','宋词','song-ci','长相思','[]','树槎牙。',44,'宋词/ci.song.12000.json','["树槎牙。", "冰交加。", "冷艳疏疏瘦影斜。", "几枝梅花放。", "天一涯。", "语三叉。", "已是情多怨物华。", "那堪更忆家。"]'),
('song-ci-1','品令','石孝友','宋','宋词','song-ci','品令','[]','困无力。',62,'宋词/ci.song.12000.json','["困无力。", "几度偎人，翠颦红湿。", "低低问、几时麽，道不远、三五日。", "你也自家宁耐，我也自家将息。", "蓦然地、烦恼一个病，教一个、怎知得。"]'),
('song-ci-2','点绛唇','石孝友','宋','宋词','song-ci','点绛唇','[]','霁景澄秋，晚风吹尽朝来雨。',50,'宋词/ci.song.12000.json','["霁景澄秋，晚风吹尽朝来雨。", "夕阳烟树。", "万里山光暮。", "一带长川，自在流今古。", "人何处。", "月波横素。", "冷浸蒹葭浦。"]'),
('song-ci-3','点绛唇','石孝友','宋','宋词','song-ci','点绛唇','[]','缓解罗裳，十分鸳履低腰素。',50,'宋词/ci.song.12000.json','["缓解罗裳，十分鸳履低腰素。", "冰香微度。", "一罅殷红露。", "风折芳莲，影落盆池去。", "多羞处。", "怕人偷觑。", "粉面频回顾。"]'),
('song-ci-4','点绛唇','石孝友','宋','宋词','song-ci','点绛唇','[]','著意栽银，砌成叶叶莲花舫。',50,'宋词/ci.song.12000.json','["著意栽银，砌成叶叶莲花舫。", "醉霞摇荡。", "恰似凌波样。", "自笑平生，鲸吸洪波量。", "孤心赏。", "不如深幌。", "一搦酬千想。"]'),
('song-ci-5','点绛唇','石孝友','宋','宋词','song-ci','点绛唇','[]','杨柳腰枝，春来尚怯铢衣重。',50,'宋词/ci.song.12000.json','["杨柳腰枝，春来尚怯铢衣重。", "眼波偷送。", "笑把花枝弄。", "雨帐云屏，一枕高唐梦。", "春情动。", "殢人娇纵。", "困亸钗横凤。"]'),
('song-ci-6','点绛唇','石孝友','宋','宋词','song-ci','点绛唇','[]','醉倚危墙，望中归思生天际。',50,'宋词/ci.song.12000.json','["醉倚危墙，望中归思生天际。", "山腰渚尾。", "几簇渔樵市。", "帆落西风，一段芦花水。", "八千里。", "锦书欲寄。", "新雁曾来未。"]'),
('song-ci-7','点绛唇','石孝友','宋','宋词','song-ci','点绛唇','[]','日薄风迟，柳眠无力花枝妥。',50,'宋词/ci.song.12000.json','["日薄风迟，柳眠无力花枝妥。", "燕楼空锁。", "好梦谁惊破。", "寒食清明，又等闲都过。", "愁无那。", "泪珠频堕。", "洒尽相思颗。"]'),
('song-ci-8','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','小桃破尽风前萼。',64,'宋词/ci.song.12000.json','["小桃破尽风前萼。", "草草年华闲过却。", "十分清瘦有谁知，一点相思无处著。", "书凭雁字应难托。", "花与泪珠相对落。", "万红千翠尽春光，若比此情犹自薄。"]'),
('song-ci-9','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','春生泽国芳菲早。',64,'宋词/ci.song.12000.json','["春生泽国芳菲早。", "楼外墙阴闻语笑。", "东君著意到西园，点破施朱浑未了。", "楚云暮合吴天杳。", "天色沈沈云扰扰。", "洞门深闭月轮孤，不见当时张好好。"]'),
('song-ci-10','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','风光澹沲云容粹。',64,'宋词/ci.song.12000.json','["风光澹沲云容粹。", "点染园林添况味。", "花间照夜簇红纱，柳外踏青摇彩旆。", "芳时不分空憔悴。", "抖擞愁怀赊乐事。", "罗衫一任涴尘泥，拼了通宵排日醉。"]'),
('song-ci-11','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','扁舟破浪鸣双橹。',64,'宋词/ci.song.12000.json','["扁舟破浪鸣双橹。", "岁晚客心分万绪。", "香红漠漠落梅村，愁碧萋萋芳草渡。", "汉皋珮失诚相误。", "楚峡云归无觅处。", "一天明月缺还圆，千里伴人来又去。"]'),
('song-ci-12','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','井花暖处新阳动。',64,'宋词/ci.song.12000.json','["井花暖处新阳动。", "节物撩人添倥偬。", "寒齑冰齿晕轻澌，败絮粟肌悭短梦。", "文章彻了成何用。", "闷拨炉灰窥饭瓮。", "寻思已得到春时，预把五穷连夜送。"]'),
('song-ci-13','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','汉皇受禅新尧统。',64,'宋词/ci.song.12000.json','["汉皇受禅新尧统。", "沼跃潜鱼仪舞凤。", "五云色备观台书，万世功成贤相用。", "江湖襟带蛮荆控。", "摩抚民劳输土贡。", "愿倾石尉望尘心，来献鲁侯难老颂。"]'),
('song-ci-14','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','一阳不受群阴壅。',64,'宋词/ci.song.12000.json','["一阳不受群阴壅。", "残历行间冬破仲。", "云低吹白腊寒浓，梅小绽红春意重。", "湖山千里勤飞控。", "淑气冲融披水冻。", "笑携雨露洒民心，暗聚精神交帝梦。"]'),
('song-ci-15','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','黄锺应律扶炎统。',64,'宋词/ci.song.12000.json','["黄锺应律扶炎统。", "舜日迎长佳节用。", "娟娟芳意著花梢，盎盎暖香浮酒瓮。", "寿觞唤取纤纤捧。", "雨歇珠帘云绕栋。", "兴来且伴橘中仙，归去却联池上凤。"]'),
('song-ci-16','玉楼春','石孝友','宋','宋词','song-ci','玉楼春','[]','台门瑞霭光阳动。',64,'宋词/ci.song.12000.json','["台门瑞霭光阳动。", "人语鼓声沈汹汹。", "观风堂迥暗香飘，卷雨楼前寒翠拥。", "锋车促入承天宠。", "丹诏衔来须彩凤。", "五丝宫线日边长，看补岩廊龙衮缝。"]'),
('song-ci-17','西地锦','石孝友','宋','宋词','song-ci','西地锦','[]','回望玉楼金阙。',58,'宋词/ci.song.12000.json','["回望玉楼金阙。", "正水遮山隔。", "风儿又起，雨儿又煞，好愁人天色。", "两岸荻花枫叶。", "争舞红吹白。", "中秋过也，重阳近也，作天涯行客。"]'),
('song-ci-18','朝中措','石孝友','宋','宋词','song-ci','朝中措','[]','乱山叠叠水泠泠。',56,'宋词/ci.song.12000.json','["乱山叠叠水泠泠。", "南北短长亭。", "客路如天杳杳，归心能地宁宁。", "春光荏苒花期，冷落酒伴飘零。", "鬓影黄边半白，烧痕黑处重青。"]'),
('song-ci-19','阮郎归','石孝友','宋','宋词','song-ci','阮郎归','[]','烛花吹尽篆烟青。',56,'宋词/ci.song.12000.json','["烛花吹尽篆烟青。", "长波拍枕鸣。", "西风吹断雁鸿声。", "离人梦暗惊。", "乡思动，旅愁生。", "谁知此夜情。", "乱山重叠拥孤城。", "空江月自明。"]'),
('song-ci-20','满江红','石孝友','宋','宋词','song-ci','满江红','[]','雁阵惊寒，故唤起、离愁万斛。',115,'宋词/ci.song.12000.json','["雁阵惊寒，故唤起、离愁万斛。", "因追念、镜鸾易破，凤弦难续。", "诗句已凭红叶去，梦魂未断黄粱熟。", "叹浪萍、风梗又天涯，成幽独。", "归来引，相思曲。", "尘满把，泪盈掬。", "对长天远水，落霞孤骛。", "立尽西风无好意，遥山也学双眉蹙。", "恨草根、不逐鬓根摧，秋更绿。"]'),
('song-ci-21','浪淘沙','石孝友','宋','宋词','song-ci','浪淘沙','[]','好恨这风儿。',64,'宋词/ci.song.12000.json','["好恨这风儿。", "催俺分离。", "船儿吹得去如飞。", "因甚眉儿吹不展，叵耐风儿。", "不是这船儿。", "载起相思。", "船儿若念我孤恓。", "载取人人篷底睡，感谢风儿。"]'),
('song-ci-22','胜胜慢・声声慢','石孝友','宋','宋词','song-ci','胜胜慢・声声慢','[]','花前月下，好景良辰，厮守日许多时。',119,'宋词/ci.song.12000.json','["花前月下，好景良辰，厮守日许多时。", "正美之间，何事便有轻离。", "无端珠泪暗簌，染征衫、点点红滋。", "最苦是、□殷勤密约，做造相思。", "咿哑橹声离岸，魂断处，高城隐隐天涯。", "万水千山，一去定失花期。", "东君斗来无赖，散春红、点破梅枝。", "病成也，到而今、著个甚医。"]'),
('song-ci-23','忆秦娥','石孝友','宋','宋词','song-ci','忆秦娥','[]','秦楼月。',56,'宋词/ci.song.12000.json','["秦楼月。", "秦娥本是秦宫客。", "秦宫客。", "梦云风韵，借仙标格。", "相从无计不如休，如今去也空相忆。", "空相忆。", "尊前欢笑，梦中寻觅。"]'),
('song-ci-24','菩萨蛮','石孝友','宋','宋词','song-ci','菩萨蛮','[]','酒浓花艳秋波滑。',52,'宋词/ci.song.12000.json','["酒浓花艳秋波滑。", "舞馀腰素花枝活。", "相见又还休。", "不禁归去愁。", "醉衾成独拥。", "月冷知霜重。", "早是梦难成。", "梅花肠断声。"]'),
('song-ci-25','菩萨蛮','石孝友','宋','宋词','song-ci','菩萨蛮','[]','雪香白尽江南陇。',52,'宋词/ci.song.12000.json','["雪香白尽江南陇。", "暖风绿到池塘梦。", "叠影上檐明。", "夜潮春水生。", "踏青何处去。", "杨柳桥边路。", "不见浣花人。", "汀洲空白苹。"]'),
('song-ci-26','菩萨蛮','石孝友','宋','宋词','song-ci','菩萨蛮','[]','花销玉瘦斜平薄。',52,'宋词/ci.song.12000.json','["花销玉瘦斜平薄。", "舞衣宽尽腰如削。", "困甚不胜娇。", "乌云横鬓翘。", "双蛾颦浅黛。", "鸾镜愁空对。", "罗袖晚香寒。", "泪珠和粉弹。"]'),
('song-ci-27','惜奴娇','石孝友','宋','宋词','song-ci','惜奴娇','[]','我已多情，更撞著、多情底你。',94,'宋词/ci.song.12000.json','["我已多情，更撞著、多情底你。", "把一心、十分向你。", "尽他们，劣心肠、偏有你。", "共你。", "风了人、只为个你。", "宿世冤家，百忙里、方知你。", "没前程、阿谁似你。", "坏却才名，到如今、都因你。", "是你。", "我也没、星儿恨你。"]'),
('song-ci-28','惜奴娇','石孝友','宋','宋词','song-ci','惜奴娇','[]','合下相逢，算鬼病、须沾惹。',95,'宋词/ci.song.12000.json','["合下相逢，算鬼病、须沾惹。", "闲深里、做场话霸。", "负我看承，枉驼我、许多时价。", "冤家。", "你教我、如何割舍。", "苦苦孜孜，独自个、空嗟呀。", "使心肠、捉他不下。", "你试思量，亮从前、说风话。", "冤家。", "休直待，教人咒骂。"]'),
('song-ci-29','江城子','石孝友','宋','宋词','song-ci','江城子','[]','青青杨柳水边桥。',86,'宋词/ci.song.12000.json','["青青杨柳水边桥。", "水迢迢。", "柳摇摇。", "缓引离觞，频驻木兰桡。", "我是行人君是客，俱有恨，总无聊。", "冰澌波暖数琼瑶。", "舞情飙。", "拂春潮。", "一片别魂，销尽遣谁招。", "不似严阳山上雪，魂易尽，雪难消。"]'),
('song-ci-30','江城子','石孝友','宋','宋词','song-ci','江城子','[]','相逢执手也踟蹰。',86,'宋词/ci.song.12000.json','["相逢执手也踟蹰。", "立斯须。", "话区区。", "借问来时，曾见那人无。", "忍泪啼痕香不减，虽少别，忍轻辜。", "霜风摇落岁将徂。", "景凋疏。", "恨萦纡。", "过尽行云，我在与谁居。", "一掬归心飞不去，层浪叠，片蟾孤。"]'),
('song-ci-31','如梦令','石孝友','宋','宋词','song-ci','如梦令','[]','照水粉梅开尽。',40,'宋词/ci.song.12000.json','["照水粉梅开尽。", "春残峭寒犹甚。", "秋气著人衣，斗帐玉儿生晕。", "那更。", "那更。", "帘外月斜风横。"]'),
('song-ci-32','如梦令','石孝友','宋','宋词','song-ci','如梦令','[]','风猎乱香如扫。',40,'宋词/ci.song.12000.json','["风猎乱香如扫。", "又是粉梅开了。", "庭户锁残寒，梦断池塘春草。", "情悄。", "情悄。", "帘外数声啼鸟。"]'),
('song-ci-33','如梦令','石孝友','宋','宋词','song-ci','如梦令','[]','折寄陇头春信。',40,'宋词/ci.song.12000.json','["折寄陇头春信。", "香浅绿柔红嫩。", "插向鬓云边，添得几多风韵。", "但问。", "但问。", "管与玉容相称。"]'),
('song-ci-34','亭前柳','石孝友','宋','宋词','song-ci','亭前柳','[]','有件俥遮，算好事、大家都知。',71,'宋词/ci.song.12000.json','["有件俥遮，算好事、大家都知。", "被新冤家矍索后，没别底，似别底也难为。", "识尽千千并万万，那得恁、海底猴儿。", "这百十钱，一个泼性命，不分付、待分付与谁。"]'),
('song-ci-35','好事近','石孝友','宋','宋词','song-ci','好事近','[]','幸自得人情，只是有些脾鳖。',53,'宋词/ci.song.12000.json','["幸自得人情，只是有些脾鳖。", "引杀俺时直甚，损我儿阴德。", "情知守定没乾休，乾休冤俺急。", "今夜这回除是，有翅儿飞得。"]'),
('song-ci-36','夜行船','石孝友','宋','宋词','song-ci','夜行船','[]','昨日特承传诲。',67,'宋词/ci.song.12000.json','["昨日特承传诲。", "欲相见、奈何无计。", "这场烦恼捻著嚎，晓夜价、求天祝地。", "教俺两下不存济。", "你莫却、信人调戏。", "若还真个肯收心，厮守著、快活一世。"]'),
('song-ci-37','夜行船','石孝友','宋','宋词','song-ci','夜行船','[]','漏水迢迢清夜。',67,'宋词/ci.song.12000.json','["漏水迢迢清夜。", "露华浓、洞房寒乍。", "愁人早是不成眠，奈无端、月窥窗罅。", "心心念念都绿那。", "被相思、闷损人也。", "冤家你若不知人，这欢娱、自今权罢。"]'),
('song-ci-38','茶瓶儿','石孝友','宋','宋词','song-ci','茶瓶儿','[]','相对盈盈一水。',65,'宋词/ci.song.12000.json','["相对盈盈一水。", "多声价、开名得字。", "刚能见也还抛弃。", "负了万红千翠。", "留无计。", "来无计。", "□□□、成何况味。", "而今若没些儿事。", "却枉了、做人一世。"]'),
('song-ci-39','西江月','石孝友','宋','宋词','song-ci','西江月','[]','拽尽风流露布，筑成烦恼根基。',58,'宋词/ci.song.12000.json','["拽尽风流露布，筑成烦恼根基。", "早知恁地浅情时。", "枉了教人恁地。", "惜你十分撋就，把人一味禁持。", "这回断了更相思。", "比似人间没你。"]'),
('song-ci-40','望海潮','石孝友','宋','宋词','song-ci','望海潮','[]','云龙双辅，匣龙双起，当年楚尾吴头。',129,'宋词/ci.song.12000.json','["云龙双辅，匣龙双起，当年楚尾吴头。", "借月命卿，占星分使，来宽俗瘵君忧。", "绣指屈儒流。", "□暂辍北阙，小试南州。", "协奏熏风，霈为霖雨岁登秋。", "春工点缀芳柔。", "正梅凝笑脸，柳弄青眸。", "柏叶荐觞，椒花载颂，休辞秉烛嬉游。", "乃眷在宸旒。", "更德标银管，名覆金瓯。", "共看朝天露稳，归拜富民侯。"]'),
('song-ci-41','清平乐','石孝友','宋','宋词','song-ci','清平乐','["\u897f\u6e56"]','恼花风雨。',54,'宋词/ci.song.12000.json','["恼花风雨。", "断送春将暮。", "底死留春春不住。", "那更送春归去。", "今朝且赋归与。", "明年春满皇都。", "共泛桃花锦浪，与君同醉西湖。"]'),
('song-ci-42','清平乐','石孝友','宋','宋词','song-ci','清平乐','[]','天涯重九。',54,'宋词/ci.song.12000.json','["天涯重九。", "独对黄花酒。", "醉拈黄花和泪嗅。", "忆得去年携手。", "去年同醉流霞。", "醉中折尽黄花。", "还是黄花时候，去年人在天涯。"]'),
('song-ci-43','清平乐','石孝友','宋','宋词','song-ci','清平乐','[]','见时怜惜。',54,'宋词/ci.song.12000.json','["见时怜惜。", "不见时思忆。", "花柳光阴都瞬息。", "□把光阴虚掷。", "才郎妾貌相当。", "有些似欠商量。", "看你忔憎模样，更须著我心肠。"]'),
('song-ci-44','清平乐','石孝友','宋','宋词','song-ci','清平乐','[]','醉红宿翠。',54,'宋词/ci.song.12000.json','["醉红宿翠。", "髻亸乌云坠。", "管是夜来不得睡。", "那更今朝早起。", "春风满搦腰枝。", "阶前小立多时。", "恰恨一番雨过，想应湿透鞋儿。"]'),
('song-ci-45','清平乐','石孝友','宋','宋词','song-ci','清平乐','[]','山明水嫩。',54,'宋词/ci.song.12000.json','["山明水嫩。", "潇洒桐庐郡。", "极目风烟无限景。", "说也如何得尽。", "自怜俗状尘容。", "几年断梗飘蓬。", "借使严陵知道，祗应笑问东风。"]'),
('song-ci-46','清平乐','石孝友','宋','宋词','song-ci','清平乐','[]','霁光摇目。',54,'宋词/ci.song.12000.json','["霁光摇目。", "春入郊原绿。", "残雪压枝堆烂玉。", "时闻枝间蔌蔌。", "瘦藤细履平沙。", "醉中一任欹斜。", "落日数声啼鸟，香风满路梅花。"]'),
('song-ci-47','一翦梅','石孝友','宋','宋词','song-ci','一翦梅','[]','萍水相逢无定居。',72,'宋词/ci.song.12000.json','["萍水相逢无定居。", "同在他乡，又问征途。", "离歌声里客心孤。", "花尽园林，水满江湖。", "烟树微茫带岸蒲。", "何处长沙，何处洪都。", "要知安稳到家无。", "千里征鸿，一纸来书。"]'),
('song-ci-48','浣溪沙','石孝友','宋','宋词','song-ci','浣溪沙','[]','宿醉离愁慢髻鬟。',48,'宋词/ci.song.12000.json','["宿醉离愁慢髻鬟。", "绿残红豆忆前欢。", "锦江春水寄书难。", "红袖时笼金鸭暖，小楼吹彻玉笙寒。", "为谁和泪倚阑干。"]'),
('song-ci-49','浣溪沙','石孝友','宋','宋词','song-ci','浣溪沙','[]','柳岸梅溪春又生。',48,'宋词/ci.song.12000.json','["柳岸梅溪春又生。", "风枝斜里雪枝横。", "空牵归兴惹离情。", "灰尽寸心犹自热，泪承双睫不能晴。", "梦云楼隔豫章城。"]'),
('song-ci-50','浣溪沙','石孝友','宋','宋词','song-ci','浣溪沙','[]','迎客西来送客行。',48,'宋词/ci.song.12000.json','["迎客西来送客行。", "堆堆历历短长亭。", "殢人残酒不能醒。", "烟染暮山浮紫翠，霜凋秋叶复丹青。", "凭谁图写入银屏。"]'),
('song-ci-51','浣溪沙','石孝友','宋','宋词','song-ci','浣溪沙','[]','几曲屏山数幅波。',48,'宋词/ci.song.12000.json','["几曲屏山数幅波。", "雁声斜带夕阳过。", "卸帆聊醉菊花坡。", "旅枕梦魂归路远，秋江风紧夜寒多。", "薄情还解忆人麽。"]'),
('song-ci-52','谒金门','石孝友','宋','宋词','song-ci','谒金门','[]','归不去。',53,'宋词/ci.song.12000.json','["归不去。", "归去又还春暮。", "洞里小桃音信阻。", "几番风更雨。", "相伴竹筇芒履。", "穿尽松溪花坞。", "早是行人贪道路。", "声声闻杜宇。"]'),
('song-ci-53','谒金门','石孝友','宋','宋词','song-ci','谒金门','[]','云树直。',53,'宋词/ci.song.12000.json','["云树直。", "雨歇半空犹湿。", "山影插尖高几尺。", "依依衔落日。", "远岸双飞鸂鶒。", "一水无情自碧。", "飒飒白苹风正急。", "断肠人独立。"]'),
('song-ci-54','谒金门','石孝友','宋','宋词','song-ci','谒金门','[]','春睡重。',53,'宋词/ci.song.12000.json','["春睡重。", "睡起烟销鸾凤。", "著雨柳绵吹易动。", "风帘花影弄。", "过雁空劳目送。", "纵有音书何用。", "有意相思无意共。", "不如休做梦。"]'),
('song-ci-55','谒金门','石孝友','宋','宋词','song-ci','谒金门','[]','风又雨。',53,'宋词/ci.song.12000.json','["风又雨。", "断送残春归去。", "人面桃花在何处。", "绿阴空满路。", "立马垂杨官渡。", "一寸柔肠万缕。", "回首碧云迷洞府。", "杜鹃啼日暮。"]'),
('song-ci-56','谒金门','石孝友','宋','宋词','song-ci','谒金门','[]','山雨绝。',53,'宋词/ci.song.12000.json','["山雨绝。", "山重冷如冰雪。", "窗外芭蕉三两叶。", "影排窗上月。", "醉枕惊回蝴蝶。", "好梦无人共说。", "心事悠悠芳草歇。", "不眠听鼠啮。"]'),
('song-ci-57','水调歌头','石孝友','宋','宋词','song-ci','水调歌头','[]','清霜洗空阔，黍管吹秋灰。',114,'宋词/ci.song.12000.json','["清霜洗空阔，黍管吹秋灰。", "七蓂馀翠，半月流素影徘徊。", "天遣蟠根仙李，世折一枝丹桂，积庆到云来。", "风骨峭冰玉，谈辩屑琼瑰。", "黄阁老，金闺彦，谪仙才。", "小分铜竹，遍洒雨露楚江隈。", "好把萧滩玉笥，变作嘉肴芳酒，为寿莫停杯。", "飞诏下霄汉，调鼎待盐梅。"]'),
('song-ci-58','水调歌头','石孝友','宋','宋词','song-ci','水调歌头','[]','萧滩韵环佩，玉笥灿玲珑。',114,'宋词/ci.song.12000.json','["萧滩韵环佩，玉笥灿玲珑。", "仙原积庆，当日占梦兆维熊。", "学业肯先歆向，文焰已高白贺，飞步更蟾宫。", "秀色溢眉宇，雄辩倒心胸。", "作儿戏，为亲寿，捧霞锺。", "彩衣摇曳，光映怀橘堕双红。", "正好平分风月，且伴能言桃李，鲸吸海涛洪。", "行赴紫泥诏，归拜黑头公。"]'),
('song-ci-59','水调歌头','石孝友','宋','宋词','song-ci','水调歌头','[]','男儿四方志，岂久困泥沙。',114,'宋词/ci.song.12000.json','["男儿四方志，岂久困泥沙。", "束书匣剑，依旧旅食在京华。", "蹭蹬青云未遂，奔走红尘何计，敛袂且还家。", "草木渐黄落，风月正清嘉。", "友猿鹤，宅丘壑，乐生涯。", "几时雷雨，轰磕平地起龙蛇。", "尺箠可鞭夷狄，寸舌可盂社稷，无路踏云车。", "今古万千事，洒泪向黄花。"]'),
('song-ci-60','水调歌头','石孝友','宋','宋词','song-ci','水调歌头','[]','美人在何许，相望正悠悠。',114,'宋词/ci.song.12000.json','["美人在何许，相望正悠悠。", "云窗雾阖，遥想宛在海中洲。", "空对残云冷雨，何限重山叠水，一梦到无由。", "遗怨写红叶，薄幸记青楼。", "金乌掷，玉蟾缺，物华休。", "凤梧眢井，一夜风露各惊秋。", "唯有远山无赖，淡扫一眉晴绿，特地向人愁。", "敛袂且归去，回首谩迟留。"]'),
('song-ci-61','水调歌头','石孝友','宋','宋词','song-ci','水调歌头','["\u5e90\u5c71"]','高情邈云汉，长揖谢君侯。',114,'宋词/ci.song.12000.json','["高情邈云汉，长揖谢君侯。", "脱遗轩冕，簸弄泉石下清幽。", "心契匡庐猿鹤，泪染固陵松柏，一衲且蒙头。", "风月感平发，魂梦绕神州。", "漾一叶，横孤管，去来休。", "琵琶亭畔，正是风叶荻花秋。", "点检诗囊酒碗，抬贴舞裀歌扇，收尽两眉愁。", "回望碧云合，相伴赤松游。"]'),
('song-ci-62','杏花天','石孝友','宋','宋词','song-ci','杏花天','[]','把杯莫唱阳关曲。',65,'宋词/ci.song.12000.json','["把杯莫唱阳关曲。", "行客去、居人恨局。", "屏山似展江如簇。", "不见尊前醉玉。", "鹃啼处、怨声裂竹。", "问后夜、兰舟那宿。", "帛书早系征鸿足。", "肠断弦孤怎续。"]'),
('song-ci-63','南歌子','石孝友','宋','宋词','song-ci','南歌子','["\u5e90\u5c71"]','蚁酒浮明月，鲸波泛落星。',62,'宋词/ci.song.12000.json','["蚁酒浮明月，鲸波泛落星。", "春花秋叶几飘零。", "只有庐山君眼、向人青。", "明日非今日，长亭更短亭。", "不辞一饮尽双瓶。", "争奈秋风江口、酒初醒。"]'),
('song-ci-64','南歌子','石孝友','宋','宋词','song-ci','南歌子','[]','草色裙腰展，冰容水镜开。',62,'宋词/ci.song.12000.json','["草色裙腰展，冰容水镜开。", "又还春事破寒来。", "一夜东风吹绽、后园梅。", "糯瓮篘香酿，熏炉续麝煤。", "休惊节物暗相催。", "赢取大家沈醉、探春杯。"]'),
('song-ci-65','南歌子','石孝友','宋','宋词','song-ci','南歌子','[]','凤髻斜分翠，鸳鞋小砑红。',62,'宋词/ci.song.12000.json','["凤髻斜分翠，鸳鞋小砑红。", "东君著意绮罗丛。", "最好一枝特地、怨春风。", "懊恨无情语，娇羞忍笑容。", "相看疑是梦魂中。", "怕逐飞云归去、断行踪。"]'),
('song-ci-66','南歌子','石孝友','宋','宋词','song-ci','南歌子','[]','畴昔飞鸾侣，而今断雁行。',62,'宋词/ci.song.12000.json','["畴昔飞鸾侣，而今断雁行。", "西风岭外下斜阳。", "无赖一钩新月、挂人肠。", "双泪沾襟袖，孤灯对客床。", "枕馀衾剩只残香。", "别得娇痴不睡、也思量。"]'),
('song-ci-67','南歌子','石孝友','宋','宋词','song-ci','南歌子','[]','春浅梅红小，山寒岚翠薄。',62,'宋词/ci.song.12000.json','["春浅梅红小，山寒岚翠薄。", "斜风吹雨入帘幕。", "梦觉南楼呜咽、数声角。", "歌酒工夫懒，别离情绪恶。", "舞衫宽尽不堪著。", "若比那回相见、更消削。"]'),
('song-ci-68','南歌子','石孝友','宋','宋词','song-ci','南歌子','[]','乱絮飘晴雪，残花绣地衣。',62,'宋词/ci.song.12000.json','["乱絮飘晴雪，残花绣地衣。", "西园歌舞骤然稀。", "只有多情蝴蝶、作团飞。", "旧事深琴怨，新愁减带围。", "倚楼凝望更依依。", "怕见一天风雨、卷春归。"]'),
('song-ci-69','武陵春','石孝友','宋','宋词','song-ci','武陵春','[]','走去走来三百里，五日以为期。',56,'宋词/ci.song.12000.json','["走去走来三百里，五日以为期。", "六日归时已是疑。", "应是望归时。", "鞭个马儿归去也，心急马行迟。", "不免相烦喜鹊儿。", "先报那人知。"]'),
('song-ci-70','好事近','石孝友','宋','宋词','song-ci','好事近','[]','微雨洒芳尘，酝造可人春色。',53,'宋词/ci.song.12000.json','["微雨洒芳尘，酝造可人春色。", "闻道梦云楼外，正小桃花发。", "殷勤留取最繁枝，樽前待闲折。", "准拟乱红深处，化一双蝴蝶。"]'),
('song-ci-71','减字木兰花','石孝友','宋','宋词','song-ci','减字木兰花','[]','新荷小小。',52,'宋词/ci.song.12000.json','["新荷小小。", "比目鱼儿翻翠藻。", "小小新荷。", "点破清光景趣多。", "青青半卷。", "一寸芳心浑未展。", "待得园时。", "罩定鸳鸯一对儿。"]'),
('song-ci-72','减字木兰花','石孝友','宋','宋词','song-ci','减字木兰花','[]','空阶雨过。',52,'宋词/ci.song.12000.json','["空阶雨过。", "细草摇摇光入座。", "斜日多情。", "恋恋幽窗故故明。", "沈吟无语。", "立遍梧桐庭下树。", "病叶先秋。", "零乱风前片段愁。"]'),
('song-ci-73','减字木兰花','石孝友','宋','宋词','song-ci','减字木兰花','[]','角声催晓。',52,'宋词/ci.song.12000.json','["角声催晓。", "斗帐美人初梦觉。", "黛浅妆残。", "清瘦花枝不奈寒。", "匆匆睡起。", "冷落馀香栖翠被。", "何处阳台。", "雨散云收犹未来。"]'),
('song-ci-74','柳梢青','石孝友','宋','宋词','song-ci','柳梢青','[]','云髻盘鸦。',61,'宋词/ci.song.12000.json','["云髻盘鸦。", "眉山远翠，脸晕微霞。", "燕子泥香，鹅儿酒暖，曾见来那。", "秋光已著黄花。", "又恰恨、尊前见他。", "越样风流，恼人情意，真个冤家。"]'),
('song-ci-75','乌夜啼','石孝友','宋','宋词','song-ci','乌夜啼','[]','潇湘雨打船篷。',45,'宋词/ci.song.12000.json','["潇湘雨打船篷。", "别离中。", "愁见拍天沧水、搅天风。", "留不住。", "终须去。", "莫匆匆。", "后夜一尊何处、与谁同。"]'),
('song-ci-76','愁倚阑・春光好','石孝友','宋','宋词','song-ci','愁倚阑・春光好','[]','人好远，路能长。',52,'宋词/ci.song.12000.json','["人好远，路能长。", "奈思量。", "更放晚来些小雨，做新凉。", "衰草低衬斜阳。", "斜阳外、水冷云黄。", "借使有肠须断尽，况无肠。"]'),
('song-ci-77','愁倚阑・春光好','石孝友','宋','宋词','song-ci','愁倚阑・春光好','[]','淮水阔，楚山长。',52,'宋词/ci.song.12000.json','["淮水阔，楚山长。", "恨难量。", "不道愁离人独夜，更天凉。", "佳节虚过重阳。", "更篱下、折尽疏黄。", "看取清溪三百曲，是回肠。"]'),
('song-ci-78','满庭芳','石孝友','宋','宋词','song-ci','满庭芳','[]','笔走龙蛇，词倾河汉，妙年德艺双成。',118,'宋词/ci.song.12000.json','["笔走龙蛇，词倾河汉，妙年德艺双成。", "帝庭敷奏，亲擢冠群英。", "龙首其谁不取，便直饶、勋业峥嵘。", "偏他甚，泼天来大，一个好声名。", "忆曾。", "瞻拜处，当年汝水，今日溢城。", "叹白首青衫，又造宾闳。", "谨贽诗文一卷，仗仙风、吹到蓬瀛。", "依归地，熏香摘艳，作个老门生。"]'),
('song-ci-79','满庭芳','石孝友','宋','宋词','song-ci','满庭芳','[]','兰畹霜浓，柳溪冰咽，春光先到江梅。',118,'宋词/ci.song.12000.json','["兰畹霜浓，柳溪冰咽，春光先到江梅。", "瘦枝疏萼，特地破寒开。", "钩引天涯旧恨，双眉锁、九曲回肠。", "空销黯，故园何在，风月浸长淮。", "当年，吟赏处，醉山颓倒，飞屑成堆。", "怎奈向而今，雨误云乖。", "万里难凭驿使，那堪对、别馆离杯。", "谁知道，洛阳诗老，还有梦魂来。"]'),
('song-ci-80','满庭芳','石孝友','宋','宋词','song-ci','满庭芳','[]','瘦颊凝酥，残妆弄酒，相逢一笑东风。',118,'宋词/ci.song.12000.json','["瘦颊凝酥，残妆弄酒，相逢一笑东风。", "并肩携手，羞落可怜红。", "疑是回心院里，埋醉首、吐作芳丛。", "无端处，雄蜂雌蝶，相美两情通。", "一从。", "攀折后，汉皋珮失，铜雀春空。", "想桃叶桃根，此恨能同。", "多谢金銮旧客，收拾在、芸阁签中。", "还知否，窃香传粉，输与蠹书虫。"]'),
('song-ci-81','满庭芳','石孝友','宋','宋词','song-ci','满庭芳','[]','修竹挼蓝，梅山耸翠，小小佳处西安。',118,'宋词/ci.song.12000.json','["修竹挼蓝，梅山耸翠，小小佳处西安。", "从来闻说，今日还来看。", "便好求田问舍，耳溪涧、目饱林峦。", "争知道，尘缘未了，无计与盘桓。", "小蛮。", "应念处，弦孤么凤，镜掩孤鸾。", "愁在见多情，素日闲闲。", "早晚扁舟两桨，惊翠枕、云巘风湍。", "从前去，殷勤细数，细数万重滩。"]'),
('song-ci-82','更漏子','石孝友','宋','宋词','song-ci','更漏子','[]','亸吟鞭，欹醉帽。',58,'宋词/ci.song.12000.json','["亸吟鞭，欹醉帽。", "行尽关山古道。", "霜满地，水平田。", "雁儿声在天。", "北沙门，南浦岸。", "望得眼穿肠断。", "桐树巷，梦云楼。", "玉儿应也愁。"]'),
('song-ci-83','更漏子','石孝友','宋','宋词','song-ci','更漏子','[]','烛销红，窗送白。',58,'宋词/ci.song.12000.json','["烛销红，窗送白。", "冷落一衾寒色。", "鸡唤起，马驰行。", "月昏衣上明。", "酒香唇，妆印臂。", "竟夜人人共睡。", "魂蝶乱，梦鸾孤。", "知他睡稳无。"]'),
('song-ci-84','木兰花・玉楼春','石孝友','宋','宋词','song-ci','木兰花・玉楼春','[]','阳关声里催行色。',64,'宋词/ci.song.12000.json','["阳关声里催行色。", "马惜离群人惜别。", "入怀风月记衔杯，迎步溪山供散策。", "阴飙断渡江吹白。", "晴壑吞云天放碧。", "悬知诗兴满归途，三四野梅开的砾。"]'),
('song-ci-85','木兰花・玉楼春','石孝友','宋','宋词','song-ci','木兰花・玉楼春','[]','寻春误入桃源洞。',64,'宋词/ci.song.12000.json','["寻春误入桃源洞。", "草草幽欢聊与共。", "牢笼风月此时情，做造溪山今夜梦。", "柳蹊未放金丝弄。", "梅径已经香雪冻。", "春愁离恨重於山，不信马儿驼得动。"]'),
('song-ci-86','踏莎行','石孝友','宋','宋词','song-ci','踏莎行','[]','钗凤摇金，髻螺分翠。',68,'宋词/ci.song.12000.json','["钗凤摇金，髻螺分翠。", "铢衣稳束宫腰细。", "绿柔红小不禁风，海棠无力贪春睡。", "剪水精神，怯春情意。", "霓裳一曲当时事。", "五陵年少本多情，为何特地添憔悴。"]'),
('song-ci-87','行香子','石孝友','宋','宋词','song-ci','行香子','[]','你也娇痴。',83,'宋词/ci.song.12000.json','["你也娇痴。", "我也狂迷。", "望今生、永不分离。", "如何别后，三换梅枝。", "是好相知，不相见，只相思。", "良辰美景，赏心乐事，□□□负我辜伊。", "凤弦再续，鸾鉴重窥。", "且等些时，说些子，做些儿。"]'),
('song-ci-88','画堂春','石孝友','宋','宋词','song-ci','画堂春','[]','寒蛩切切响空帷。',55,'宋词/ci.song.12000.json','["寒蛩切切响空帷。", "断肠风叶霜枝。", "凤楼何处雁书迟。", "空数归期。", "□□沈腰春瘦，却成宋玉秋悲。", "又还辜负菊花时。", "没个人知。"]'),
('song-ci-89','摊破浣溪沙・山花子','石孝友','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','落日秋风岭上村。',56,'宋词/ci.song.12000.json','["落日秋风岭上村。", "全稀过雁少行人。", "正是悲伤愁绝处，更黄昏。", "漠漠野烟生碧树，漫漫衰草际黄云。", "借使昔人行到此，也销魂。"]'),
('song-ci-90','燕归梁','石孝友','宋','宋词','song-ci','燕归梁','[]','楼外春风桃李阴。',62,'宋词/ci.song.12000.json','["楼外春风桃李阴。", "记一笑千金。", "翠眉山敛眼波侵。", "情滴滴、怨深深。", "当初见了，而今别后，算此恨难禁。", "与其向后两关心。", "又何似、□而今。"]'),
('song-ci-91','望江南・忆江南','石孝友','宋','宋词','song-ci','望江南・忆江南','[]','山又水，云巘带风湾。',64,'宋词/ci.song.12000.json','["山又水，云巘带风湾。", "断雁飞时天拍水，乱鸦啼处日衔山。", "疑在画图间。", "人渐远，游子损朱颜。", "别泪空沾双袖湿，春心不放两眉间。", "此去几时还。"]'),
('song-ci-92','青玉案','石孝友','宋','宋词','song-ci','青玉案','["\u957f\u6c5f"]','征鸿过尽秋容谢。',80,'宋词/ci.song.12000.json','["征鸿过尽秋容谢。", "卷离恨、还东下。", "剪剪霜风落平野。", "溪山掩映，水烟摇曳，几簇渔樵舍。", "芙蓉城里人如画。", "春伴春游夜转夜。", "别后知他如何也。", "心随云乱，眼随天断，泪逐长江泻。"]'),
('song-ci-93','蝶恋花','石孝友','宋','宋词','song-ci','蝶恋花','[]','别后相思无限忆。',70,'宋词/ci.song.12000.json','["别后相思无限忆。", "欲说相思，要见终无计。", "拟写相思持送似。", "如何尽得相思意。", "眼底相思心里事。", "纵把相思，写尽凭谁寄。", "多少相思都做泪。", "一齐泪损相思字。"]'),
('song-ci-94','蝶恋花','石孝友','宋','宋词','song-ci','蝶恋花','[]','寒卸园林春已透。',70,'宋词/ci.song.12000.json','["寒卸园林春已透。", "红著溪梅，绿染前堤柳。", "见个人人今感旧。", "引杯相属蒲塘酒。", "金缕歌中眉黛皱。", "多少闲愁，借与伤春瘦。", "明日马蹄浮野秀。", "柳颦梅惨空回首。"]'),
('song-ci-95','蝶恋花','石孝友','宋','宋词','song-ci','蝶恋花','[]','薄幸人人留不住。',70,'宋词/ci.song.12000.json','["薄幸人人留不住。", "杨柳花时，还是成虚度。", "一枕梦回春又去。", "海棠吹落胭脂雨。", "金鸭未销香篆吐。", "断尽柔肠，看取沈烟缕。", "独上危楼凝望处。", "西山暝色连南浦。"]'),
('song-ci-96','蓦山溪','石孝友','宋','宋词','song-ci','蓦山溪','[]','莺莺燕燕。',102,'宋词/ci.song.12000.json','["莺莺燕燕。", "摇荡春光懒。", "时节近清明，雨初晴、娇云弄暖。", "醉红湿翠，春意酿成愁，花似染。", "草如剪。", "已是春强半。", "小鬟微盼。", "分付多情管。", "痴呆不知愁，想怕晚、贪春未惯。", "主人好事，应许玳筵开，歌眉敛。", "舞腰软。", "怎向轻分散。"]'),
('song-ci-97','蓦山溪','石孝友','宋','宋词','song-ci','蓦山溪','[]','小花静院。',102,'宋词/ci.song.12000.json','["小花静院。", "有个人人现。", "缥缈更娉婷，算不数、歌朋舞伴。", "鸣珂曲里，常记偶相逢，无语恨，有情愁，绿嫩红妆浅。", "别来谁念。", "人面关山远。", "凝睇倚危楼，眼波长、眉峰不展。", "一年心事，到此向谁论，书雁杳，梦云深，寂寞江天晚。"]'),
('song-ci-98','蓦山溪','石孝友','宋','宋词','song-ci','蓦山溪','[]','醉魂初醒。',102,'宋词/ci.song.12000.json','["醉魂初醒。", "强起寻芳径。", "一似楚云归，诮没个、鳞书羽信。", "疏狂踪迹，虚度可怜春，阴还闷。", "晴还困。", "赢得无端病。", "菱花宝镜。", "拆破双鸾影。", "别袖忍频看，生怕见、啼红醉粉。", "而今憔悴，瘦立对东风，红成阵，绿成阴，况是春将尽。"]'),
('song-ci-99','千秋岁','石孝友','宋','宋词','song-ci','千秋岁','[]','春工领略。',87,'宋词/ci.song.12000.json','["春工领略。", "点破群花萼。", "对流景，伤沦落。", "踏青心缕懒，病酒情怀恶。", "无奈处，东风故故吹帘幕。", "腕玉宽金约。", "一去音容邈。", "鱼与雁，应难托。", "从前多少事，不忍思量著。", "心撩乱，斜阳影在栏干角。"]'),
('song-ci-100','传言玉女','石孝友','宋','宋词','song-ci','传言玉女','[]','雪压梅梢，金袅柳丝轻敛。',90,'宋词/ci.song.12000.json','["雪压梅梢，金袅柳丝轻敛。", "锦宫春早，乍风和日暖。", "华国翠路，九陌绮罗香满。", "连空灯火，满城弦管。", "月射西楼，更交光照夜宴。", "万人拥路，指鳌山共看。", "花旗翠帽，到处朱帘高卷。", "归时常是，漏残银箭。"]'),
('song-ci-101','水调歌头','韩玉','宋','宋词','song-ci','水调歌头','[]','间世真贤出，吉梦兆维熊。',114,'宋词/ci.song.12000.json','["间世真贤出，吉梦兆维熊。", "玉麟天上谪见，帏薄贯长虹。", "追念当年筹算，封魏封留勋业，千古事攸同。", "语云仁者寿，何必喻乔松。", "嗣天子，乘九五，驭飞龙。", "分麾契符阃外，凭倚定寰中。", "由是天才英纵，散入枢庭闲暇，谈笑抚兵戎。", "伫看骄虏静，金鼎篆元功。"]'),
('song-ci-102','水调歌头','韩玉','宋','宋词','song-ci','水调歌头','[]','有美如花客，容饰尚中州。',114,'宋词/ci.song.12000.json','["有美如花客，容饰尚中州。", "玉京杳渺天际，与别几经秋。", "家在金河堤畔，身寄白苹洲末，南北两悠悠。", "休苦话萍梗，清泪已难收。", "玉壶酒，倾潋滟，听君讴。", "伫云却月，新弄一曲洗人忧。", "同是天涯沦落，何必平生相识，相见且迟留。", "明日征帆发，风月为君愁。"]'),
('song-ci-103','水调歌头','韩玉','宋','宋词','song-ci','水调歌头','[]','月里一枝桂，不付等闲人。',114,'宋词/ci.song.12000.json','["月里一枝桂，不付等闲人。", "昔年霄汉，闻道争者尽输君。", "衣袖天香犹在，风度仙清难老，冰雪莹无尘。", "赋才三十倍，论寿八千春。", "夏庭芝，周室凤，舜郊麟。", "岂如今日称瑞，皇国再生申。", "聊借济时霖雨，来种重湖桃李，和气一番新。", "尚闻虚黄阁，行看秉洪钧。"]'),
('song-ci-104','念奴娇','韩玉','宋','宋词','song-ci','念奴娇','[]','吴东清胜，是吴山苍翠，吴江澄绿。',120,'宋词/ci.song.12000.json','["吴东清胜，是吴山苍翠，吴江澄绿。", "灵秀锺人文物盛，历历皆非凡俗。", "而况君家，风流遗世，犹寄山阴曲。", "继承才业，算来真是名族。", "聊恁驻节重湖，惠歌仁咏，蔼丰年图绿。", "行看登庸归去后，谁展高才相续。", "寿日称觞，一杯千岁，应见蟠桃熟。", "祝君难老，为君还更再祝。"]'),
('song-ci-105','感皇恩','韩玉','宋','宋词','song-ci','感皇恩','[]','远柳绿含烟，土膏才透。',80,'宋词/ci.song.12000.json','["远柳绿含烟，土膏才透。", "云海微茫露晴岫。", "故乡何在，梦寐草堂溪友。", "旧时游赏处，谁携手。", "尘世利名，於身何有。", "老去生涯殢樽酒。", "小桥流水，一树雪香瘦。", "故人今夜月，相思否。"]'),
('song-ci-106','满江红','韩玉','宋','宋词','song-ci','满江红','[]','正欲登临，何处好、登临眺望。',115,'宋词/ci.song.12000.json','["正欲登临，何处好、登临眺望。", "君约我、今朝携酒，古台同上。", "风静秋郊浑似洗，碧空淡覆玻璃盎。", "夕照外、渺渺万遥山，开青嶂。", "龙山事，空追想。", "风流会，今安往。", "我劝君一杯，为君高唱。", "今日谋欢真雅胜，休辞痛饮葡萄浪。", "纵黄花、明日未凋零，非佳赏。"]'),
('song-ci-107','曲江秋','韩玉','宋','宋词','song-ci','曲江秋','[]','明轩快目。',127,'宋词/ci.song.12000.json','["明轩快目。", "正雨过湘溪，秋来泽国。", "波面鉴开，山光淀拂，竹声摇寒玉。", "鸥鹭戏晚日，芰荷动，香红蔌。", "千古兴亡意，凄凉扬□舟，望迷南北。", "仿佛烟笼雾簇。", "认何处、当年绣毂。", "沈香花萼事，潇然伤□，宫殿三十六。", "忍听向晚菱歌，依稀犹似新番曲。", "试与问，如今新蒲细柳，为谁摇绿。"]'),
('song-ci-108','一剪梅・一翦梅','韩玉','宋','宋词','song-ci','一剪梅・一翦梅','[]','镜里新妆镜外情。',72,'宋词/ci.song.12000.json','["镜里新妆镜外情。", "小眉幽恨，浅绿低横。", "只怨闲纵绣鞍尘。", "不道天涯，萦绊归程。", "梦里兰闺相见惊。", "玉香花瘦，春艳盈盈。", "觉来欹枕转愁人。", "门外潇潇，风雨三更。"]'),
('song-ci-109','上平西・金人捧露盘','韩玉','宋','宋词','song-ci','上平西・金人捧露盘','[]','折腰劳，弹冠望，纵飞蓬。',98,'宋词/ci.song.12000.json','["折腰劳，弹冠望，纵飞蓬。", "笑造化、相戏穷通。", "风帆浪桨，暮成寒角晓楼锺。", "暗借霜雪鬓边来，惊对青铜。", "萧闲好，何时遂，门横水，迳穿松。", "有无限、杯月襟风。", "区区个甚，帝尧堂下足夔龙。", "不如闻早问溪山，高养吾慵。"]'),
('song-ci-110','西江月','韩玉','宋','宋词','song-ci','西江月','[]','捍拨声传酒绿，蔷薇面衬宫黄。',58,'宋词/ci.song.12000.json','["捍拨声传酒绿，蔷薇面衬宫黄。", "娇波斜入鬓云长。", "眉与春山一样。", "潇洒不禁疏瘦，低回犹似思量。", "换花梨叶晚阴凉。", "说与三年梦想。"]'),
('song-ci-111','临江仙','韩玉','宋','宋词','song-ci','临江仙','[]','月是银釭溪是镜，云霓与作衣裳。',70,'宋词/ci.song.12000.json','["月是银釭溪是镜，云霓与作衣裳。", "夜寒独立竹篱傍。", "妆成那待粉，笑罢自生香。", "自古佳人多薄命，枉教傲雪凌霜。", "从来林下异闺房。", "何须三弄笛，方断九回肠。"]'),
('song-ci-112','番枪子','韩玉','宋','宋词','song-ci','番枪子','[]','莫把团扇双鸾隔。',89,'宋词/ci.song.12000.json','["莫把团扇双鸾隔。", "要看玉溪头、春风客。", "妙处风骨潇闲，翠罗金缕瘦宜窄。", "转面两眉攒、青山色。", "到此月想精神，花似秀质。", "待与不清狂、如何得。", "奈向难驻朝云，易成春梦恨又积。", "送上七香车春草碧。"]'),
('song-ci-113','清平乐','韩玉','宋','宋词','song-ci','清平乐','[]','梅花照雪。',54,'宋词/ci.song.12000.json','["梅花照雪。", "浑似人清绝。", "香叠绀螺双背结。", "曾侍霓旌降节。", "如今却向尘寰。", "棋中寄个清闲。", "纵使阿郎多病，也须偷画春山。"]'),
('song-ci-114','减字木兰花','韩玉','宋','宋词','song-ci','减字木兰花','[]','香檀素手。',52,'宋词/ci.song.12000.json','["香檀素手。", "缓理新词来伴酒。", "音调凄凉。", "便是无情也断肠。", "莫歌杨柳。", "记得渭城朝雨后。", "客路茫茫。", "几度东风春草长。"]'),
('song-ci-115','行香子','韩玉','宋','宋词','song-ci','行香子','[]','一剪梅花，一见销魂。',84,'宋词/ci.song.12000.json','["一剪梅花，一见销魂。", "况溪桥、雪里前村。", "香传细蕊，春透灵根。", "更水清冷，云黯淡，月黄昏。", "幽过溪兰，清胜山矾。", "对东风、独立无言。", "霜寒塞垒，风净谯门。", "听角声悲，笛声怨，恨难论。"]'),
('song-ci-116','太常引','韩玉','宋','宋词','song-ci','太常引','[]','荒山连水水连天。',62,'宋词/ci.song.12000.json','["荒山连水水连天。", "忆曾上、桂江船。", "风雨过吴川。", "又却在、潇湘岸边。", "不堪追念，浪萍踪迹，虚度夜如年。", "风外晓钟传。", "尚独对、残灯未眠。"]'),
('song-ci-117','太常引','韩玉','宋','宋词','song-ci','太常引','[]','东城归路水云间。',62,'宋词/ci.song.12000.json','["东城归路水云间。", "几曾放、梦魂闲。", "何日整归鞍。", "又人对、西风凭栏。", "温柔情性，系怀伤感，欲诉诉应难。", "愁聚两眉端。", "又叠起、千山万山。"]'),
('song-ci-118','贺新郎','韩玉','宋','宋词','song-ci','贺新郎','[]','柳外莺声碎。',142,'宋词/ci.song.12000.json','["柳外莺声碎。", "晚晴天、东风力软，嫩寒初退。", "花底觅春春已去，时见乱红飞坠。", "又闲傍、阑干十二。", "阑外青山烟缥缈，远连空、愁与眉峰对。", "凝望处，两叠翠。", "鸳鸯结带灵犀佩。", "绮屏深、香罗帐小，宝檠灯背。", "谁谓彩云和梦断，青翼阻寻后会。", "待都把、相思情缀。", "便做锦书难写恨，奈菱花、都见人憔悴。", "那更有，枕痕泪。"]'),
('song-ci-119','贺新郎','韩玉','宋','宋词','song-ci','贺新郎','[]','绰约人如玉。',142,'宋词/ci.song.12000.json','["绰约人如玉。", "试新妆、娇黄半绿，汉宫匀注。", "倚傍小阑闲伫立，翠带风前似舞。", "记洛浦、当年俦侣。", "罗袜尘生香冉冉，料征鸿、微步凌波女。", "惊梦断，楚江曲。", "春工若见应为主。", "忍教都、闲亭邃馆，冷风凄雨。", "待把此花都折取。", "和泪连香寄与。", "须信道、离情如许。", "烟水茫茫斜照里，是骚人、九辨招魂处。", "千古恨，与谁语。"]'),
('song-ci-120','贺新郎','韩玉','宋','宋词','song-ci','贺新郎','[]','睡起帘栊静。',142,'宋词/ci.song.12000.json','["睡起帘栊静。", "□金铺、春帏半卷，宝香烟冷。", "门外落花风不定。", "糁糁乱红堆径。", "谁唤做、春愁如病。", "零乱云鬟慵梳掠，傍菱花、羞对孤鸾影。", "情易感，恨难醒。", "沙边柳外当时景。", "记分携、离筵乍阕，去帆初整。", "尽举棹歌和泪听。", "云淡水寒烟暝。", "空怆望、楼高天迥。", "犹未归来何处也，日长时、不念人孤另。", "书谩写，雁谁倩。"]'),
('song-ci-121','水调歌头','韩玉','宋','宋词','song-ci','水调歌头','[]','重午日过六，灵岳再生申。',114,'宋词/ci.song.12000.json','["重午日过六，灵岳再生申。", "丰神英毅，端是天上谪仙人。", "夙蕴机权才略，早岁来归明圣，惊耸汉庭臣。", "言语妙天下，名德冠朝绅。", "绣衣节，移方面，政如神。", "九重隆眷倚注，伟业富经纶。", "闻道山东出相，行拜紫泥飞诏，归去秉洪钧。", "寿虾自天锡，安用拟庄椿。"]'),
('song-ci-122','且坐令','韩玉','宋','宋词','song-ci','且坐令','[]','闲院落。',85,'宋词/ci.song.12000.json','["闲院落。", "误了清明约。", "杏花雨过胭脂绰。", "紧了秋千索。", "斗草人归，朱门悄掩，梨花寂寞。", "书万纸、恨凭谁托。", "才封了、又揉却。", "冤家何处贪欢乐。", "引得我心儿恶。", "怎生全不思量著。", "那人人情薄。"]'),
('song-ci-123','风入松','韩玉','宋','宋词','song-ci','风入松','[]','柳阴亭院杏梢长。',86,'宋词/ci.song.12000.json','["柳阴亭院杏梢长。", "依约巫阳。", "凤箫已远秦楼在，水沈烟暖馀香。", "临镜舞鸾窥沼，倚筝飞雁辞行。", "醉边人去自凄凉。", "泪眼愁肠。", "断云残雨当年事，到而今、好处难忘。", "两袖晓风花陌，一帘夜雨兰堂。"]'),
('song-ci-124','鹧鸪天','韩玉','宋','宋词','song-ci','鹧鸪天','[]','披拂芝兰便断金。',64,'宋词/ci.song.12000.json','["披拂芝兰便断金。", "顿成南北岂胜任。", "三年尊酒半生话，千里云山一寸心。", "休怅望，莫登临。", "梦魂何处不相寻。", "柔肠欲问愁多少，未比湘江烟水深。"]'),
('song-ci-125','鹧鸪天','韩玉','宋','宋词','song-ci','鹧鸪天','["\u957f\u6c5f"]','爱日烘晴旬日间。',64,'宋词/ci.song.12000.json','["爱日烘晴旬日间。", "谩邀朋辈为跻攀。", "无穷望眼无穷恨，不尽长江不尽山。", "星点点，月团团。", "倒流河汉入杯盘。", "饱吟风月三千首，寄与吴姬忍泪看。"]'),
('song-ci-126','生查子','韩玉','宋','宋词','song-ci','生查子','[]','裙拖簇石榴，髻绾偏荷叶。',48,'宋词/ci.song.12000.json','["裙拖簇石榴，髻绾偏荷叶。", "头上短金钗，轻重还相压。", "轻颦月入眉，浅笑花生颊。", "夫婿不风流，取次看承别。"]'),
('song-ci-127','卜算子','韩玉','宋','宋词','song-ci','卜算子','[]','杨柳绿成阴，初过寒食节。',52,'宋词/ci.song.12000.json','["杨柳绿成阴，初过寒食节。", "门掩金铺独自眠，那更逢寒夜。", "强起立东风，惨惨梨花谢。", "何事王孙不早归，寂寞秋千月。"]'),
('song-ci-128','霜天晓月','韩玉','宋','宋词','song-ci','霜天晓月','[]','竹篱茅屋。',54,'宋词/ci.song.12000.json','["竹篱茅屋。", "一树扶疏玉。", "客里十分清绝，有人在、江南北。", "伫目。", "诗思促。", "翠袖倚修竹。", "不是月媒风聘，谁人与、伴幽独。"]'),
('song-ci-129','蓦山溪','熊良翰','宋','宋词','song-ci','蓦山溪','[]','四时美景，最好惟春昼。',101,'宋词/ci.song.12000.json','["四时美景，最好惟春昼。", "仙诞弥辰，况还当、中春时候。", "日迟风软，是处霭晴烟，桃散锦，柳摇金，交映门庭秀。", "此时称寿。", "兰玉相先后。", "喜色上眉峰，且休辞、频倾芳酒。", "虚空看透，摆脱利名缰，云鬓绿，醉颜酡，笑挹浮丘袖。"]'),
('song-ci-130','鹧鸪天','熊可量','宋','宋词','song-ci','鹧鸪天','[]','清晓南窗笑语喧。',64,'宋词/ci.song.12000.json','["清晓南窗笑语喧。", "今朝生日胜从前。", "鹤吞沆瀣神逾爽，松饱风霜节更坚。", "调气马，殖心田。", "几曾佞佛与夸仙。", "戏衫脱了浑无累，快活人间百十年。"]'),
('song-ci-131','万年欢','熊上达','宋','宋词','song-ci','万年欢','[]','春管方中，正良辰馀五，韶光明媚。',122,'宋词/ci.song.12000.json','["春管方中，正良辰馀五，韶光明媚。", "晓见非烟佳气，满堂融溢。", "学语儿童喜色。", "庆间世、悬弧此日。", "休言未、结组弹冠，不劳戏傲泉石。", "生平服膺道德。", "看名高谷口，年齐箕翼。", "况有宁馨，已报月宫消息。", "只这谁人似得。", "且莫惜、高张华席。", "应须拚、明日扶头，尽教金盏频侧。"]'),
('song-ci-132','南柯子・南歌子','苏十能','宋','宋词','song-ci','南柯子・南歌子','[]','江水粼粼碧，云山叠叠奇。',62,'宋词/ci.song.12000.json','["江水粼粼碧，云山叠叠奇。", "平生心事一钩丝。", "便是壶中日月、更何疑。", "文叔今方贵，君房素自痴。", "洛阳尘土涴人衣。", "争似归来双足、踏涟漪。"]'),
('song-ci-133','玉楼春','朱景文','宋','宋词','song-ci','玉楼春','[]','玉阶琼室冰壶帐。',64,'宋词/ci.song.12000.json','["玉阶琼室冰壶帐。", "恁地水晶帘不上。", "儿家住处隔红尘，云气悠扬风淡荡。", "有时闲把兰舟放。", "雾鬓风鬟乘翠浪。", "夜深满载月明归，画破琉璃千万丈。"]'),
('song-ci-134','满江红','欧阳光祖','宋','宋词','song-ci','满江红','[]','恰则元宵，灿万灯、星球如昼。',115,'宋词/ci.song.12000.json','["恰则元宵，灿万灯、星球如昼。", "春乍暖、化工未放，十分花柳。", "和气并随灯夕至，一时锺作人间秀。", "问烟霄、直上舌含香，文摛绣。", "命世杰，调元手。", "荆楚地，淹留久。", "看日边追诏，印垂金斗。", "翠竹苍松身逾健，蛾儿雪竹人如旧。", "愿湘江、卷入玉壶中，为公寿。"]'),
('song-ci-135','瑞鹤仙','欧阳光祖','宋','宋词','song-ci','瑞鹤仙','[]','得毛韩经学。',125,'宋词/ci.song.12000.json','["得毛韩经学。", "振祖风，挺挺凌烟勋业。", "文章世为甲。", "果妙龄秀发，荐膺衡鹗。", "名登雁塔。", "访梅仙，种河阳桃李，从兹两绾铜符，多少吏民欢洽。", "庆惬。", "归来整顿，松竹笑傲，武夷溪壑。", "韶光恰匝。", "清明过了旬浃。", "喜当初度日。", "称觞春酒，一饮红生双颊。", "愿儿孙，世袭簪缨，代常不乏。"]'),
('song-ci-136','酹江月・念奴娇','罗椿','宋','宋词','song-ci','酹江月・念奴娇','[]','郎星锦帐，忽翩然归访，南溪孤鹜。',120,'宋词/ci.song.12000.json','["郎星锦帐，忽翩然归访，南溪孤鹜。", "前日登高谁信道，寿酒重浮茱萸。", "风露杯寒，芙蓉帐冷，笑受长生箓。", "广寒宫殿，桂华应已新续。", "不用翠倚红围，舞裙歌袖，共理称觞曲。", "只把文章千古事，留伴平生幽独。", "但使明年，鬓青长在，萱草春风绿。", "诸郎如许，转头百事都足。"]'),
('song-ci-137','沁园春','游九言','宋','宋词','song-ci','沁园春','[]','五十五年，满簪华发，俨然遂良。',140,'宋词/ci.song.12000.json','["五十五年，满簪华发，俨然遂良。", "又何曾戚戚，荜门圭窦，何曾汲汲，玉带金章。", "困后高眠，饥来饱□，老矣狂夫老更狂。", "空回首，叹世间名利，傀儡开场。", "幸临晚节安康。", "又两日、三秋催萧霜。", "叹生朝亦是，贺宾踵至，龙锺矍铄，何足称觞。", "喜对诸贤，笑谈世事，相会亲朋醉玉觞。", "谁如我，素乐天知命，不事侯王。"]'),
('song-ci-138','赤枣子','游九言','宋','宋词','song-ci','赤枣子','[]','河汉澈，碧霄晴。',32,'宋词/ci.song.12000.json','["河汉澈，碧霄晴。", "九华仙子到凡尘。", "凉夜山头吹玉笛，纤云卷尽月分明。"]'),
('song-ci-139','赤枣子','游九言','宋','宋词','song-ci','赤枣子','[]','香露湿，草晶荧。',32,'宋词/ci.song.12000.json','["香露湿，草晶荧。", "起看大地粲瑶琼。", "下界千门人寂寂，空山夜静海波声。"]'),
('song-ci-140','赤枣子','游九言','宋','宋词','song-ci','赤枣子','[]','仙子去，眇云程。',32,'宋词/ci.song.12000.json','["仙子去，眇云程。", "天香杳杳佩环清。", "回望九州烟雾日，千山月落影纵横。"]'),
('song-ci-141','洞仙歌','刘光祖','宋','宋词','song-ci','洞仙歌','[]','晚风收暑，小池塘荷净。',101,'宋词/ci.song.12000.json','["晚风收暑，小池塘荷净。", "独倚胡床酒初醒。", "起徘徊、时有香气吹来，云藻乱，叶底游鱼动影。", "空擎承露盖，不见冰容，惆怅明妆晓鸾镜。", "后夜月凉时，月淡花低，幽梦觉、欲凭谁省。", "且应记、临流凭阑干，便遥想，江南红酣千顷。"]'),
('song-ci-142','鹊桥仙','刘光祖','宋','宋词','song-ci','鹊桥仙','[]','相逢一笑，又成相避，南雁归时霜透。',68,'宋词/ci.song.12000.json','["相逢一笑，又成相避，南雁归时霜透。", "明朝人在短亭西，看舞袖、双双行酒。", "歌声此处，秋声何处，几度乱愁搔首。", "如何不寄一行书，有万绪、千端别后。"]'),
('song-ci-143','昭君怨','刘光祖','宋','宋词','song-ci','昭君怨','[]','人在醉乡居住。',48,'宋词/ci.song.12000.json','["人在醉乡居住。", "记得旧曾来去。", "疏雨听芭蕉。", "梦魂遥。", "惆怅柳烟何处。", "目送落霞江浦。", "明夜月当楼。", "照人愁。"]'),
('song-ci-144','江城子','刘光祖','宋','宋词','song-ci','江城子','[]','十分雪意却成霜。',86,'宋词/ci.song.12000.json','["十分雪意却成霜。", "暮云黄。", "月微茫。", "只有梅花，依旧吐幽芳。", "还喜无边春信漏，疏影下，觅浮香。", "才清端是紫薇郎。", "别鹓行。", "忆宫墙。", "夜半胡为，人与月交相。", "君合召归吾老矣，月随去，照西厢。"]'),
('song-ci-145','长相思','刘光祖','宋','宋词','song-ci','长相思','[]','玉尊凉。',44,'宋词/ci.song.12000.json','["玉尊凉。", "玉人凉。", "若听离歌须断肠。", "休教成鬓霜。", "画桥西，画桥东。", "有泪分明清涨同。", "如何留醉翁。"]'),
('song-ci-146','水调歌头','刘光祖','宋','宋词','song-ci','水调歌头','[]','客梦一回醒，三度碧梧秋。',114,'宋词/ci.song.12000.json','["客梦一回醒，三度碧梧秋。", "仰看今夕天上，河汉又西流。", "早晚凉风过雁，惊落空阶一叶，急雨闹清沟。", "归计休令暮，宵露浥征裘。", "古来今，生老病，许多愁。", "那堪更说，无限功业镜中羞。", "只有青山高致，对此还论世事，举白与君浮。", "送我一杯酒，谁起舞凉州。"]'),
('song-ci-147','临江仙','刘光祖','宋','宋词','song-ci','临江仙','[]','小院回廊春寂寂，晚来独自闲行。',68,'宋词/ci.song.12000.json','["小院回廊春寂寂，晚来独自闲行。", "画帘东畔碧云生。", "也知无雨，空滴枕边声。", "一簇小桃开又落，低头拾取红英。", "东风相送忘相迎。", "梨花寒食，到得锦宫城。"]'),
('song-ci-148','临江仙','刘光祖','宋','宋词','song-ci','临江仙','[]','我似万山千里外，悠然一片归云。',70,'宋词/ci.song.12000.json','["我似万山千里外，悠然一片归云。", "宫衔犹自带云云。", "谁知前进士，已是故将军。", "闲坐闲行闲饮酒，闲拈闲字闲文。", "诸公留我笑纷纷。", "一枝簪宝髻，六幅舞罗裙。"]'),
('song-ci-149','踏莎行','刘光祖','宋','宋词','song-ci','踏莎行','[]','扫径花零，闭门春晚。',68,'宋词/ci.song.12000.json','["扫径花零，闭门春晚。", "恨长无奈东风短。", "起来消息探荼縻，雪条玉蕊都开遍。", "晚月魂清，夕阳香远。", "故山别后谁拘管。", "多情於此更情多，一枝嗅罢还重拈。"]'),
('song-ci-150','醉落魄・一斛珠','刘光祖','宋','宋词','song-ci','醉落魄・一斛珠','[]','春风开者。',67,'宋词/ci.song.12000.json','["春风开者。", "一时还共春风谢。", "柳条送我今槐夏。", "不饮香醪，孤负人生也。", "曲塘泉细幽琴写。", "胡床滑簟应无价。", "日迟睡起帘钩挂。", "何不归欤，花竹秀而野。"]'),
('song-ci-151','沁园春','刘光祖','宋','宋词','song-ci','沁园春','[]','画戟如霜，绮疏如水，篆香渐微。',137,'宋词/ci.song.12000.json','["画戟如霜，绮疏如水，篆香渐微。", "向莺花多处，青山衮衮，鹭凫散后，落屑霏霏。", "曾是鸾台金马客，一场梦觉来人事非。", "多少话，付无心云叶，自在闲飞。", "想看燕鸿易感，□几度春往秋又归。", "见黄馀露点，东坡菊赋，清传雪片，处士梅诗。", "向此年年开寿斝，算今古人生七十稀。", "歌啸外，作皇朝遗老，名字辉辉。"]'),
('song-ci-152','满江红','何师心','宋','宋词','song-ci','满江红','["\u9ec4\u5c71"]','一水飞空，揭起珠帘全幅。',109,'宋词/ci.song.12000.json','["一水飞空，揭起珠帘全幅。", "不须人卷，不须人轴。", "一点不容飞燕入，些而未许游鱼宿。", "向山头、款步听疏音，清如玉。", "三峡水，堪人掬。", "三汲浪，堪龙浴。", "更两边潇洒，数竿修竹。", "晓倩碧烟为绳束，夜凭新月为钩曲。", "问当年、题品是何人，黄山谷。"]'),
('song-ci-153','小重山','赵蕃','宋','宋词','song-ci','小重山','["\u5e90\u5c71"]','何地无溪祗欠人。',70,'宋词/ci.song.12000.json','["何地无溪祗欠人。", "有翁年八十，住其滨。", "直钩元不事丝缗。", "优游尔，聊以遂吾身。", "陶令赋归辰。", "未尝轻出入，犯风尘。", "江洲太守独情亲。", "庐山醉，谁主复谁宾。"]'),
('song-ci-154','菩萨蛮','赵蕃','宋','宋词','song-ci','菩萨蛮','[]','鸡声茅店饮残月。',52,'宋词/ci.song.12000.json','["鸡声茅店饮残月。", "板桥人迹霜如雪。", "此是古人诗。", "身经老忘之。", "君行当此境。", "令我昏成醒。", "乘月犯霜来。", "诗真误尔哉。"]'),
('song-ci-155','失调名','赵蕃','宋','宋词','song-ci','失调名','[]','春浦雪，涧泉梅。',8,'宋词/ci.song.12000.json','["春浦雪，涧泉梅。"]'),
('song-ci-156','望江南・忆江南','何令修','宋','宋词','song-ci','望江南・忆江南','[]','登龙脊，抚剑一长歌。',32,'宋词/ci.song.12000.json','["登龙脊，抚剑一长歌。", "巫峡峰高腾凤鹤，夔门波阔失蛟鼍。", "东望意如何。"]'),
('song-ci-157','水龙吟','马子严','宋','宋词','song-ci','水龙吟','[]','买庄为贮梅花，玉妃一万森庭户。',126,'宋词/ci.song.12000.json','["买庄为贮梅花，玉妃一万森庭户。", "古来词客，比方不类，可怜毫楮。", "谁扫尘凡，独超物表，神仙中取。", "是崑丘标致，射山风骨，除此外、吾谁与。", "九酝醍醐雪乳。", "和金盘、月边清露。", "寿阳骄呆，单于疏贱，不堪充数。", "弄玉排箫，许琼挥拍，胎禽飞舞。", "待先生，披著羊裘鹤氅，作园林主。"]'),
('song-ci-158','玉楼春','马子严','宋','宋词','song-ci','玉楼春','[]','南枝又觉芳心动。',64,'宋词/ci.song.12000.json','["南枝又觉芳心动。", "慰我相思情味重。", "陇头何处寄将书，香发有时疑是梦。", "谁家横笛成三弄。", "吹到幽香和梦送。", "觉来知不是梅花，落寞岁寒谁与共。"]'),
('song-ci-159','桃源忆故人','马子严','宋','宋词','song-ci','桃源忆故人','["\u897f\u6e56"]','几年闲作园林主。',56,'宋词/ci.song.12000.json','["几年闲作园林主。", "未向梅花著语。", "雪后又开半树。", "风递幽香去。", "断魂不为花间女。", "枝上青禽□诉。", "我是西湖处士。", "长恨芳时误。"]'),
('song-ci-160','十拍子・破阵子','马子严','宋','宋词','song-ci','十拍子・破阵子','[]','点缀莫窥天巧，名称却道人为。',72,'宋词/ci.song.12000.json','["点缀莫窥天巧，名称却道人为。", "香酝蜜脾分几点，色映乌云倚一枝。", "遥看步赏迟。", "映水不嫌疏影，娇春也自同时。", "红树落残风自暖，塞管声长晓更催。", "此时知不知。"]'),
('song-ci-161','花心动','马子严','宋','宋词','song-ci','花心动','[]','雨洗胭脂，被年时、桃花杏花占了。',127,'宋词/ci.song.12000.json','["雨洗胭脂，被年时、桃花杏花占了。", "独惜野梅，风骨非凡，品格胜如多少。", "探春常恨无颜色，试浓抹、当场微笑。", "趁时节，千般冶艳，是谁偏好。", "直与岁寒共保。", "问单于、如今几分娇小。", "莫怪山人，不识南枝，横玉自来同调。", "岂须摘叶分明认，又何必、枯枝比较。", "恐桃李、开时妒他太早。"]'),
('song-ci-162','贺新郎','马子严','宋','宋词','song-ci','贺新郎','[]','客里伤春浅。',140,'宋词/ci.song.12000.json','["客里伤春浅。", "问今年梅蕊，因甚化工不管。", "陌上芳尘行处满。", "可计天涯近远。", "见说道、迷楼左畔。", "一似江南先得暖。", "向何郎、庭下都寻遍。", "辜负了，看花眼。", "古来好物难为伴。", "只琼花一种，传来仙苑。", "独许扬州作珍产。", "便胜了、千千万万。", "又却待、东风吹绽。", "自昔闻名今见面。", "数归期、屈指家山晚。", "归去说，也稀罕。"]'),
('song-ci-163','满庭芳','马子严','宋','宋词','song-ci','满庭芳','[]','共庆春时，满庭芳思，一枝心蕊非常。',118,'宋词/ci.song.12000.json','["共庆春时，满庭芳思，一枝心蕊非常。", "少年游冶，何但折垂杨。", "曾向瑶台月下，逢解佩、玉女翻香。", "风光好，真珠帘卷，都胜早梅芳。", "人间，无比并，玉蝴蝶树，争敢相方，既□春归后，此意难忘。", "夜梦扬州万玉，飞魂共、紫燕归梁。", "须行乐，马家花圃，不肯醉红妆。"]'),
('song-ci-164','水龙吟','马子严','宋','宋词','song-ci','水龙吟','[]','东君直是多情，好花一夜都开尽。',126,'宋词/ci.song.12000.json','["东君直是多情，好花一夜都开尽。", "杏梢零落，药栏迟暮，不教宁静。", "风度秋千，日移帘幕，翠红交映。", "正太真浴罢，西施浓抹，都沉醉、娇相称。", "磨遍绿窗铜镜。", "挽春衫、不堪比并。", "暮云空谷，佳人何处，碧苔侵迳。", "睡里相看，酒边凝想，许多风韵。", "问因何，却欠一些香味，惹旁人恨。"]'),
('song-ci-165','二郎神','马子严','宋','宋词','song-ci','二郎神','[]','日高睡起，又恰见、柳梢飞絮。',127,'宋词/ci.song.12000.json','["日高睡起，又恰见、柳梢飞絮。", "倩说与、年年相挽，却又因他相误。", "南北东西何时定，看碧沼、青萍无数。", "念蜀郡风流，金陵年少，哪寻张绪。", "应许。", "雪花比并，扑帘堆户。", "更羽缀游丝，毡铺小径，肠断鹁鸠唤雨。", "舞态颠狂，腰肢轻怯，散了几回重聚。", "空暗想，昔日长亭别酒，杜鹃催去。"]'),
('song-ci-166','天仙子','马子严','宋','宋词','song-ci','天仙子','[]','白玉为台金作盏。',80,'宋词/ci.song.12000.json','["白玉为台金作盏。", "香是江梅名阆苑。", "年时把酒对君歌，歌不断。", "杯无算。", "花月当楼人意满。", "翘戴一枝蝉影乱。", "乐事且随人意换。", "西楼回首月明中，花已绽。", "人何远。", "可惜国香天不管。"]'),
('song-ci-167','最高楼','马子严','宋','宋词','song-ci','最高楼','[]','花解笑，冷淡不求知。',102,'宋词/ci.song.12000.json','["花解笑，冷淡不求知。", "长是殿、众芳时。", "鲜鲜秀颈磋圆玉，洛阳翠佩剪琉璃。", "向人前，迎茉莉，送荼䕷。", "几欲把、清香换春色。", "费多少、黄金酬不得。", "梅雨妒，麦风欺。", "细腰空恋当心蕊，同时犹结旧年枝。", "谢家娘，将远寄，待凭谁。"]'),
('song-ci-168','青门引・青门饮','马子严','宋','宋词','song-ci','青门引・青门饮','[]','手种团团玉。',62,'宋词/ci.song.12000.json','["手种团团玉。", "香趁日晴初熟。", "金刀错落晓霜寒，十分风味，独向暑天足。", "唐君去后云空谷。", "异事传流俗。", "刀圭倘是神仙药，地皮卷尽犹飞肉。"]'),
('song-ci-169','朝中措','马子严','宋','宋词','song-ci','朝中措','[]','龙荪晚颖破苔纹。',57,'宋词/ci.song.12000.json','["龙荪晚颖破苔纹。", "英气欲凌云。", "深处未须留客，春风自掩柴门。", "蒲团宴坐，轻敲茶臼，细扑炉熏。", "弹到琴心二叠，鹧鸪啼傍黄昏。"]'),
('song-ci-170','临江仙','马子严','宋','宋词','song-ci','临江仙','[]','人意舒闲春事到，徐徐弄日微云。',68,'宋词/ci.song.12000.json','["人意舒闲春事到，徐徐弄日微云。", "翠鬟飞绕蛾群。", "烟横沽酒市，风转落梅村。", "岁事一新人半旧，相逢际晚醺醺。", "花间亭馆柳间门。", "除风雨外，排日醉红裙。"]'),
('song-ci-171','月华清','马子严','宋','宋词','song-ci','月华清','[]','瑟瑟秋声，萧萧天籁，满庭摇落空翠。',123,'宋词/ci.song.12000.json','["瑟瑟秋声，萧萧天籁，满庭摇落空翠。", "数遍丹枫，不见叶间题字。", "人何处、千里婵娟，愁不断、一江流水。", "遥睇。", "见征鸿几点，碧天无际。", "怅望月中仙桂。", "问窃药佳人，谁与同岁。", "把镜当空，照尽别离情意。", "心里恨、莫结丁香，琴上曲、休弹秋思。", "怕里。", "又悲来老却，兰台公子。"]');
